// ══════════════════════════════════════════════════════════════
//  병원 급식 예산 관리 - 메인 앱 JS v2.0
// ══════════════════════════════════════════════════════════════

// ══════════════════════════════════════════════════════════════
//  CALC_ENGINE — 중앙 계산 엔진 (Single Source of Truth)
//  ※ 이 객체의 함수만 사용하고 각 페이지에서 인라인 계산 금지
//
//  [영향 범위]
//  · calcAnnualRemain  → 스케줄 편집뷰, 연차탭, 관리자대시보드,
//                        운영진뷰, 보고서(PDF/XLSX), 우측패널, 직원모달
//  · REST_CODES_SET    → 모든 스케줄 뷰(편집/설계/운영진/직원),
//                        연차·휴무 집계, 외부인력 집계
//  · calcShiftHrs      → 스케줄 편집뷰, 운영진뷰, 우측패널, 보고서
//  · calcBudgetPct     → 발주입력, 영양사대시보드, 관리자대시보드,
//                        인사이트패널, 경영대시보드
//  · getShiftCore      → 스케줄 편집뷰, 설계모드 (UI 표현 레이어만 분리)
// ══════════════════════════════════════════════════════════════
const CALC_ENGINE = (() => {

  // ─────────────────────────────────────────────
  //  1. REST_CODES_SET  (휴무로 분류되는 shift 코드 집합)
  //     기준: 연·휴·경조·병가 → 근무일수에서 제외
  //     ※ '-' 는 미입력(공란)으로 별도 처리 — 이 Set에 포함하지 않음
  // ─────────────────────────────────────────────
  const REST_CODES_SET = new Set(['연', '휴', '경조', '병가'])

  // ─────────────────────────────────────────────
  //  2. calcAnnualRemain(empLeave)
  //     연차 잔여일 계산 — 이월연차(carried_over_days) 포함
  //
  //  [입력] empLeave: leaveMap[empId] 또는 scheduleLeavesData 행
  //         두 가지 구조 모두 처리:
  //         A) { annual: { total, used, carried_over_days, allowance_paid } }
  //            → 스케줄/운영진/보고서의 leaveMap 구조
  //         B) { total_days, used_days, carried_over_days, allowance_paid }
  //            → scheduleLeavesData / openEmpStatsModal 구조
  //
  //  [반환] { effective, used, remain, carried }
  //         effective: 실질 연차 총일수 (total + carried)
  //         used:      사용 일수
  //         remain:    잔여 일수 (null = 데이터 없음)
  //         carried:   이월 연차 일수
  // ─────────────────────────────────────────────
  function calcAnnualRemain(empLeave) {
    if (!empLeave) return { total: null, effective: null, used: 0, remain: null, carried: 0 }

    // 구조 A: leaveMap[empId].annual
    const hasNested = empLeave.annual !== undefined
    const src = hasNested ? empLeave.annual : empLeave

    const _rawTotal = src?.total ?? src?.total_days ?? null
    const total    = (_rawTotal !== null && _rawTotal > 0) ? _rawTotal : null  // 0 = 미부여 → null 처리
    const used     = src?.used  ?? src?.used_days  ?? 0
    const carried  = (src?.allowance_paid) ? 0 : (src?.carried_over_days ?? 0)
    const effective = total !== null ? total + carried : null
    const remain    = effective !== null ? effective - used : null

    return { total, effective, used, remain, carried }
  }

  // ─────────────────────────────────────────────
  //  3. calcMonthlyLeaveRemain(mlData, hireDate)
  //     월차 잔여일 계산 (1년 미만 직원)
  //
  //  [입력] mlData:    _monthlyLeavesData 항목
  //         hireDate:  emp.hire_date (string)
  //  [반환] { total, used, remain, isUnsaved, isUnder1Y }
  // ─────────────────────────────────────────────
  function calcMonthlyLeaveRemain(mlData, hireDate) {
    const hired    = hireDate ? new Date(hireDate) : null
    const isUnder1Y = hired
      ? (Date.now() - hired.getTime()) < 365.25 * 24 * 3600 * 1000
      : false
    if (!isUnder1Y || !mlData) {
      return { total: null, used: 0, remain: null, isUnsaved: false, isUnder1Y }
    }
    const total     = mlData.monthly_total ?? mlData.auto_calc_days ?? null
    const used      = mlData.monthly_used  ?? 0
    const remain    = total !== null ? total - used : null
    const isUnsaved = mlData.monthly_total == null && total !== null
    return { total, used, remain, isUnsaved, isUnder1Y }
  }

  // ─────────────────────────────────────────────
  //  4. calcShiftHrs(code, shifts)
  //     shift 코드 → 근무 시간(h) 계산
  //     · 빈 코드 / '-' / REST_CODES_SET → 0
  //     · shifts 배열에서 start_time/end_time 조회
  //     · 야간(end < start) 자동 처리
  //     · shifts 미매칭 → 기본 8h
  // ─────────────────────────────────────────────
  function calcShiftHrs(code, shifts) {
    if (!code || code === '-' || REST_CODES_SET.has(code)) return 0
    const sf = (shifts || scheduleShifts || []).find(s => s.shift_code === code)
    if (sf?.start_time && sf?.end_time) {
      const [sh, sm] = sf.start_time.split(':').map(Number)
      const [eh, em] = sf.end_time.split(':').map(Number)
      let hrs = (eh * 60 + em - sh * 60 - sm) / 60
      if (hrs < 0) hrs += 24
      return Math.max(0, hrs - 1) // 휴게시간 1h 차감
    }
    return 8
  }

  // ─────────────────────────────────────────────
  //  5. calcBudgetPct(used, budget)
  //     예산 사용률(%) 계산
  //     · budget = 0 또는 null → 0 반환
  //     · 소수점 없이 정수 반환
  // ─────────────────────────────────────────────
  function calcBudgetPct(used, budget) {
    if (!budget || budget <= 0) return 0
    return Math.round((used || 0) / budget * 100)
  }

  // ─────────────────────────────────────────────
  //  6. getBudgetColor(pct)
  //     예산 사용률 → 색상 코드 반환
  //     · ≥100% → 빨강 / ≥80% → 주황 / 미만 → 초록
  // ─────────────────────────────────────────────
  function getBudgetColor(pct) {
    if (pct >= 100) return '#dc2626'
    if (pct >= 80)  return '#d97706'
    return '#16a34a'
  }

  // ─────────────────────────────────────────────
  //  7. getShiftCore(code, shifts)
  //     shift 코드의 핵심 속성 반환 (계산 엔진 — UI 표현 제외)
  //     · bg, fg: 배경/전경 색상
  //     · hrs:    근무 시간
  //     · isRest: 휴무 코드 여부
  //     ※ UI 표현(설계모드/편집모드 border·크기 등)은 각 뷰에서 분리 처리
  // ─────────────────────────────────────────────
  function getShiftCore(code, shifts) {
    const isRest = !code || code === '-' || REST_CODES_SET.has(code)
    const hrs    = calcShiftHrs(code, shifts)
    const sf     = (shifts || scheduleShifts || []).find(s => s.shift_code === code)
    const bg     = sf?.color       || (isRest ? '#f9fafb' : '#e0f2fe')
    const fg     = sf?.text_color  || (isRest ? '#d1d5db' : '#0369a1')
    return { bg, fg, hrs, isRest, shiftData: sf || null }
  }

  // ─────────────────────────────────────────────
  //  8. calcWorkSummary(empId, days, year, month, schedMap, leaveMap)
  //     직원 한 명의 월간 근무 요약 계산
  //     [반환] { workDays, leaveDays, annualDays, otHours,
  //              annualRemain, maxConsecDays, weeklyHoursMap }
  // ─────────────────────────────────────────────
  function calcWorkSummary(emp, days, year, month, schedMap, leaveMap, shifts) {
    let workDays = 0, leaveDays = 0, annualDays = 0, otHours = 0
    let maxConsec = 0, curConsec = 0
    const weeklyHoursMap = {}

    for (let d = 1; d <= days; d++) {
      const dateStr = `${year}-${String(month).padStart(2,'0')}-${String(d).padStart(2,'0')}`
      const sched   = schedMap[`${emp.id}_${dateStr}`]
      const code    = sched?.shift_code || ''
      const ltype   = sched?.leave_type || ''
      const ot      = sched?.overtime_hours || 0

      if (code && code !== '-') {
        if (code === '연' || ltype === 'annual') annualDays++
        else if (REST_CODES_SET.has(code) || ltype) leaveDays++
        else {
          workDays++
          otHours += ot
          curConsec++
          if (curConsec > maxConsec) maxConsec = curConsec
          // 주차별 시간 누적
          const d2 = new Date(dateStr)
          const soy = new Date(d2.getFullYear(), 0, 1)
          const wk  = Math.ceil(((d2 - soy) / 86400000 + soy.getDay() + 1) / 7)
          weeklyHoursMap[wk] = (weeklyHoursMap[wk] || 0) + calcShiftHrs(code, shifts)
        }
      } else {
        curConsec = 0
      }
    }

    const annual = calcAnnualRemain(leaveMap ? leaveMap[emp.id] : null)
    return {
      workDays, leaveDays, annualDays, otHours,
      annualRemain: annual.remain,
      annualEffective: annual.effective,
      annualUsed: annual.used,
      annualCarried: annual.carried,
      maxConsecDays: maxConsec,
      weeklyHoursMap
    }
  }

  // ─────────────────────────────────────────────
  //  Public API
  // ─────────────────────────────────────────────
  return {
    REST_CODES_SET,
    calcAnnualRemain,
    calcMonthlyLeaveRemain,
    calcShiftHrs,
    calcBudgetPct,
    getBudgetColor,
    getShiftCore,
    calcWorkSummary
  }
})()

// 하위 호환 단축 참조 (기존 코드에서 직접 사용하는 경우 대비)
const _CE = CALC_ENGINE

const App = {
  token: localStorage.getItem('token'),
  role: localStorage.getItem('role'),
  hospitalName: localStorage.getItem('hospitalName'),
  username: localStorage.getItem('username'),
  currentYear: new Date().getFullYear(),
  currentMonth: new Date().getMonth() + 1,
  currentPage: '',
  charts: {},
  lockedMonths: []  // 마감 승인된 읽기전용 월 목록 ["2026-02", ...]
}

// ── 읽기전용 헬퍼 ────────────────────────────────────────────
// 관리자는 항상 편집 가능, 영양사는 마감 승인된 달은 읽기전용
function isReadOnly(year, month) {
  if (App.role === 'admin') return false
  const key = `${year}-${String(month).padStart(2,'0')}`
  return App.lockedMonths.includes(key)
}

// 읽기전용 배너 HTML (페이지 상단에 표시)
function readOnlyBanner() {
  return `<div class="flex items-center gap-2 bg-amber-50 border border-amber-200 rounded-xl px-4 py-2.5 mb-4 text-sm text-amber-800">
    <i class="fas fa-lock text-amber-500"></i>
    <span><strong>마감 완료된 달</strong>입니다. 데이터를 수정할 수 없습니다. (조회만 가능)</span>
  </div>`
}

// 마감 승인 폴링 타이머 ID (전역에 선언해 navigateTo에서 접근 가능)
let _closingPollTimer = null
function stopClosingPoll() {
  if (_closingPollTimer) {
    clearInterval(_closingPollTimer)
    _closingPollTimer = null
  }
}
function startClosingPoll(approvedYear, approvedMonth) {
  stopClosingPoll()
  _closingPollTimer = setInterval(async () => {
    try {
      const am = await api('GET', '/api/settings/active-month')
      if (!am) return
      const isAdvanced = (am.year > approvedYear) ||
        (am.year === approvedYear && am.month > approvedMonth)
      if (isAdvanced || (am.closingStatus === 'open' && am.year === approvedYear && am.month === approvedMonth)) {
        stopClosingPoll()
        App.currentYear = am.year
        App.currentMonth = am.month
        updateMonthDisplay()
        showToast(`관리자가 마감을 승인했습니다. ${am.year}년 ${am.month}월로 전환됩니다.`, 'success')
        renderSettings()
      }
    } catch (e) {}
  }, 20000) // 20초마다 확인
}

// ── 초기화 ────────────────────────────────────────────────────
window.addEventListener('DOMContentLoaded', async () => {
  if (!App.token) { window.location.href = '/login'; return }
  // 운영진(executive) 역할이면 전용 대시보드로 리다이렉트
  if (App.role === 'executive') { window.location.href = '/executive'; return }

  // 병원 계정이면 DB의 활성 월(current_year/month)로 App 상태 동기화
  if (App.role !== 'admin') {
    try {
      const am = await api('GET', '/api/settings/active-month')
      if (am?.year) {
        App.currentYear = am.year
        App.currentMonth = am.month
      }
      // 마감 승인된 월 목록 저장 (읽기전용 처리용)
      if (am?.lockedMonths) App.lockedMonths = am.lockedMonths
    } catch(e) {}
    // heartbeat 시작 (60초마다 현재 페이지 서버에 전달)
    startHeartbeat()
  }

  initSidebar()
  initMobileNav()   // 모바일 하단 네비 초기화
  initMobileUtils() // 모바일 제스처/UX 초기화

  const path = window.location.pathname
  const pageMap = {
    '/dashboard': 'dashboard', '/': 'dashboard',
    '/orders': 'orders', '/meals': 'meals',
    '/schedule': 'schedule', '/analysis': 'analysis',
    '/settings': 'settings', '/admin': 'admin'
  }
  navigateTo(pageMap[path] || 'dashboard')
})

// ── 모바일 사이드바 토글 ──────────────────────────────────────
window.openSidebar = function() {
  const sidebar = document.getElementById('sidebar')
  const overlay = document.getElementById('sidebarOverlay')
  if (sidebar) sidebar.classList.add('open')
  if (overlay) overlay.classList.add('active')
  document.body.style.overflow = 'hidden'
}
window.closeSidebar = function() {
  const sidebar = document.getElementById('sidebar')
  const overlay = document.getElementById('sidebarOverlay')
  if (sidebar) sidebar.classList.remove('open')
  if (overlay) overlay.classList.remove('active')
  document.body.style.overflow = ''
}

// ── 모바일 하단 네비게이션 초기화 ─────────────────────────────
function initMobileNav() {
  const nav = document.getElementById('mobileBottomNav')
  const container = document.getElementById('mobileNavItems')
  if (!nav || !container) return

  const menus = App.role === 'admin' ? getAdminMenus() : getHospitalMenus()
  // 최대 5개만 표시
  const mobileMenus = menus.slice(0, 5)

  container.innerHTML = mobileMenus.map(item => `
    <div class="mobile-nav-item" id="mobnav-${item.id}" onclick="navigateTo('${item.id}');closeSidebar()">
      <i class="fas ${item.icon}"></i>
      <span>${item.label.length > 4 ? item.label.substring(0,4) : item.label}</span>
    </div>
  `).join('')
}

// 모바일 하단 네비 활성 상태 업데이트
function updateMobileNav(page) {
  document.querySelectorAll('.mobile-nav-item').forEach(el => {
    el.classList.toggle('active', el.id === `mobnav-${page}`)
  })
}

// ── 모바일 유틸리티 초기화 ────────────────────────────────────
function initMobileUtils() {
  // 모바일 판단 (768px 이하)
  const isMobile = () => window.innerWidth <= 768

  // 사이드바 메뉴 클릭 시 모바일이면 자동 닫기
  document.addEventListener('click', (e) => {
    const menuItem = e.target.closest('.menu-item')
    if (menuItem && isMobile()) {
      closeSidebar()
    }
  })

  // 키보드(숫자 입력) 시 하단 nav 잠시 숨기기 (모바일 전용)
  if (isMobile()) {
    document.addEventListener('focusin', (e) => {
      if (e.target.tagName === 'INPUT' || e.target.tagName === 'TEXTAREA') {
        const nav = document.getElementById('mobileBottomNav')
        if (nav) nav.style.display = 'none'
        const main = document.querySelector('main')
        if (main) main.style.paddingBottom = '0'
      }
    })
    document.addEventListener('focusout', (e) => {
      setTimeout(() => {
        const nav = document.getElementById('mobileBottomNav')
        if (nav) nav.style.display = 'block'
        const main = document.querySelector('main')
        if (main) main.style.paddingBottom = '60px'
      }, 200)
    })
  }
}

// ── 세션 heartbeat (병원 계정 전용) ─────────────────────────
// D1 write 최적화: 120초 간격으로 변경 (기존 60초 → 하루 720회/계정으로 50% 절감)
let _heartbeatTimer = null
let _heartbeatFailCount = 0  // 연속 실패 횟수 추적
function startHeartbeat() {
  if (_heartbeatTimer) clearInterval(_heartbeatTimer)
  _heartbeatFailCount = 0
  sendHeartbeat()
  _heartbeatTimer = setInterval(sendHeartbeat, 120000) // 120초마다 (D1 write 절감)
}
async function sendHeartbeat() {
  if (App.role === 'admin') return
  try {
    const res = await api('POST', '/api/settings/session/heartbeat', { page: App.currentPage })
    if (res?.ok !== false) _heartbeatFailCount = 0  // 성공 시 실패 카운트 초기화
  } catch(e) {
    _heartbeatFailCount++
    // 3회 연속 실패 시 30초 후 재시도 (네트워크 일시 오류 대응)
    if (_heartbeatFailCount >= 3) {
      _heartbeatFailCount = 0
      if (_heartbeatTimer) clearInterval(_heartbeatTimer)
      setTimeout(() => {
        _heartbeatTimer = setInterval(sendHeartbeat, 120000)
        sendHeartbeat()
      }, 30000)
    }
  }
}

// ── 실시간 활동 로그 전송 (실제 편집 시에만 호출) ─────────────
// D1 write 최적화: 동일 액션 3초 이내 중복 호출 방지 (debounce)
let _lastActivityAction = null
let _lastActivityTime = 0
async function sendActivityLog(action) {
  if (App.role === 'admin') return
  const now = Date.now()
  // 동일 액션이 3초 이내 중복 호출되면 스킵 (D1 write 중복 방지)
  if (action === _lastActivityAction && now - _lastActivityTime < 3000) return
  _lastActivityAction = action
  _lastActivityTime = now
  try {
    await api('POST', '/api/settings/session/activity', {
      page: App.currentPage,
      action: action || ''
    })
  } catch(e) {}
}

// ── 스마트 폴링 (관리자 대시보드 실시간 갱신) ─────────────────
let _smartPollTimer = null
let _lastInputTime = 0
let _isPolling = false

function startSmartPolling(refreshFn, baseInterval = 10000) {
  stopSmartPolling()
  // 입력 감지: 포커스 중인 셀은 갱신 제외
  const onInput = () => { _lastInputTime = Date.now() }
  document.addEventListener('input', onInput)
  document.addEventListener('change', onInput)

  _smartPollTimer = setInterval(async () => {
    if (_isPolling) return
    // 입력 중(2초 이내)이면 건너뜀
    if (Date.now() - _lastInputTime < 2000) return
    // 포커스된 입력 요소 있으면 건너뜀
    const focused = document.activeElement
    if (focused && (focused.tagName === 'INPUT' || focused.tagName === 'TEXTAREA' || focused.tagName === 'SELECT')) return
    _isPolling = true
    try { await refreshFn() } catch(e) {}
    _isPolling = false
  }, baseInterval)

  return () => {
    document.removeEventListener('input', onInput)
    document.removeEventListener('change', onInput)
  }
}

function stopSmartPolling() {
  if (_smartPollTimer) {
    clearInterval(_smartPollTimer)
    _smartPollTimer = null
  }
  _isPolling = false
}

function initSidebar() {
  document.getElementById('hospitalNameDisplay').textContent = App.hospitalName || '병원'
  document.getElementById('usernameDisplay').textContent = App.username
  document.getElementById('roleDisplay').textContent = App.role === 'admin' ? '관리자' : '영양사'
  updateMonthDisplay()
  const menus = App.role === 'admin' ? getAdminMenus() : getHospitalMenus()
  document.getElementById('menuContainer').innerHTML = menus.map(renderMenuItem).join('')
  // 관리자면 알림 배지 로드
  if (App.role === 'admin') loadNotificationBadge()
}

async function loadNotificationBadge() {
  const data = await api('GET', '/api/admin/notifications')
  if (!data) return
  const notifCnt = data.unreadCount || 0

  // 마감 승인 요청 건수도 별도로 가져오기
  let closeReqCnt = 0
  try {
    const cr = await api('GET', '/api/admin/close-requests/pending')
    closeReqCnt = cr?.count || 0
  } catch(e) {}

  // ① 마감요청 배지 (빨간색) - 별도 표시
  const closeReqEl = document.getElementById('close-req-badge')
  if (closeReqEl) {
    if (closeReqCnt > 0) {
      closeReqEl.textContent = closeReqCnt > 9 ? '9+' : closeReqCnt
      closeReqEl.style.display = ''
      closeReqEl.title = `📋 마감요청 ${closeReqCnt}건`
    } else {
      closeReqEl.style.display = 'none'
    }
  }

  // ② 이슈 알림 배지 (주황색) - 별도 표시
  const issueBadgeEl = document.getElementById('notif-issue-badge')
  if (issueBadgeEl) {
    if (notifCnt > 0) {
      issueBadgeEl.textContent = notifCnt > 9 ? '9+' : notifCnt
      issueBadgeEl.style.display = ''
      issueBadgeEl.title = `🔔 이슈알림 ${notifCnt}건`
    } else {
      issueBadgeEl.style.display = 'none'
    }
  }

  // 기존 단일 배지(notif-badge) 정리 - 이전 코드 잔재 제거
  const menuEl = document.getElementById('menu-hospital-manage')
  if (menuEl) {
    const existing = menuEl.querySelector('.notif-badge')
    if (existing) existing.remove()
  }

  App.unreadNotifCount = notifCnt
  App.closeReqCount = closeReqCnt
}

