// ════════════════════════════════════════════════════════════════
// 운영 분석 탭 (9번 요청)
// ════════════════════════════════════════════════════════════════
function renderAnalysisTab() {
  const year  = App.currentYear
  const month = App.currentMonth
  const ad    = scheduleAnalysisData
  if (!ad) return `<div class="bg-white rounded-2xl p-8 text-center text-gray-400">분석 데이터 로딩 중...</div>`

  // 영양사(hospital) 역할은 간소화 뷰 표시
  if (App.role === 'hospital') return renderAnalysisTabSimple(ad, year, month)

  const dateMap    = ad.date_map    || {}
  const monthly    = ad.monthly     || {}
  const shortDates = ad.short_dates || {}
  const clusterDates = ad.cluster_dates || {}
  const days = getDaysInMonth(year, month)

  // 날짜 목록
  const dateList = []
  for (let d = 1; d <= days; d++) {
    const ds = `${year}-${String(month).padStart(2,'0')}-${String(d).padStart(2,'0')}`
    dateList.push({ d, ds, data: dateMap[ds] || null })
  }

  // 주별 집계
  const weeks = []
  let wk = { num: 1, work: 0, rest: 0, annual: 0, ot: 0, temp: 0 }
  for (const { d, ds, data } of dateList) {
    const dow = getDayOfWeek(year, month, d)
    if (data) {
      wk.work   += data.work   || 0
      wk.rest   += data.rest   || 0
      wk.annual += data.annual || 0
      wk.ot     += data.ot     || 0
      wk.temp   += data.tempStaff || 0
    }
    if (dow === '일' || d === days) {
      weeks.push({ ...wk })
      wk = { num: wk.num + 1, work: 0, rest: 0, annual: 0, ot: 0, temp: 0 }
    }
  }

  const shortCount   = Object.keys(shortDates).length
  const clusterCount = Object.keys(clusterDates).length

  // ── 파출/알바 외부인력 집계 ──────────────────────────────
  const extWorkers = scheduleExternalWorkers || []
  const extMap = scheduleExtSchedMap || {}
  let extDispatchDays = 0, extParttimeDays = 0
  const dispatchSet = new Set(), parttimeSet = new Set()
  extWorkers.forEach(w => {
    let worked = false
    for (let d = 1; d <= days; d++) {
      const ds = `${year}-${String(month).padStart(2,'0')}-${String(d).padStart(2,'0')}`
      const key = `${w.id}_${ds}`
      if (extMap[key]?.shift_type || extMap[key]?.shift_code) {
        if (w.worker_type === 'dispatch') { extDispatchDays++; worked = true }
        else { extParttimeDays++; worked = true }
      }
    }
    if (worked) {
      if (w.worker_type === 'dispatch') dispatchSet.add(w.id)
      else parttimeSet.add(w.id)
    }
  })
  const extDispatchCount = dispatchSet.size
  const extParttimeCount = parttimeSet.size
  const hasExtWorkers = extWorkers.length > 0
  const totalWorkDays = (monthly.totalWork || 0) + extDispatchDays + extParttimeDays
  const totalPersonnel = (ad.total_employees || 0) + extDispatchCount + extParttimeCount

  return `
  <div class="space-y-4">
    <!-- 월간 요약 카드 -->
    <div class="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-6 gap-3">
      ${[
        { label:'총 근무', value: monthly.totalWork||0, unit:'건', color:'text-green-700', bg:'bg-green-50' },
        { label:'총 휴무', value: monthly.totalRest||0, unit:'건', color:'text-red-700', bg:'bg-red-50' },
        { label:'연차 사용', value: monthly.totalAnnual||0, unit:'건', color:'text-yellow-700', bg:'bg-yellow-50' },
        { label:'반차(오전)', value: monthly.totalHalfAM||0, unit:'건', color:'text-purple-700', bg:'bg-purple-50' },
        { label:'반차(오후)', value: monthly.totalHalfPM||0, unit:'건', color:'text-blue-700', bg:'bg-blue-50' },
        { label:'경조사', value: monthly.totalEvent||0, unit:'건', color:'text-pink-700', bg:'bg-pink-50' },
      ].map(c => `
        <div class="bg-white rounded-xl p-3 border border-gray-100 shadow-sm ${c.bg}">
          <div class="text-xs text-gray-500 mb-1">${c.label}</div>
          <div class="text-xl font-bold ${c.color}">${c.value}<span class="text-xs ml-0.5">${c.unit}</span></div>
        </div>`).join('')}
    </div>

    <!-- 파출/알바 + 전체 인력 통합 분석 -->
    ${hasExtWorkers ? `
    <div class="bg-white rounded-2xl shadow-sm border border-orange-100 overflow-hidden">
      <div class="px-5 py-3 border-b border-orange-100 bg-orange-50">
        <h3 class="font-bold text-orange-800 text-sm"><i class="fas fa-people-carry mr-2"></i>파출·알바 외부인력 현황</h3>
      </div>
      <div class="p-4 grid grid-cols-2 md:grid-cols-4 gap-3">
        <div class="bg-orange-50 rounded-xl p-3 border border-orange-200">
          <div class="text-xs text-orange-600 mb-1">파출 인원</div>
          <div class="text-xl font-bold text-orange-700">${extDispatchCount}<span class="text-xs ml-1">명</span></div>
          <div class="text-xs text-orange-400 mt-1">총 ${extDispatchDays}일 근무</div>
        </div>
        <div class="bg-amber-50 rounded-xl p-3 border border-amber-200">
          <div class="text-xs text-amber-600 mb-1">알바 인원</div>
          <div class="text-xl font-bold text-amber-700">${extParttimeCount}<span class="text-xs ml-1">명</span></div>
          <div class="text-xs text-amber-400 mt-1">총 ${extParttimeDays}일 근무</div>
        </div>
        <div class="bg-blue-50 rounded-xl p-3 border border-blue-200">
          <div class="text-xs text-blue-600 mb-1">전체 인원 (정규+외부)</div>
          <div class="text-xl font-bold text-blue-700">${totalPersonnel}<span class="text-xs ml-1">명</span></div>
          <div class="text-xs text-blue-400 mt-1">정규 ${ad.total_employees||0}명 + 외부 ${extDispatchCount+extParttimeCount}명</div>
        </div>
        <div class="bg-green-50 rounded-xl p-3 border border-green-200">
          <div class="text-xs text-green-600 mb-1">전체 근무일수 합계</div>
          <div class="text-xl font-bold text-green-700">${totalWorkDays}<span class="text-xs ml-1">건</span></div>
          <div class="text-xs text-green-400 mt-1">정규 ${monthly.totalWork||0} + 파출 ${extDispatchDays} + 알바 ${extParttimeDays}</div>
        </div>
      </div>
    </div>` : ''}

    <!-- 경고 섹션 -->
    ${(shortCount > 0 || clusterCount > 0) ? `
    <div class="grid grid-cols-1 md:grid-cols-2 gap-3">
      ${shortCount > 0 ? `
      <div class="bg-red-50 border border-red-200 rounded-xl p-4">
        <h4 class="font-bold text-red-700 mb-2"><i class="fas fa-exclamation-triangle mr-1"></i>최소 인력 미달 (${shortCount}일)</h4>
        <div class="space-y-1 max-h-32 overflow-y-auto">
          ${Object.entries(shortDates).slice(0,10).map(([date, items]) =>
            `<div class="text-xs text-red-600">📅 ${date}: ${items.map(i => `${i.position} ${i.actual}/${i.required}명`).join(', ')}</div>`
          ).join('')}
        </div>
      </div>` : ''}
      ${clusterCount > 0 ? `
      <div class="bg-orange-50 border border-orange-200 rounded-xl p-4">
        <h4 class="font-bold text-orange-700 mb-2"><i class="fas fa-users-slash mr-1"></i>휴무/연차 쏠림 (${clusterCount}일)</h4>
        <div class="space-y-1 max-h-32 overflow-y-auto">
          ${Object.entries(clusterDates).slice(0,10).map(([date, info]) =>
            `<div class="text-xs text-orange-600">📅 ${date}: 연차 ${info.annual}명, 휴무 ${info.rest}명</div>`
          ).join('')}
        </div>
      </div>` : ''}
    </div>` : ''}

    <!-- 날짜별 상세 분석 -->
    <div class="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
      <div class="px-5 py-4 border-b flex items-center justify-between">
        <h3 class="font-bold text-gray-800">${year}년 ${month}월 일별 분석</h3>
      </div>
      <div class="overflow-x-auto overflow-y-auto" style="max-height:50vh">
        <table class="w-full text-xs">
          <thead class="bg-gray-800 text-white sticky top-0">
            <tr>
              <th class="px-3 py-2 text-left sticky left-0 bg-gray-800 min-w-[70px]">날짜</th>
              <th class="px-2 py-2 text-center">근무</th>
              <th class="px-2 py-2 text-center">휴무</th>
              <th class="px-2 py-2 text-center">연차</th>
              <th class="px-2 py-2 text-center">오전반차</th>
              <th class="px-2 py-2 text-center">오후반차</th>
              <th class="px-2 py-2 text-center">경조</th>
              <th class="px-2 py-2 text-center">OT</th>
              <th class="px-2 py-2 text-center">파출/알바</th>
              <th class="px-2 py-2 text-left">경고</th>
            </tr>
          </thead>
          <tbody>
            ${dateList.map(({ d, ds, data }) => {
              const dow = getDayOfWeek(year, month, d)
              const isWknd = ['토','일'].includes(dow)
              const hasShort = shortDates[ds]
              const hasCluster = clusterDates[ds]
              const bg = hasShort ? '#fff1f2' : hasCluster ? '#fffbeb' : isWknd ? '#f8fafc' : 'white'
              return `<tr style="background:${bg};border-bottom:1px solid #e5e7eb">
                <td class="px-3 py-2 sticky left-0 font-semibold" style="background:${bg}">
                  <span style="color:${dow==='일'?'#dc2626':dow==='토'?'#b45309':'#374151'}">${d}일(${dow})</span>
                </td>
                <td class="px-2 py-2 text-center font-bold text-green-700">${data?.work||0}</td>
                <td class="px-2 py-2 text-center text-red-600">${data?.rest||0}</td>
                <td class="px-2 py-2 text-center text-yellow-600">${data?.annual||0}</td>
                <td class="px-2 py-2 text-center text-purple-600">${data?.halfAM||0}</td>
                <td class="px-2 py-2 text-center text-blue-600">${data?.halfPM||0}</td>
                <td class="px-2 py-2 text-center text-pink-600">${data?.event||0}</td>
                <td class="px-2 py-2 text-center text-emerald-600">${data?.ot||0}</td>
                <td class="px-2 py-2 text-center text-orange-600">${data?.tempStaff||0}</td>
                <td class="px-2 py-2 text-xs">
                  ${hasShort ? `<span class="text-red-600 font-bold">⚠인력부족</span> ` : ''}
                  ${hasCluster ? `<span class="text-orange-600 font-bold">⚠쏠림</span>` : ''}
                </td>
              </tr>`
            }).join('')}
          </tbody>
          <tfoot class="bg-gray-100 border-t-2 sticky bottom-0">
            <tr class="font-bold">
              <td class="px-3 py-2 sticky left-0 bg-gray-100">월 합계</td>
              <td class="px-2 py-2 text-center text-green-700">${monthly.totalWork||0}</td>
              <td class="px-2 py-2 text-center text-red-600">${monthly.totalRest||0}</td>
              <td class="px-2 py-2 text-center text-yellow-600">${monthly.totalAnnual||0}</td>
              <td class="px-2 py-2 text-center text-purple-600">${monthly.totalHalfAM||0}</td>
              <td class="px-2 py-2 text-center text-blue-600">${monthly.totalHalfPM||0}</td>
              <td class="px-2 py-2 text-center text-pink-600">${monthly.totalEvent||0}</td>
              <td class="px-2 py-2 text-center text-emerald-600">${monthly.totalOT||0}</td>
              <td class="px-2 py-2 text-center text-orange-600">${monthly.totalTempStaff||0}</td>
              <td></td>
            </tr>
          </tfoot>
        </table>
      </div>
    </div>

    <!-- 주별 집계 -->
    <div class="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
      <div class="px-5 py-3 border-b"><h3 class="font-bold text-gray-800 text-sm">주별 집계</h3></div>
      <div class="overflow-x-auto">
        <table class="w-full text-sm">
          <thead class="bg-gray-50 border-b">
            <tr>
              <th class="px-4 py-2 text-left text-xs text-gray-600">주차</th>
              <th class="px-3 py-2 text-center text-xs text-green-700">근무</th>
              <th class="px-3 py-2 text-center text-xs text-red-600">휴무</th>
              <th class="px-3 py-2 text-center text-xs text-yellow-600">연차</th>
              <th class="px-3 py-2 text-center text-xs text-emerald-600">OT</th>
              <th class="px-3 py-2 text-center text-xs text-orange-600">파출/알바</th>
            </tr>
          </thead>
          <tbody>
            ${weeks.map(w => `<tr class="border-b">
              <td class="px-4 py-2 font-medium text-gray-700">${w.num}주차</td>
              <td class="px-3 py-2 text-center font-bold text-green-700">${w.work}</td>
              <td class="px-3 py-2 text-center text-red-600">${w.rest}</td>
              <td class="px-3 py-2 text-center text-yellow-600">${w.annual}</td>
              <td class="px-3 py-2 text-center text-emerald-600">${w.ot}</td>
              <td class="px-3 py-2 text-center text-orange-600">${w.temp}</td>
            </tr>`).join('')}
          </tbody>
        </table>
      </div>
    </div>

    <!-- OT 직원별 집계 -->
    ${Object.keys(monthly.otByEmp||{}).length > 0 ? `
    <div class="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
      <div class="px-5 py-3 border-b"><h3 class="font-bold text-gray-800 text-sm">개인별 오버타임 집계</h3></div>
      <div class="p-4 flex flex-wrap gap-2">
        ${Object.entries(monthly.otByEmp||{}).sort((a,b)=>b[1]-a[1]).map(([name, hrs]) =>
          `<div class="bg-emerald-50 border border-emerald-200 rounded-lg px-3 py-2 text-sm">
            <span class="font-medium text-gray-700">${name}</span>
            <span class="ml-2 font-bold text-emerald-700">${hrs}시간</span>
          </div>`
        ).join('')}
      </div>
    </div>` : ''}
  </div>`
}

// ════════════════════════════════════════════════════════════════
// 영양사(hospital) 전용 운영분석 간소화 뷰
// ════════════════════════════════════════════════════════════════
function renderAnalysisTabSimple(ad, year, month) {
  const monthly    = ad.monthly     || {}
  const shortDates = ad.short_dates || {}
  const clusterDates = ad.cluster_dates || {}
  const shortCount   = Object.keys(shortDates).length
  const clusterCount = Object.keys(clusterDates).length

  // 외부인력 집계
  const extWorkers = scheduleExternalWorkers || []
  const extMap = scheduleExtSchedMap || {}
  const days = getDaysInMonth(year, month)
  let extDispatchDays = 0, extParttimeDays = 0
  extWorkers.forEach(w => {
    for (let d = 1; d <= days; d++) {
      const ds = `${year}-${String(month).padStart(2,'0')}-${String(d).padStart(2,'0')}`
      const key = `${w.id}_${ds}`
      if (extMap[key]?.shift_type || extMap[key]?.shift_code) {
        if (w.worker_type === 'dispatch') extDispatchDays++
        else extParttimeDays++
      }
    }
  })

  // ── OT 발생 직원 집계 ────────────────────────────────────────
  const otByEmp = monthly.otByEmp || {}
  const otEntries = Object.entries(otByEmp)
    .filter(([, hrs]) => hrs > 0)
    .sort((a, b) => b[1] - a[1])
  const otCount = otEntries.length

  // ── 직원별 이달 근무 요약 (sched_map 기반) ───────────────────
  const sm   = scheduleMonthData?.sched_map || {}
  const REST_CODES_S = new Set([...CALC_ENGINE.REST_CODES_SET, '반차','대체','오전','오후']) // ✅ CALC_ENGINE + 확장
  const ANNUAL_CODES = new Set(['연'])
  const empsForSummary = (scheduleEmployees || []).filter(e => e.is_active !== 0 && !e.resign_date)

  // 연차 잔여 맵 (scheduleLeavesData 기반)
  const leaveMap = {}
  ;(scheduleLeavesData || []).forEach(l => { leaveMap[l.employee_id] = l })

  const empSummaryRows = empsForSummary.map(e => {
    let workDays = 0, restDays = 0, annualUsed = 0
    for (let d = 1; d <= days; d++) {
      const ds = `${year}-${String(month).padStart(2,'0')}-${String(d).padStart(2,'0')}`
      const entry = sm[`${e.id}_${ds}`] || {}
      const code  = entry.shift_code || ''
      if (!code || code === '-') continue
      if (ANNUAL_CODES.has(code)) { annualUsed++; restDays++ }
      else if (REST_CODES_S.has(code)) restDays++
      else workDays++
    }
    const leaveRow      = leaveMap[e.id]
    // ✅ CALC_ENGINE: calcAnnualRemain (이월연차 포함 — 이전: remaining_days 직접 참조)
    const { remain: _annR } = CALC_ENGINE.calcAnnualRemain(leaveRow)
    const annualRemain  = _annR !== null ? _annR : '-'
    const otHrs         = otByEmp[e.name] || 0
    return { name: e.name, position: e.position_name || '', workDays, restDays, annualUsed, annualRemain, otHrs }
  })

  const riskLevel = shortCount > 5 ? 'high' : shortCount > 0 ? 'mid' : 'ok'
  const clusterLevel = clusterCount > 5 ? 'high' : clusterCount > 0 ? 'mid' : 'ok'

  const riskColor = riskLevel === 'high' ? '#dc2626' : riskLevel === 'mid' ? '#d97706' : '#16a34a'
  const riskBg    = riskLevel === 'high' ? '#fef2f2' : riskLevel === 'mid' ? '#fffbeb' : '#f0fdf4'
  const clusterColor = clusterLevel === 'high' ? '#dc2626' : clusterLevel === 'mid' ? '#d97706' : '#16a34a'
  const clusterBg    = clusterLevel === 'high' ? '#fef2f2' : clusterLevel === 'mid' ? '#fffbeb' : '#f0fdf4'

  return `
  <div class="space-y-4">
    <!-- 리스크 요약 배너 -->
    ${(shortCount > 0 || clusterCount > 0) ? `
    <div class="bg-red-50 border border-red-200 rounded-2xl p-4">
      <div class="flex items-center gap-2 mb-2">
        <i class="fas fa-exclamation-triangle text-red-600"></i>
        <span class="font-bold text-red-700 text-sm">${month}월 운영 주의사항</span>
      </div>
      <div class="flex flex-wrap gap-3">
        ${shortCount > 0 ? `<span class="inline-flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-sm font-bold" style="background:${riskBg};color:${riskColor};border:1px solid ${riskColor}30">
          <i class="fas fa-user-minus text-xs"></i> 인력 부족일 <strong>${shortCount}일</strong>
        </span>` : ''}
        ${clusterCount > 0 ? `<span class="inline-flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-sm font-bold" style="background:${clusterBg};color:${clusterColor};border:1px solid ${clusterColor}30">
          <i class="fas fa-users-slash text-xs"></i> 휴무·연차 쏠림일 <strong>${clusterCount}일</strong>
        </span>` : ''}
      </div>
    </div>` : `
    <div class="bg-green-50 border border-green-200 rounded-2xl p-4 flex items-center gap-3">
      <i class="fas fa-check-circle text-green-600 text-xl"></i>
      <span class="font-bold text-green-700">${month}월 운영 이상 없음 — 인력 부족 및 연차 쏠림 없음</span>
    </div>`}

    <!-- 월간 핵심 수치 카드 -->
    <div class="grid grid-cols-2 md:grid-cols-3 gap-3">
      ${[
        { label:'총 근무', value: monthly.totalWork||0, unit:'건', color:'text-green-700', bg:'bg-green-50', icon:'fa-briefcase' },
        { label:'총 휴무', value: monthly.totalRest||0, unit:'건', color:'text-red-600', bg:'bg-red-50', icon:'fa-bed' },
        { label:'연차 사용', value: monthly.totalAnnual||0, unit:'건', color:'text-yellow-700', bg:'bg-yellow-50', icon:'fa-umbrella-beach' },
        { label:'반차(오전)', value: monthly.totalHalfAM||0, unit:'건', color:'text-purple-700', bg:'bg-purple-50', icon:'fa-sun' },
        { label:'반차(오후)', value: monthly.totalHalfPM||0, unit:'건', color:'text-blue-700', bg:'bg-blue-50', icon:'fa-moon' },
        { label:'경조사', value: monthly.totalEvent||0, unit:'건', color:'text-pink-700', bg:'bg-pink-50', icon:'fa-heart' },
      ].map(c => `
        <div class="bg-white rounded-xl p-4 border border-gray-100 shadow-sm">
          <div class="flex items-center gap-2 mb-2">
            <div class="w-8 h-8 rounded-lg ${c.bg} flex items-center justify-center">
              <i class="fas ${c.icon} text-xs ${c.color}"></i>
            </div>
            <span class="text-xs text-gray-500">${c.label}</span>
          </div>
          <div class="text-2xl font-bold ${c.color}">${c.value}<span class="text-xs ml-0.5 font-normal">${c.unit}</span></div>
        </div>`).join('')}
    </div>

    <!-- OT 요약 배너 (발생 직원 있을 때만) -->
    ${otCount > 0 ? `
    <div class="bg-amber-50 border border-amber-200 rounded-2xl overflow-hidden">
      <!-- 헤더 (클릭으로 펼침/접기) -->
      <button onclick="this.closest('.ot-summary-card').querySelector('.ot-detail').classList.toggle('hidden')"
        class="ot-summary-card w-full" style="display:block;background:none;border:none;padding:0;cursor:pointer;text-align:left">
        <div class="ot-summary-card px-5 py-3 flex items-center justify-between">
          <div class="flex items-center gap-3">
            <div class="w-8 h-8 rounded-lg bg-amber-100 flex items-center justify-center flex-shrink-0">
              <i class="fas fa-clock text-amber-600 text-sm"></i>
            </div>
            <div>
              <div class="font-bold text-amber-800 text-sm">OT 발생 직원 <span class="text-amber-600">${otCount}명</span></div>
              <div class="text-xs text-amber-600 mt-0.5">${otEntries.slice(0,3).map(([n]) => n).join(', ')}${otCount > 3 ? ` 외 ${otCount-3}명` : ''}</div>
            </div>
          </div>
          <div class="flex items-center gap-2">
            <span class="text-xs text-amber-500 bg-amber-100 px-2 py-1 rounded-md">탭하여 상세 보기</span>
            <i class="fas fa-chevron-down text-amber-400 text-xs"></i>
          </div>
        </div>
      </button>
      <!-- 펼침 상세 (기본 숨김) -->
      <div class="ot-detail hidden border-t border-amber-100">
        <div class="px-5 py-3 space-y-2">
          ${otEntries.map(([name, hrs]) => `
          <div class="flex items-center justify-between py-1.5 border-b border-amber-50 last:border-0">
            <span class="text-sm font-medium text-gray-700"><i class="fas fa-user text-amber-400 mr-2 text-xs"></i>${name}</span>
            <span class="text-sm font-bold text-amber-700 bg-amber-100 px-2.5 py-0.5 rounded-full">${hrs}시간</span>
          </div>`).join('')}
        </div>
        <div class="px-5 pb-3 text-xs text-amber-500">
          <i class="fas fa-info-circle mr-1"></i>비용 상세는 관리자 인력비 탭에서 확인하세요.
        </div>
      </div>
    </div>` : `
    <div class="bg-green-50 border border-green-100 rounded-2xl px-5 py-3 flex items-center gap-3">
      <i class="fas fa-clock text-green-500"></i>
      <span class="text-sm text-green-700 font-medium">이달 OT 발생 직원 없음</span>
    </div>`}

    <!-- 직원별 이달 근무 요약 표 -->
    ${empSummaryRows.length > 0 ? `
    <div class="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
      <div class="px-5 py-3 border-b bg-gray-50 flex items-center gap-2">
        <i class="fas fa-table text-gray-500 text-sm"></i>
        <span class="font-bold text-gray-700 text-sm">직원별 이달 근무 요약</span>
        <span class="text-xs text-gray-400 ml-1">${year}년 ${month}월</span>
      </div>
      <div class="overflow-x-auto">
        <table class="w-full text-sm">
          <thead class="bg-gray-50 border-b">
            <tr>
              <th class="px-4 py-2.5 text-left text-xs text-gray-500 font-semibold">이름</th>
              <th class="px-3 py-2.5 text-center text-xs text-green-600 font-semibold">근무일</th>
              <th class="px-3 py-2.5 text-center text-xs text-red-500 font-semibold">휴무일</th>
              <th class="px-3 py-2.5 text-center text-xs text-yellow-600 font-semibold">연차잔여</th>
              <th class="px-3 py-2.5 text-center text-xs text-amber-600 font-semibold">OT</th>
            </tr>
          </thead>
          <tbody>
            ${empSummaryRows.map((r, idx) => `
            <tr class="border-b ${idx % 2 === 0 ? '' : 'bg-gray-50/50'} hover:bg-blue-50/30">
              <td class="px-4 py-2.5">
                <div class="font-medium text-gray-800 text-sm">${r.name}</div>
                ${r.position ? `<div class="text-xs text-gray-400">${r.position}</div>` : ''}
              </td>
              <td class="px-3 py-2.5 text-center">
                <span class="font-bold text-green-700">${r.workDays}</span><span class="text-xs text-gray-400 ml-0.5">일</span>
              </td>
              <td class="px-3 py-2.5 text-center">
                <span class="text-red-500">${r.restDays}</span><span class="text-xs text-gray-400 ml-0.5">일</span>
              </td>
              <td class="px-3 py-2.5 text-center">
                ${r.annualRemain === '-'
                  ? `<span class="text-gray-300 text-xs">-</span>`
                  : `<span class="font-medium ${r.annualRemain <= 2 ? 'text-red-600' : 'text-gray-700'}">${r.annualRemain}</span><span class="text-xs text-gray-400 ml-0.5">일</span>`}
              </td>
              <td class="px-3 py-2.5 text-center">
                ${r.otHrs > 0
                  ? `<span class="inline-flex items-center gap-1 px-2 py-0.5 rounded-full bg-amber-100 text-amber-700 text-xs font-bold"><i class="fas fa-clock text-[10px]"></i>${r.otHrs}h</span>`
                  : `<span class="text-gray-300 text-xs">-</span>`}
              </td>
            </tr>`).join('')}
          </tbody>
        </table>
      </div>
    </div>` : ''}

    <!-- 파출/알바 현황 (있을 때만) -->
    ${extWorkers.length > 0 ? `
    <div class="bg-orange-50 border border-orange-200 rounded-2xl p-4">
      <div class="font-bold text-orange-800 text-sm mb-3"><i class="fas fa-people-carry mr-2"></i>외부인력 현황</div>
      <div class="grid grid-cols-2 gap-3">
        <div class="bg-white rounded-xl p-3 border border-orange-100 text-center">
          <div class="text-xs text-orange-500 mb-1">파출 근무일</div>
          <div class="text-xl font-bold text-orange-700">${extDispatchDays}<span class="text-xs ml-1">일</span></div>
        </div>
        <div class="bg-white rounded-xl p-3 border border-orange-100 text-center">
          <div class="text-xs text-amber-500 mb-1">알바 근무일</div>
          <div class="text-xl font-bold text-amber-700">${extParttimeDays}<span class="text-xs ml-1">일</span></div>
        </div>
      </div>
    </div>` : ''}

    <!-- 인력 부족 날짜 목록 -->
    ${shortCount > 0 ? `
    <div class="bg-white rounded-2xl shadow-sm border border-red-100 overflow-hidden">
      <div class="px-5 py-3 border-b border-red-100 bg-red-50 flex items-center gap-2">
        <i class="fas fa-user-minus text-red-600"></i>
        <span class="font-bold text-red-700 text-sm">인력 부족 날짜 (${shortCount}일)</span>
      </div>
      <div class="p-4 space-y-1.5 max-h-48 overflow-y-auto">
        ${Object.entries(shortDates).map(([date, items]) =>
          `<div class="flex items-center gap-2 py-1.5 border-b border-gray-50">
            <span class="text-xs font-bold text-red-600 min-w-[70px]">📅 ${date}</span>
            <span class="text-xs text-gray-600">${items.map(i => `${i.position} ${i.actual}/${i.required}명`).join(', ')}</span>
          </div>`
        ).join('')}
      </div>
    </div>` : ''}

    <!-- 연차·휴무 쏠림 날짜 -->
    ${clusterCount > 0 ? `
    <div class="bg-white rounded-2xl shadow-sm border border-orange-100 overflow-hidden">
      <div class="px-5 py-3 border-b border-orange-100 bg-orange-50 flex items-center gap-2">
        <i class="fas fa-users-slash text-orange-600"></i>
        <span class="font-bold text-orange-700 text-sm">휴무·연차 쏠림 날짜 (${clusterCount}일)</span>
      </div>
      <div class="p-4 space-y-1.5 max-h-48 overflow-y-auto">
        ${Object.entries(clusterDates).map(([date, info]) =>
          `<div class="flex items-center gap-2 py-1.5 border-b border-gray-50">
            <span class="text-xs font-bold text-orange-600 min-w-[70px]">📅 ${date}</span>
            <span class="text-xs text-gray-600">연차 ${info.annual}명, 휴무 ${info.rest}명</span>
          </div>`
        ).join('')}
      </div>
    </div>` : ''}

    <!-- 안내 문구 -->
    <div class="bg-blue-50 border border-blue-100 rounded-xl p-3 text-xs text-blue-600">
      <i class="fas fa-info-circle mr-1"></i>
      상세 분석 데이터(일별 집계, 주별 통계, 비용 현황)는 관리자에게 문의하세요.
    </div>
  </div>`
}

// ════════════════════════════════════════════════════════════════
// 직원 공유 뷰 전용 인쇄 함수
// ════════════════════════════════════════════════════════════════
window.printStaffView = function() {
  const staffTable = document.querySelector('.staff-emp-row')
  if (!staffTable) {
    alert('직원 공유 뷰가 현재 표시되어 있지 않습니다.')
    return
  }
  const container = staffTable.closest('div[style*="border-radius:16px"]') ||
                    staffTable.closest('div[style*="border-radius: 16px"]') ||
                    staffTable.closest('div')
  if (!container) { window.print(); return }

  // 그룹 헤더 행에서 직급 목록 추출
  const groupHeaders = container.querySelectorAll('tr td[colspan]')
  const groups = []
  groupHeaders.forEach((td, idx) => {
    const span = td.querySelector('span')
    const label = span?.textContent?.trim() || td.textContent?.trim() || ('그룹 ' + (idx+1))
    groups.push({ label, idx })
  })

  // 인쇄 옵션 모달
  const existingModal = document.getElementById('printSelectModal')
  if (existingModal) existingModal.remove()

  const modal = document.createElement('div')
  modal.id = 'printSelectModal'
  modal.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,.55);z-index:9999;display:flex;align-items:center;justify-content:center;padding:20px'
  modal.innerHTML = `
    <div style="background:white;border-radius:16px;padding:24px;min-width:320px;max-width:440px;box-shadow:0 8px 30px rgba(0,0,0,.2)">
      <h3 style="font-size:16px;font-weight:800;color:#1f2937;margin:0 0 6px"><i class="fas fa-print" style="color:#2563eb;margin-right:8px"></i>인쇄 범위 선택</h3>
      <p style="font-size:12px;color:#6b7280;margin:0 0 16px">인쇄할 직급을 선택하세요</p>
      <div style="display:flex;flex-direction:column;gap:8px;margin-bottom:20px">
        <label style="display:flex;align-items:center;gap:8px;padding:8px 12px;border:1px solid #e5e7eb;border-radius:8px;cursor:pointer;font-size:13px;font-weight:600;color:#374151">
          <input type="checkbox" id="printGrp_all" value="all" checked
            onchange="document.querySelectorAll('#printSelectModal input[type=checkbox]:not(#printGrp_all)').forEach(cb=>cb.checked=this.checked)"
            style="accent-color:#2563eb">
          전체 인쇄
        </label>
        ${groups.map((g, i) => `
        <label style="display:flex;align-items:center;gap:8px;padding:8px 12px;border:1px solid #e5e7eb;border-radius:8px;cursor:pointer;font-size:13px;color:#374151">
          <input type="checkbox" class="printGrpCb" value="${i}" checked style="accent-color:#2563eb">
          ${g.label}
        </label>`).join('')}
      </div>
      <div style="display:flex;gap:8px;justify-content:flex-end">
        <button onclick="document.getElementById('printSelectModal').remove()"
          style="padding:8px 16px;background:#f3f4f6;border:none;border-radius:8px;font-size:13px;cursor:pointer;font-weight:600;color:#374151">취소</button>
        <button onclick="executePrintStaffView()"
          style="padding:8px 20px;background:#2563eb;color:white;border:none;border-radius:8px;font-size:13px;font-weight:700;cursor:pointer">
          <i class="fas fa-print" style="margin-right:6px"></i>인쇄 실행</button>
      </div>
    </div>`
  document.body.appendChild(modal)
}

window.executePrintStaffView = function() {
  const modal = document.getElementById('printSelectModal')
  const checkedIdxs = new Set(
    Array.from(document.querySelectorAll('#printSelectModal .printGrpCb:checked')).map(cb => parseInt(cb.value))
  )
  modal?.remove()

  const container = document.querySelector('.staff-emp-row')?.closest('div[style*="border-radius:16px"]') ||
                    document.querySelector('.staff-emp-row')?.closest('div[style*="border-radius: 16px"]') ||
                    document.querySelector('.staff-emp-row')?.closest('div')
  if (!container) { window.print(); return }

  // 선택된 그룹만 포함한 클론 생성
  const clone = container.cloneNode(true)
  if (checkedIdxs.size > 0) {
    const tbody = clone.querySelector('tbody')
    if (tbody) {
      const allRows = Array.from(tbody.querySelectorAll('tr'))
      let currentGroupIdx = -1
      allRows.forEach(row => {
        const isGroupHeader = row.querySelector('td[colspan]')
        if (isGroupHeader) {
          currentGroupIdx++
          if (!checkedIdxs.has(currentGroupIdx)) row.remove()
        } else {
          if (currentGroupIdx >= 0 && !checkedIdxs.has(currentGroupIdx)) row.remove()
        }
      })
    }
  }

  const year = App.currentYear, month = App.currentMonth
  const printWindow = window.open('', '_blank', 'width=1400,height=900')
  printWindow.document.write(`<!DOCTYPE html>
<html>
<head>
<meta charset="utf-8">
<title>${year}년 ${month}월 근무표</title>
<link href="https://cdn.jsdelivr.net/npm/@fortawesome/fontawesome-free@6.4.0/css/all.min.css" rel="stylesheet">
<style>
  * { box-sizing:border-box; margin:0; padding:0; }
  body { font-family:-apple-system,BlinkMacSystemFont,sans-serif; background:white; }
  @page { margin:5mm; size:A4 landscape; }
  @media print {
    body { -webkit-print-color-adjust:exact; print-color-adjust:exact; }
    button { display:none!important; }
  }
  table { width:100%; border-collapse:collapse; font-size:8px; }
  th, td { padding:1px; }
  div[style*="overflow-x:auto"] { overflow:visible!important; max-height:none!important; }
</style>
</head>
<body>
${clone.outerHTML}
<script>
  document.querySelectorAll('button').forEach(b => b.style.display='none');
  window.onload = function() { window.print(); window.close(); }
</script>
</body>
</html>`)
  printWindow.document.close()
}


// ════════════════════════════════════════════════════════════════
// 인쇄/PDF 출력
// ════════════════════════════════════════════════════════════════
window.printSchedule = () => {
  const year  = App.currentYear
  const month = App.currentMonth
  const days  = getDaysInMonth(year, month)
  const emps  = scheduleEmployees
  const og    = scheduleOffGrants
  const md    = scheduleMonthData
  const schedMap = md?.sched_map || {}
  const leaveMap = md?.leave_map || {}
  const grantedSet = new Set((og?.granted_days||[]).map(d=>d.date))
  const subSet     = new Set((og?.substitute_days||[]).map(d=>d.date))
  const allOffSet  = new Set([...grantedSet, ...subSet])

  const SHIFT_COLORS = {}
  ;(scheduleShifts||[]).forEach(s => { SHIFT_COLORS[s.shift_code] = s.color })
  function getCellStyle(code) {
    if (!code || code==='-') return 'background:#f9fafb;color:#d1d5db'
    if (SHIFT_COLORS[code]) return `background:${SHIFT_COLORS[code]}33;color:${SHIFT_COLORS[code]};font-weight:700`
    const dm = {'연':'background:#fef9c3;color:#92400e','휴':'background:#fee2e2;color:#b91c1c','오전':'background:#ede9fe;color:#6d28d9','오후':'background:#dbeafe;color:#1d4ed8','경조':'background:#fce7f3;color:#9d174d','OT':'background:#ecfdf5;color:#065f46'}
    return dm[code]||'background:#f3f4f6;color:#374151'
  }

  let tableRows = ''
  const allEmps = [...emps.filter(e=>e.team==='cook'||!e.team), ...emps.filter(e=>e.team==='nutrition')]
  for (const emp of allEmps) {
    let cells = ''
    let workCount = 0, annualCount = 0
    for (let d=1; d<=days; d++) {
      const ds = `${year}-${String(month).padStart(2,'0')}-${String(d).padStart(2,'0')}`
      const dow = getDayOfWeek(year, month, d)
      const isOff = allOffSet.has(ds)
      const code  = schedMap[`${emp.id}_${ds}`]?.shift_code || ''
      const bg    = dow==='일'?'#fff1f2':dow==='토'?'#fffbeb':isOff?'#fffde7':'white'
      const st    = getCellStyle(code)
      if (code && code!=='-') {
        if (code==='연') annualCount++
        else if (!['휴','경조','병가'].includes(code)) workCount++
      }
      cells += `<td style="padding:2px;text-align:center;background:${bg};border:1px solid #e5e7eb">
        <span style="display:inline-block;width:22px;height:22px;line-height:22px;border-radius:3px;font-size:9px;${st}">${code||'·'}</span>
      </td>`
    }
    const lv = leaveMap[emp.id]
    const total = lv?.annual?.total ?? null
    const used  = lv?.annual?.used  ?? 0
    // 이월연차 합산 (수당지급 완료 시 0)
    const carriedOver = lv?.annual?.allowance_paid ? 0 : (lv?.annual?.carried_over_days ?? 0)
    const effectiveTotal = total !== null ? total + carriedOver : null
    const remain = effectiveTotal !== null ? effectiveTotal - used : '-'
    const remainDisplay = remain === '-' ? '-' : remain
    const remainColor = remain !== '-' && remain <= 3 ? 'color:#dc2626' : remain !== '-' && remain <= 7 ? 'color:#d97706' : 'color:#166534'
    tableRows += `<tr>
      <td style="padding:4px 8px;font-weight:600;font-size:11px;border:1px solid #e5e7eb;position:sticky;left:0;background:white;min-width:90px">${emp.name}<br><span style="font-size:9px;color:#94a3b8">${emp.position_name||''}</span></td>
      ${cells}
      <td style="padding:4px;text-align:center;font-weight:700;font-size:11px;border:1px solid #e5e7eb;background:#f0fdf4">${workCount}</td>
      <td style="padding:4px;text-align:center;font-size:10px;border:1px solid #e5e7eb;background:#fef9c3">${annualCount}일<br><span style="font-size:8px;${remainColor}">잔${remainDisplay}${carriedOver > 0 ? `<span style="color:#d97706;font-size:7px">(+${carriedOver})</span>` : ''}</span></td>
    </tr>`
  }

  const dayHeaders = Array.from({length:days},(_,i)=>{
    const d=i+1, dow=getDayOfWeek(year,month,d)
    return `<th style="padding:3px 1px;text-align:center;min-width:28px;font-size:10px;background:#166534;color:${dow==='일'?'#fca5a5':dow==='토'?'#93c5fd':'white'};border:1px solid #14532d">${d}<br>${dow}</th>`
  }).join('')

  const html = `<!DOCTYPE html><html><head><meta charset="UTF-8">
  <title>${year}년 ${month}월 근무 스케줄</title>
  <style>
    * { margin:0; padding:0; box-sizing:border-box; }
    body { font-family: 'Malgun Gothic', sans-serif; font-size: 11px; }
    @page { size: A4 landscape; margin: 10mm; }
    @media print { body { -webkit-print-color-adjust: exact; print-color-adjust: exact; } }
    table { border-collapse: collapse; width: 100%; }
    h1 { text-align: center; font-size: 14px; margin-bottom: 8px; color: #166534; }
    .legend { display: flex; gap: 8px; flex-wrap: wrap; margin-bottom: 8px; font-size: 9px; }
    .legend-item { padding: 2px 6px; border-radius: 3px; }
  </style>
  </head><body>
  <h1>${year}년 ${month}월 근무 스케줄</h1>
  <div class="legend">
    <span class="legend-item" style="background:#fef9c3;color:#92400e">연 = 연차</span>
    <span class="legend-item" style="background:#fee2e2;color:#b91c1c">휴 = 휴무</span>
    <span class="legend-item" style="background:#ede9fe;color:#6d28d9">오전 = 오전반차</span>
    <span class="legend-item" style="background:#dbeafe;color:#1d4ed8">오후 = 오후반차</span>
    <span class="legend-item" style="background:#fce7f3;color:#9d174d">경조 = 경조사</span>
    <span class="legend-item" style="background:#ecfdf5;color:#065f46">OT = 오버타임</span>
    ${scheduleShifts.map(s=>`<span class="legend-item" style="background:${s.color}33;color:${s.color}">${s.shift_code} = ${s.shift_name}${s.start_time&&s.end_time?` (${s.start_time}~${s.end_time})`:''}</span>`).join('')}
  </div>
  ${buildShiftLegendHtml(scheduleShifts, {forPrint:true})}
  ${buildExtShiftLegendHtml({forPrint:true})}
  <table>
    <thead>
      <tr>
        <th style="padding:4px 8px;text-align:left;background:#166534;color:white;border:1px solid #14532d;min-width:90px">이름/직위</th>
        ${dayHeaders}
        <th style="padding:4px;background:#0f3d25;color:white;border:1px solid #14532d;min-width:35px;font-size:9px">근무</th>
        <th style="padding:4px;background:#0f3d25;color:white;border:1px solid #14532d;min-width:35px;font-size:9px">연차</th>
      </tr>
    </thead>
    <tbody>${tableRows}</tbody>
  </table>
  <p style="text-align:right;font-size:9px;color:#94a3b8;margin-top:4px">출력일: ${new Date().toLocaleDateString('ko-KR')}</p>
  <script>window.onload = function(){ window.print(); }<\/script>
  </body></html>`

  const win = window.open('', '_blank')
  if (win) {
    win.document.write(html)
    win.document.close()
  }
}

// ════════════════════════════════════════════════════════════════
// 엑셀 내보내기
// ════════════════════════════════════════════════════════════════
window.exportScheduleExcel = async () => {
  // XLSX 라이브러리 동적 로드
  if (typeof XLSX === 'undefined') {
    showToast('엑셀 라이브러리 로딩 중... 잠시 후 다시 시도해주세요.', 'warning')
    const s = document.createElement('script')
    s.src = 'https://cdn.jsdelivr.net/npm/xlsx@0.18.5/dist/xlsx.full.min.js'
    document.head.appendChild(s)
    await new Promise(r => { s.onload = r })
  }

  const year     = App.currentYear
  const month    = App.currentMonth
  const days     = getDaysInMonth(year, month)
  const emps     = scheduleEmployees
  const og       = scheduleOffGrants
  const md       = scheduleMonthData
  const schedMap = md?.sched_map || {}
  const leaveMap = md?.leave_map || {}
  const grantedSet = new Set((og?.granted_days    || []).map(d => d.date))
  const subSet     = new Set((og?.substitute_days || []).map(d => d.date))
  const allOffSet  = new Set([...grantedSet, ...subSet])

  const wb = XLSX.utils.book_new()

  // ─── 시트1: 월간 스케줄 ──────────────────────────────────
  const schedData = []

  // 헤더행 1: 날짜
  const hdr1 = ['이름', '직위', '팀']
  for (let d = 1; d <= days; d++) hdr1.push(String(d))
  hdr1.push('근무일', '연차사용', '연차잔여')
  schedData.push(hdr1)

  // 헤더행 2: 요일
  const hdr2 = ['', '', '']
  for (let d = 1; d <= days; d++) hdr2.push(getDayOfWeek(year, month, d))
  hdr2.push('', '', '')
  schedData.push(hdr2)

  // 팀별 직원 행
  const allEmps = [...emps.filter(e=>e.team==='cook'||!e.team), ...emps.filter(e=>e.team==='nutrition')]
  const REST_CODES = new Set([...CALC_ENGINE.REST_CODES_SET, '오전','오후']) // ✅ CALC_ENGINE + 확장

  for (const emp of allEmps) {
    let workCount = 0, annualCount = 0
    const row = [emp.name, emp.position_name || emp.position || '', emp.team === 'nutrition' ? '영양팀' : '조리팀']
    for (let d = 1; d <= days; d++) {
      const ds  = `${year}-${String(month).padStart(2,'0')}-${String(d).padStart(2,'0')}`
      const key = `${emp.id}_${ds}`
      const code = schedMap[key]?.shift_code || ''
      row.push(code || '')
      if (code && code !== '-') {
        if (code === '연') annualCount++
        else if (!REST_CODES.has(code)) workCount++
      }
    }
    const lv = leaveMap[emp.id]
    // ✅ CALC_ENGINE: calcAnnualRemain (이월연차 포함)
    const { effective: annualEffective, used: annualUsed, remain: _annRemainRaw } =
      CALC_ENGINE.calcAnnualRemain(lv)
    const annualRemain = _annRemainRaw !== null ? _annRemainRaw : '-'
    row.push(workCount, annualCount, annualRemain)
    schedData.push(row)
  }

  const ws1 = XLSX.utils.aoa_to_sheet(schedData)

  // 열 너비 설정
  const colWidths = [{ wch: 10 }, { wch: 8 }, { wch: 6 }]
  for (let d = 1; d <= days; d++) colWidths.push({ wch: 4 })
  colWidths.push({ wch: 6 }, { wch: 6 }, { wch: 6 })
  ws1['!cols'] = colWidths

  XLSX.utils.book_append_sheet(wb, ws1, `${month}월 스케줄`)

  // ─── 시트2: 연차 현황 ──────────────────────────────────
  const leaveData = [
    ['이름', '팀', '직위', '입사일', '법정연차(일)', '부여연차(일)', '사용(일)', '잔여(일)', '사용률(%)']
  ]

  function calcLegal(emp) {
    if (!emp.hire_date) return 0
    const hired = new Date(emp.hire_date)
    const now   = new Date(year + '-12-31')
    const yrs   = (now - hired) / (1000*60*60*24*365)
    if (yrs < 0) return 0
    if (yrs < 1) return Math.min(Math.floor((now - hired) / (1000*60*60*24*30)), 11)
    return Math.min(15 + Math.floor((yrs - 1) / 2), 25)
  }

  for (const emp of allEmps) {
    const legal = calcLegal(emp)
    const lv    = leaveMap[emp.id] || {}
    const total  = lv?.annual?.total ?? null
    const used   = lv?.annual?.used  ?? 0
    const carried = lv?.annual?.allowance_paid ? 0 : (lv?.annual?.carried_over_days ?? 0)
    const effective = total !== null ? total + carried : null
    const remain = effective !== null ? effective - used : '-'
    const pct    = effective ? Math.round(used / effective * 100) : 0
    leaveData.push([
      emp.name,
      emp.team === 'nutrition' ? '영양팀' : '조리팀',
      emp.position_name || '',
      emp.hire_date || '',
      legal,
      total !== null ? total : '미부여',
      used,
      remain,
      total ? `${pct}%` : '-'
    ])
  }

  const ws2 = XLSX.utils.aoa_to_sheet(leaveData)
  ws2['!cols'] = [{ wch:10 },{ wch:6 },{ wch:8 },{ wch:12 },{ wch:10 },{ wch:10 },{ wch:8 },{ wch:8 },{ wch:8 }]
  XLSX.utils.book_append_sheet(wb, ws2, '연차현황')

  // ─── 파일 저장 ──────────────────────────────────────────
  const mm = String(month).padStart(2, '0')
  XLSX.writeFile(wb, `근무스케줄_${year}년${mm}월.xlsx`)
  showToast('엑셀 파일이 다운로드됩니다', 'success')
}

