window.switchScheduleTab = async (tab) => {
  scheduleTab = tab
  const content = document.getElementById('pageContent')
  if (!content) return

  // 스피너를 탭 콘텐츠 영역에만 표시
  const tc = document.getElementById('scheduleTabContent')
  if (tc) tc.innerHTML = `<div class="flex items-center justify-center h-40"><div class="loading-spinner"></div></div>`

  try {
    if (tab === 'leaves') {
      // 직원 데이터도 같이 최신화
      const hospQ = (App.role === 'admin' && App.currentHospitalId) ? `&hospitalId=${App.currentHospitalId}` : ''
      const hospQs = (App.role === 'admin' && App.currentHospitalId) ? `?hospitalId=${App.currentHospitalId}` : ''
      const [raw, emps, histSummary] = await Promise.all([
        api('GET', `/api/schedule/leaves/all?year=${App.currentYear}${hospQ}`).catch(() => []),
        api('GET', `/api/schedule/employees${hospQs}`).catch(() => []),
        api('GET', `/api/schedule/leaves/history-summary?year=${App.currentYear}${hospQ}`).catch(() => null)
      ])
      scheduleLeavesData = Array.isArray(raw) ? raw : (raw?.employees ? raw.employees : [])
      if (Array.isArray(emps)) scheduleEmployees = emps
      scheduleLeaveHistorySummary = histSummary
      // 월차 데이터 갱신
      await loadMonthlyLeaveData()

      if (App.role === 'admin' || App.role === 'hospital') {
        const hospQuery = (App.role === 'admin' && App.currentHospitalId) ? `?hospitalId=${App.currentHospitalId}` : ''
        // ── 미발생 월차 소급 자동처리 (조용히) ──────────────
        try {
          const backfillRes = await api('POST', `/api/schedule/monthly-leave/backfill${hospQuery}`, {}).catch(() => null)
          if (backfillRes?.summary?.granted > 0) {
            await loadMonthlyLeaveData()
          }
        } catch(e) {}
        // ── 1년 도달 직원 자동 연차 전환 (조용히) ───────────
        try {
          const transRes = await api('POST', `/api/schedule/monthly-leave/transition${hospQuery}`, {}).catch(() => null)
          if (transRes?.transitioned?.length > 0) {
            const names = transRes.transitioned.map(t => t.name).join(', ')
            showToast(`🎉 ${names} — 1년 근속 달성, 연차 자동 부여 완료`, 'success')
            scheduleLeavesData = await api('GET', `/api/schedule/leaves/all?year=${App.currentYear}`).catch(() => [])
          }
        } catch(e) {}
      }
    } else if (tab === 'analysis') {
      const hq = (App.role === 'admin' && App.currentHospitalId) ? `?hospitalId=${App.currentHospitalId}` : ''
      scheduleAnalysisData = await api('GET', `/api/schedule/analysis/${App.currentYear}/${App.currentMonth}${hq}`).catch(() => null)
    } else if (tab === 'laborCost') {
      const hq = (App.role === 'admin' && App.currentHospitalId) ? `?hospitalId=${App.currentHospitalId}` : ''
      scheduleLaborCostData = await api('GET', `/api/schedule/labor-cost-report/${App.currentYear}/${App.currentMonth}${hq}`).catch(() => null)
    }
  } catch(e) { console.error('탭 데이터 로드 오류:', e) }

  renderScheduleTab(content)
}

// 연차 수정 모달 열기
window.openLeaveEditModal = (empId, empName, totalDays, usedDays, carriedOver = 0, allowancePaid = 0, allowancePaidAt = '') => {
  document.getElementById('leaveEditEmpId').value = empId
  document.getElementById('leaveEditEmpName').textContent = empName
  document.getElementById('leaveEditTotal').value = totalDays || ''
  document.getElementById('leaveEditUsed').value  = usedDays  || 0
  document.getElementById('leaveEditCarriedOver').value = carriedOver || 0
  document.getElementById('leaveEditNote').value  = ''
  // 수당지급 체크박스 초기화
  const chk = document.getElementById('leaveEditAllowancePaid')
  chk.checked = allowancePaid ? true : false
  const dateRow = document.getElementById('leaveEditAllowanceDateRow')
  const dateInput = document.getElementById('leaveEditAllowancePaidAt')
  if (chk.checked) {
    dateRow.classList.remove('hidden')
    dateInput.value = allowancePaidAt || ''
  } else {
    dateRow.classList.add('hidden')
    dateInput.value = ''
  }
  document.getElementById('leaveEditModal').classList.remove('hidden')
}

window.toggleAllowancePaidDate = () => {
  const chk = document.getElementById('leaveEditAllowancePaid')
  const dateRow = document.getElementById('leaveEditAllowanceDateRow')
  const dateInput = document.getElementById('leaveEditAllowancePaidAt')
  if (chk.checked) {
    dateRow.classList.remove('hidden')
    // 오늘 날짜로 기본값 설정
    const today = new Date().toISOString().slice(0, 10)
    if (!dateInput.value) dateInput.value = today
  } else {
    dateRow.classList.add('hidden')
  }
}

window.saveLeaveEdit = async () => {
  const empId    = document.getElementById('leaveEditEmpId').value
  const totalDays= parseFloat(document.getElementById('leaveEditTotal').value)
  const usedDays = parseFloat(document.getElementById('leaveEditUsed').value  || 0)
  const note     = document.getElementById('leaveEditNote').value
  const carriedOverDays = parseFloat(document.getElementById('leaveEditCarriedOver').value || 0)
  const allowancePaid = document.getElementById('leaveEditAllowancePaid').checked
  const allowancePaidAt = allowancePaid ? document.getElementById('leaveEditAllowancePaidAt').value : null
  if (isNaN(totalDays) || totalDays < 0) { showToast('부여 일수를 입력하세요', 'error'); return }
  if (allowancePaid && !allowancePaidAt) { showToast('수당 지급일을 입력하세요', 'error'); return }

  const res = await api('PUT', `/api/schedule/employees/${empId}/leaves`, {
    year: App.currentYear, totalDays, usedDays, note,
    carriedOverDays: allowancePaid ? 0 : carriedOverDays,
    allowancePaid,
    allowancePaidAt
  })
  if (res?.success) {
    showToast(allowancePaid ? '연차수당 지급 처리 완료' : '연차가 저장되었습니다', 'success')
    document.getElementById('leaveEditModal').classList.add('hidden')

    // 관리자 직원관리 페이지에서 열었을 경우 → 직원관리 리로드
    if (window._adminLeaveEditMode) {
      window._adminLeaveEditMode = false
      adminStaffAllData = await api('GET', '/api/schedule/employees').catch(() => [])
      renderAdminStaffContent(document.getElementById('pageContent'))
      return
    }

    // 스케줄 관리 탭에서 열었을 경우 → 최소 리로드 (연차 데이터만 갱신 후 해당 행만 재계산)
    scheduleLeavesData = await api('GET', `/api/schedule/leaves/all?year=${App.currentYear}`).catch(() => [])
    // leave_map도 갱신 (scheduleMonthData 내 캐시 교체)
    if (scheduleMonthData) {
      const freshLeave = await api('GET', `/api/schedule/${App.currentYear}/${App.currentMonth}/leave-map`).catch(() => null)
      if (freshLeave?.leave_map) {
        scheduleMonthData.leave_map = freshLeave.leave_map
      } else {
        // leave_map 전용 API 없을 경우 월간 데이터 전체 갱신 후 해당 행만 재계산
        scheduleMonthData = await api('GET', `/api/schedule/${App.currentYear}/${App.currentMonth}`).catch(() => null)
      }
    }
    // ✅ 성능 최적화: 전체 탭 재렌더 대신 해당 직원 행만 재계산
    schedRecalcRow(parseInt(empId))
    // 연차 탭이 열려 있으면 해당 탭도 갱신
    if (document.getElementById('tab-leaves')?.classList.contains('active')) {
      const content = document.getElementById('pageContent')
      renderScheduleTab(content)
    }
  } else {
    showToast(res?.error || '저장 실패', 'error')
  }
}

// 자동 부여 (단일 직원)
window.autoGrantLeave = async (empId, legalDays) => {
  if (!confirm(`법정 연차 ${legalDays}일을 자동 부여하시겠습니까?`)) return
  const res = await api('PUT', `/api/schedule/employees/${empId}/leaves`, {
    year: App.currentYear, totalDays: legalDays, usedDays: 0, note: '자동부여'
  })
  if (res?.success) {
    showToast('연차가 부여되었습니다', 'success')
    scheduleLeavesData = await api('GET', `/api/schedule/leaves/all?year=${App.currentYear}`).catch(() => [])
    scheduleMonthData  = await api('GET', `/api/schedule/${App.currentYear}/${App.currentMonth}`).catch(() => null)
    const content = document.getElementById('pageContent')
    renderScheduleTab(content)
  }
}

// 미부여 직원 전체 자동 부여
window.autoGrantAllLeaves = async () => {
  const leaves  = scheduleLeavesData
  const leaveByEmp = {}
  for (const l of leaves) leaveByEmp[l.employee_id] = true

  const unassigned = scheduleEmployees.filter(e => !leaveByEmp[e.id] && e.hire_date)
  if (unassigned.length === 0) { showToast('미부여 직원이 없습니다', 'info'); return }
  if (!confirm(`${unassigned.length}명에게 법정 연차를 자동 부여하시겠습니까?`)) return

  let count = 0
  for (const emp of unassigned) {
    const hired = new Date(emp.hire_date)
    const now   = new Date(App.currentYear + '-12-31')
    const years = (now - hired) / (1000*60*60*24*365)
    let legal = 0
    if (years >= 1) {
      legal = Math.min(15 + Math.floor((years-1)/2), 25)
    } else {
      legal = Math.min(Math.floor((now - hired) / (1000*60*60*24*30)), 11)
    }
    if (legal > 0) {
      await api('PUT', `/api/schedule/employees/${emp.id}/leaves`, {
        year: App.currentYear, totalDays: legal, usedDays: 0, note: '자동부여'
      }).catch(()=>null)
      count++
    }
  }
  showToast(`${count}명에게 연차를 부여했습니다`, 'success')
  scheduleLeavesData = await api('GET', `/api/schedule/leaves/all?year=${App.currentYear}`).catch(() => [])
  scheduleMonthData  = await api('GET', `/api/schedule/${App.currentYear}/${App.currentMonth}`).catch(() => null)
  const content = document.getElementById('pageContent')
  renderScheduleTab(content)
}

// ════════════════════════════════════════════════════════════════
// 월차 관리 함수
// ════════════════════════════════════════════════════════════════

// 월차 수정 모달 열기
// 입사일 기준 자동 발생 월차 계산 (프론트엔드 버전)
function calcAutoMonthlyLeave(hireDate, maxDays) {
  if (!hireDate) return { days: 0, detail: '' }
  const hired  = new Date(hireDate)
  const now    = new Date()
  const msPerYear = 365.25 * 24 * 3600 * 1000
  if ((now - hired) >= msPerYear) return { days: 0, detail: '1년 이상 근무 (연차 대상)' }

  // 입사 다음달 ~ 이번달 이전달까지
  let y = hired.getFullYear()
  let m = hired.getMonth() + 2  // 다음달
  if (m > 12) { m = 1; y++ }

  const limitY = now.getFullYear()
  const limitM = now.getMonth() + 1  // 이번달(현재달)도 포함

  let count = 0
  const months = []
  while ((y < limitY || (y === limitY && m <= limitM)) && count < (maxDays || 11)) {
    months.push(`${y}/${m}`)
    count++
    m++; if (m > 12) { m = 1; y++ }
  }
  const detail = count > 0
    ? `입사 다음달(${months[0]})부터 이번달까지 ${count}개월 → ${count}일`
    : '발생 가능한 달 없음'
  return { days: count, detail }
}

window.mlEditUpdateRemain = () => {
  const total  = parseFloat(document.getElementById('mlEditTotal')?.value) || 0
  const used   = parseFloat(document.getElementById('mlEditUsed')?.value)  || 0
  const remain = Math.max(0, total - used)
  const el = document.getElementById('mlEditRemain')
  if (el) {
    el.textContent = `${remain}일`
    el.className = `text-xl font-bold ${remain <= 0 ? 'text-red-500' : remain <= 2 ? 'text-yellow-600' : 'text-teal-700'}`
  }
}

window.openMonthlyLeaveEditModal = async (empId, empName) => {
  document.getElementById('mlEditEmpId').value = empId
  document.getElementById('mlEditEmpName').textContent = empName
  document.getElementById('mlEditReason').value = ''

  // 직원 정보 + 현재 월차 데이터 로드
  const hospQuery = App.role === 'admin' && App.currentHospitalId ? `&hospitalId=${App.currentHospitalId}` : ''
  const hospQueryQ = App.role === 'admin' && App.currentHospitalId ? `?hospitalId=${App.currentHospitalId}` : ''

  // 현재 저장된 월차 값 (summary에서)
  const mlData = (window._monthlyLeavesData || []).find(d => d.employee_id === empId)
  const currentTotal = mlData?.monthly_total ?? null
  const currentUsed  = mlData?.monthly_used  ?? 0

  // 직원 입사일 가져오기
  const emp = (Array.isArray(scheduleEmployees) ? scheduleEmployees : []).find(e => e.id === empId)
  const hireDate = emp?.hire_date || ''
  const maxDays  = parseInt(scheduleWorkSettings?.monthly_leave_max_days || '11')

  // 자동 계산값
  const autoCalc = calcAutoMonthlyLeave(hireDate, maxDays)

  // 발생일수: 이미 저장된 값 있으면 그 값, 없으면 자동계산값
  const totalToShow = currentTotal !== null ? currentTotal : autoCalc.days
  document.getElementById('mlEditTotal').value = totalToShow
  document.getElementById('mlEditUsed').value  = currentUsed

  // 자동계산 표시
  document.getElementById('mlEditAutoCalc').textContent = `${autoCalc.days}일`
  document.getElementById('mlEditCalcDetail').textContent = autoCalc.detail

  mlEditUpdateRemain()

  // 발생 이력 로드
  const grants = await api('GET', `/api/schedule/monthly-leave/grants?year=${App.currentYear}&employeeId=${empId}${hospQuery}`).catch(() => [])
  const histEl   = document.getElementById('mlEditGrantHistory')
  const histList = document.getElementById('mlEditGrantHistoryList')
  if (grants && grants.length > 0) {
    histList.innerHTML = grants.map((g) => {
      const typeLabel = g.grant_type === 'auto' ? '자동' : g.grant_type === 'initial_setup' ? '초기셋업' : g.grant_type === 'auto_backfill' ? '소급' : '수동'
      return `<div class="flex items-center justify-between p-1.5 rounded bg-teal-50 border border-teal-100">
        <span class="text-teal-700">${g.target_year}년 ${g.target_month || '-'}월 → <strong>${g.days_granted}일</strong></span>
        <span class="text-gray-400">${typeLabel} · ${(g.created_at||'').substring(0,10)}</span>
      </div>`
    }).join('')
    histEl.classList.remove('hidden')
  } else {
    histEl.classList.add('hidden')
  }

  document.getElementById('monthlyLeaveEditModal').classList.remove('hidden')
}

// 월차 수정 저장
window.saveMonthlyLeaveEdit = async () => {
  const empId    = parseInt(document.getElementById('mlEditEmpId').value)
  const totalDays= parseFloat(document.getElementById('mlEditTotal').value) || 0
  const usedDays = parseFloat(document.getElementById('mlEditUsed').value)  || 0
  const reason   = document.getElementById('mlEditReason').value.trim() || '수동 설정'

  if (usedDays > totalDays) { showToast('사용일수가 발생일수보다 클 수 없습니다', 'error'); return }

  const hospQuery = App.role === 'admin' && App.currentHospitalId ? `?hospitalId=${App.currentHospitalId}` : ''
  const res = await api('POST', `/api/schedule/monthly-leave/adjust${hospQuery}`, {
    employeeId: empId, year: App.currentYear, totalDays, usedDays, reason
  }).catch(() => null)

  if (res?.ok) {
    showToast(`월차 설정 완료 — 발생 ${totalDays}일 / 사용 ${usedDays}일 / 잔여 ${totalDays - usedDays}일`, 'success')
    document.getElementById('monthlyLeaveEditModal').classList.add('hidden')
    await loadMonthlyLeaveData()
    // ✅ 성능 최적화: 전체 탭 재렌더 대신 해당 직원 행만 재계산
    schedRecalcRow(empId)
  } else {
    showToast('저장 실패', 'error')
  }
}

// 월차 발생 처리 (이번달/선택달)
window.runMonthlyLeaveGenerate = async () => {
  const now   = new Date()
  // 현재 달도 포함하여 선택 가능
  const curMonth = now.getMonth() + 1
  const curYear  = now.getFullYear()
  const prevMonth = now.getMonth() === 0 ? 12 : now.getMonth()
  const prevYear  = now.getMonth() === 0 ? now.getFullYear() - 1 : now.getFullYear()

  // 간단한 월/년 선택 다이얼로그
  const input = prompt(
    `발생 처리할 연월을 입력하세요 (예: ${prevYear}-${String(prevMonth).padStart(2,'0')})\n비워두면 이전 달(${prevYear}년 ${prevMonth}월) 처리`,
    `${prevYear}-${String(prevMonth).padStart(2,'0')}`
  )
  if (input === null) return // 취소

  let year = prevYear, month = prevMonth
  if (input && input.trim()) {
    const parts = input.trim().split('-')
    if (parts.length === 2) {
      year  = parseInt(parts[0])
      month = parseInt(parts[1])
    }
  }
  if (isNaN(year) || isNaN(month) || month < 1 || month > 12) {
    showToast('올바른 연월을 입력하세요 (예: 2025-03)', 'error')
    return
  }

  if (!confirm(`${year}년 ${month}월 개근 확인 후 월차를 발생하시겠습니까?\n(스케줄 미입력 직원도 개근으로 간주합니다)`)) return

  const hospQuery = App.role === 'admin' && App.currentHospitalId ? `?hospitalId=${App.currentHospitalId}` : ''
  const res = await api('POST', `/api/schedule/monthly-leave/generate${hospQuery}`, { year, month }).catch(() => null)
  if (!res) { showToast('오류 발생', 'error'); return }
  if (res.skipped) { showToast(res.reason || '월차 기능 비활성화', 'info'); return }

  const granted   = (res.results || []).filter((r) => r.status === 'granted').length
  const qualified = (res.results || []).filter((r) => r.status === 'not_qualified').length
  const existing  = (res.results || []).filter((r) => r.status === 'already_exists').length
  const maxed     = (res.results || []).filter((r) => r.status === 'max_reached').length
  showToast(`${year}년 ${month}월 월차 발생: ${granted}명 발생, ${qualified}명 미개근, ${existing}명 이미처리, ${maxed}명 한도초과`, granted > 0 ? 'success' : 'info')

  await loadMonthlyLeaveData()
  const content = document.getElementById('pageContent')
  renderScheduleTab(content)
}

// 전체 월차 자동발생 (입사 다음달부터 이번달까지 미발생 월차 일괄 처리)
window.runMonthlyLeaveBackfill = async () => {
  if (!confirm('1년 미만 재직 직원의 월차를 자동 발생하시겠습니까?\n\n' +
    '• 입사 다음달부터 이번달까지 미발생 월차를 한번에 처리합니다\n' +
    '• 스케줄(근무기록) 없어도 자동으로 발생됩니다\n' +
    '• 이미 발생된 달은 건너뜁니다\n' +
    '• 발생 후 수정 버튼으로 실제 사용일수를 입력하세요')) return

  showToast('월차 자동발생 처리 중...', 'info')
  const hospQuery = App.role === 'admin' && App.currentHospitalId ? `?hospitalId=${App.currentHospitalId}` : ''
  const res = await api('POST', `/api/schedule/monthly-leave/backfill${hospQuery}`, {}).catch(() => null)
  if (!res) { showToast('오류 발생', 'error'); return }

  const granted = res.summary?.granted ?? (res.results || []).filter((r) => r.status === 'granted').length
  const already = res.summary?.already_exists ?? (res.results || []).filter((r) => r.status === 'already_exists').length
  const maxed   = res.summary?.max_reached ?? (res.results || []).filter((r) => r.status === 'max_reached').length

  if (granted === 0 && already === 0 && maxed === 0) {
    showToast('처리 대상 직원이 없습니다 (1년 미만 재직자 없음)', 'info')
  } else if (granted === 0 && already > 0) {
    showToast(`이미 모두 발생 완료 (${already}건 기존 발생)`, 'info')
  } else if (granted > 0) {
    let msg = `✅ 월차 발생 완료: ${granted}일 발생`
    if (already > 0) msg += ` (기존 ${already}건 제외)`
    if (maxed > 0) msg += ` (한도초과 ${maxed}건 제외)`
    showToast(msg, 'success')
  } else {
    showToast(`처리 완료 — 발생 ${granted}건, 한도초과 ${maxed}건`, 'info')
  }

  await loadMonthlyLeaveData()
  const content = document.getElementById('pageContent')
  renderScheduleTab(content)
}

// 연차 전환 처리
window.runMonthlyLeaveTransition = async () => {
  if (!confirm('1년 만료 직원을 연차로 전환하시겠습니까?')) return
  const hospQuery = App.role === 'admin' && App.currentHospitalId ? `?hospitalId=${App.currentHospitalId}` : ''
  const res = await api('POST', `/api/schedule/monthly-leave/transition${hospQuery}`, {}).catch(() => null)
  if (!res) { showToast('오류 발생', 'error'); return }
  const count = (res.transitioned || []).length
  showToast(count > 0 ? `${count}명 연차 전환 완료` : '전환 대상 없음', 'success')
  if (count > 0) {
    scheduleLeavesData = await api('GET', `/api/schedule/leaves/all?year=${App.currentYear}`).catch(() => [])
    await loadMonthlyLeaveData()
    const content = document.getElementById('pageContent')
    renderScheduleTab(content)
  }
}

// 연차 탭 - 수동으로 1년 도달 직원 연차 전환 실행
window.runAnnualLeaveTransition = async () => {
  const hospQuery = (App.role === 'admin' && App.currentHospitalId) ? `?hospitalId=${App.currentHospitalId}` : ''
  showToast('전환 처리 중...', 'info')
  const res = await api('POST', `/api/schedule/monthly-leave/transition${hospQuery}`, {}).catch(() => null)
  if (!res) { showToast('오류 발생', 'error'); return }
  const transitioned = res.transitioned || []
  if (transitioned.length === 0) {
    showToast('현재 연차 전환 대상이 없습니다 (1년 도달 직원 없음)', 'info')
    return
  }
  const names = transitioned.map(t => `${t.name}(${t.legalDays}일)`).join(', ')
  showToast(`✅ ${transitioned.length}명 연차 자동 부여 완료: ${names}`, 'success')
  scheduleLeavesData = await api('GET', `/api/schedule/leaves/all?year=${App.currentYear}`).catch(() => [])
  await loadMonthlyLeaveData()
  const content = document.getElementById('pageContent')
  renderScheduleTab(content)
}

// 직원 1명 월차 발생
window.generateMonthlyLeaveForEmp = async (empId) => {
  const now   = new Date()
  const month = now.getMonth() === 0 ? 12 : now.getMonth()
  const year  = now.getMonth() === 0 ? now.getFullYear() - 1 : now.getFullYear()
  const hospQuery = App.role === 'admin' && App.currentHospitalId ? `?hospitalId=${App.currentHospitalId}` : ''
  const res = await api('POST', `/api/schedule/monthly-leave/generate${hospQuery}`, { year, month, employeeId: empId }).catch(() => null)
  if (!res) { showToast('오류 발생', 'error'); return }
  const r = (res.results || [])[0]
  if (!r) { showToast('처리 결과 없음', 'info'); return }
  const msgs = {
    granted: '월차 1일 발생',
    not_qualified: '개근 미충족',
    already_exists: '이미 처리됨',
    max_reached: '최대 한도 초과'
  }
  showToast(msgs[r.status] || r.status, r.status === 'granted' ? 'success' : 'info')
  if (r.status === 'granted') {
    await loadMonthlyLeaveData()
    const content = document.getElementById('pageContent')
    renderScheduleTab(content)
  }
}

// 월차 데이터 로드 (글로벌 캐시)
async function loadMonthlyLeaveData() {
  const hospQuery = App.role === 'admin' && App.currentHospitalId ? `&hospitalId=${App.currentHospitalId}` : ''
  const hospQueryQ = App.role === 'admin' && App.currentHospitalId ? `?hospitalId=${App.currentHospitalId}` : ''
  try {
    window._monthlyLeavesData = await api('GET', `/api/schedule/monthly-leave/summary?year=${App.currentYear}${hospQuery}`)
  } catch (e) {
    window._monthlyLeavesData = []
  }
}

