window.reuseExternalWorker = async (workerId) => {
  // 이미 활성 상태면 그냥 모달 닫고 스케줄 새로고침
  document.getElementById('addExtWorkerModal')?.remove()
  showToast('외부인력을 불러왔습니다. 셀을 클릭해서 근무일을 입력하세요.', 'info')
}

window.saveExternalWorker = async () => {
  const workerType = document.getElementById('ew_type')?.value || 'dispatch'
  const name = document.getElementById('ew_name')?.value?.trim() || ''
  const memo = document.getElementById('ew_memo')?.value?.trim() || ''
  
  if (!name) {
    showToast('이름을 입력해주세요', 'error')
    document.getElementById('ew_name')?.focus()
    return
  }
  
  try {
    const hospitalId = App.role === 'admin' ? (App.adminHospitalId || null) : null
    const res = await api('POST', '/api/schedule/external-workers', { workerType, name, memo, ...(hospitalId ? {hospitalId} : {}) })
    if (res?.id) {
      showToast(`${workerType === 'dispatch' ? '파출' : '알바'} ${name} 추가 완료`, 'success')
      document.getElementById('addExtWorkerModal')?.remove()
      // 스케줄 데이터 새로고침
      const monthData = await api('GET', `/api/schedule/${App.currentYear}/${App.currentMonth}`).catch(() => null)
      if (monthData) {
        scheduleMonthData = monthData
        scheduleExternalWorkers = monthData.external_workers || []
        scheduleExtSchedMap = monthData.ext_sched_map || {}
      }
      const tc = document.getElementById('scheduleTabContent')
      if (tc && scheduleTab === 'schedule') {
        tc.innerHTML = renderMonthlyScheduleTab()
        setTimeout(initExtWorkerEvents, 0)
      }
    } else {
      showToast(res?.error || '추가 실패', 'error')
    }
  } catch(e) {
    showToast('오류가 발생했습니다', 'error')
  }
}

// ── 외부인력 셀 클릭 (근무유형 순환) ─────────────────────────
// ── 외부인력 이벤트 위임 초기화 ─────────────────────────────
function initExtWorkerEvents() {
  const tc = document.getElementById('scheduleTabContent')
  if (!tc) return

  // 이전 리스너 제거 후 재등록 (중복 방지)
  if (tc._extEvtBound) {
    tc.removeEventListener('click',       tc._extEvtHandler)
    tc.removeEventListener('dblclick',    tc._extDblHandler)
    tc.removeEventListener('mousedown',   tc._extMdHandler)
    tc.removeEventListener('mousemove',   tc._extMmHandler)
    tc.removeEventListener('mouseup',     tc._extMuHandler)
    if (tc._extCtxHandler) tc.removeEventListener('contextmenu', tc._extCtxHandler)
  }

  tc._extEvtHandler = function(e) {
    // 파출/알바 추가 버튼
    const addBtn = e.target.closest('.ext-add-btn')
    if (addBtn) {
      e.preventDefault(); e.stopPropagation()
      openAddExternalWorkerModal(addBtn.dataset.stype || 'dispatch')
      return
    }
    // 외부인력 삭제 버튼
    const delBtn = e.target.closest('.ext-del-btn')
    if (delBtn) {
      e.preventDefault(); e.stopPropagation()
      const wid = parseInt(delBtn.dataset.wid)
      if (wid) deleteExternalWorker(wid, delBtn.dataset.wname || '')
      return
    }
    // inline select 드롭다운 클릭이면 무시 (select 자체가 처리)
    if (e.target.closest('.ext-inline-select')) return
    // 외부인력 셀 클릭 (단독 클릭 = 선택만)
    const cell = e.target.closest('.ext-cell')
    if (cell) {
      if (!(App.role === 'admin' || App.role === 'hospital')) return
      // 드래그 중에는 click 무시 (드래그가 이미 선택 처리함)
      if (_extIsDragging) return
      _extHandleCellClick(e, cell)
      return
    }
    // 셀 바깥 클릭 → 선택 해제
    if (!e.target.closest('#multiSelectBar') && !e.target.closest('.ext-cell')) {
      _extClearSelection()
    }
  }

  // 더블클릭 → 드롭다운 입력
  if (tc._extDblHandler) tc.removeEventListener('dblclick', tc._extDblHandler)
  tc._extDblHandler = function(e) {
    const cell = e.target.closest('.ext-cell')
    if (!cell) return
    if (!(App.role === 'admin' || App.role === 'hospital')) return
    e.preventDefault(); e.stopPropagation()
    // 재클릭 타이머 취소 (더블클릭은 이 핸들러에서 처리)
    if (typeof _extClickTimer !== 'undefined' && _extClickTimer) {
      clearTimeout(_extClickTimer); _extClickTimer = null
    }
    const wid  = parseInt(cell.dataset.extid)
    const date = cell.dataset.date
    // 선택 상태 맞추기
    const key = _extCellKey(cell)
    _extSelectedCells.clear()
    _extSelectedCells.add(key)
    _extAnchorKey = key
    _extUpdateSelectStyle()
    _extOpenInlineInput(wid, date, cell, null)
  }
  // (dblclick 핸들러는 아래에서 한 번만 등록)

  // 마우스다운: 드래그 시작
  tc._extMdHandler = function(e) {
    if (e.button !== 0) return
    const cell = e.target.closest('.ext-cell')
    if (!cell) return
    if (!(App.role === 'admin' || App.role === 'hospital')) return
    // fill handle 드래그
    if (e.target.classList.contains('ext-fill-handle')) {
      e.preventDefault(); e.stopPropagation()
      _extFillDragStart(cell)
      return
    }
    // inline select 클릭이면 무시
    if (e.target.closest('.ext-inline-select')) return
    // 일반 드래그 시작 (e.preventDefault 제거 - click 이벤트 살리기)
    _extDragStart(cell, e)
  }

  tc._extMmHandler = function(e) {
    const cell = e.target.closest('.ext-cell')
    if (!cell) return
    if (_extIsFillDrag) { _extFillDragMove(cell); return }
    if (_extIsDragging)  { _extDragMove(cell) }
  }

  tc._extMuHandler = function(e) {
    if (_extIsFillDrag) { _extFillDragEnd(); return }
    if (_extIsDragging) { _extDragEnd() }
  }

  // contextmenu: 외부인력 셀 우클릭 → 인라인 입력 열기 (드롭다운 선택)
  if (tc._extCtxHandler) tc.removeEventListener('contextmenu', tc._extCtxHandler)
  tc._extCtxHandler = function(e) {
    const cell = e.target.closest('.ext-cell')
    if (!cell) return
    e.preventDefault(); e.stopPropagation()
    if (!(App.role === 'admin' || App.role === 'hospital')) return
    const wid  = parseInt(cell.dataset.extid)
    const date = cell.dataset.date
    const key  = _extCellKey(cell)
    _extSelectedCells.clear()
    _extSelectedCells.add(key)
    _extAnchorKey = key
    _extUpdateSelectStyle()
    _extOpenInlineInput(wid, date, cell, null)
  }

  tc.addEventListener('click',       tc._extEvtHandler)
  tc.addEventListener('dblclick',    tc._extDblHandler)  // 한 번만 등록
  tc.addEventListener('mousedown',   tc._extMdHandler)
  tc.addEventListener('mousemove',   tc._extMmHandler)
  tc.addEventListener('mouseup',     tc._extMuHandler)
  tc.addEventListener('contextmenu', tc._extCtxHandler)
  tc._extEvtBound = true
}

// ══════════════════════════════════════════════════════════════
//  외부인력(파출/알바) 엑셀 기능 구현
// ══════════════════════════════════════════════════════════════

// 외부인력 EXT_SHIFT 설정 (로컬스토리지에서 커스터마이즈 가능)
const EXT_SHIFT_SEQUENCE_DEFAULT = ['morning', 'afternoon', 'full_9h', 'full_12h', '']
let _extShiftSequence = null  // null이면 DEFAULT 사용
const EXT_SHIFT_COLORS = {
  morning:  'background:#fff7ed;color:#c2410c',
  afternoon:'background:#fef3c7;color:#b45309',
  full_9h:  'background:#ffedd5;color:#ea580c',
  full_12h: 'background:#fee2e2;color:#dc2626',
  '':       'background:#f9fafb;color:#d1d5db'
}
const EXT_SHIFT_LABEL_MAP = { morning:'오전', afternoon:'오후', full_9h:'9H', full_12h:'12H', '':'·' }
// 활성화된 EXT_SHIFT 순환 목록 (비활성 항목 제외)
function getExtShiftSeq() {
  const stored = localStorage.getItem('extShiftConfig')
  if (stored) {
    try {
      const cfg = JSON.parse(stored)
      const active = cfg.filter(s => s.enabled !== false).map(s => s.key)
      if (active.length > 0) return [...active, '']
    } catch(e) {}
  }
  return EXT_SHIFT_SEQUENCE_DEFAULT
}

// ── 선택 상태 변수 ────────────────────────────────────────────
let _extSelectedCells = new Set()   // 'workerId_date' 키
let _extAnchorKey     = null
let _extIsDragging    = false
let _extDragStartKey  = null
let _extIsFillDrag    = false
let _extFillSrcKey    = null
let _extCopiedData    = null        // { entries: [{workerId, date, shiftType}] }
const EXT_UNDO_LIMIT  = 50
window._extUndoStack  = []
window._extRedoStack  = []

// ── 셀 키 파싱 ────────────────────────────────────────────────
function _extParseKey(key) {
  const parts = key.split('_')
  return { workerId: parseInt(parts[0]), date: parts.slice(1).join('_') }
}
function _extCellKey(cell) {
  return `${cell.dataset.extid}_${cell.dataset.date}`
}
function _extGetCell(workerId, date) {
  return document.querySelector(`.ext-cell[data-extid="${workerId}"][data-date="${date}"]`)
}

// ── DOM 즉시 반영 ─────────────────────────────────────────────
function _extApplyDOM(workerId, date, cell, shiftType) {
  if (!cell) cell = _extGetCell(workerId, date)
  if (!cell) return
  const key = `${workerId}_${date}`
  const isEmpty = !shiftType
  cell.dataset.extshift = shiftType || ''
  const span = cell.querySelector('span')
  if (span) {
    span.style.cssText = `display:inline-flex;align-items:center;justify-content:center;width:26px;height:26px;border-radius:4px;font-size:10px;font-weight:700;${EXT_SHIFT_COLORS[shiftType]||EXT_SHIFT_COLORS['']}`
    span.textContent = EXT_SHIFT_LABEL_MAP[shiftType] || '·'
  }
  // 인메모리 업데이트
  if (!scheduleExtSchedMap) scheduleExtSchedMap = {}
  if (isEmpty) delete scheduleExtSchedMap[key]
  else scheduleExtSchedMap[key] = { ...(scheduleExtSchedMap[key]||{}), worker_id: workerId, work_date: date, shift_type: shiftType }
  // 해당 행 근무일 수 재계산
  _extRecalcRow(workerId)
}

// ── debounce 배치 저장 ────────────────────────────────────────
let _extSaveTimer = null
const _extSaveQueue = {}  // 'workerId_date' → shiftType
function _extQueueSave(workerId, date, shiftType) {
  _extSaveQueue[`${workerId}_${date}`] = { workerId, date, shiftType }
  clearTimeout(_extSaveTimer)
  _extSaveTimer = setTimeout(async () => {
    const entries = Object.values(_extSaveQueue)
    for (const k in _extSaveQueue) delete _extSaveQueue[k]
    if (entries.length === 0) return
    try {
      await api('POST', '/api/schedule/external-schedules/save-batch', {
        items: entries.map(e => ({ workerId: e.workerId, workDate: e.date, shiftType: e.shiftType || '' }))
      })
    } catch(err) { console.error('ext save error:', err) }
  }, 400)
}

// ── 적용 (DOM + 인메모리 + 저장 큐) ──────────────────────────
function _extApplyOne(workerId, date, cell, shiftType) {
  _extApplyDOM(workerId, date, cell, shiftType)
  _extQueueSave(workerId, date, shiftType)
}

// ── 배치 적용 ─────────────────────────────────────────────────
function _extApplyBatch(items) {
  const undoItems = [], affected = new Set()
  for (const { workerId, date, shiftType } of items) {
    const cell = _extGetCell(workerId, date)
    if (!cell) continue
    undoItems.push({ workerId, date, oldType: cell.dataset.extshift || '', newType: shiftType })
    _extApplyDOM(workerId, date, cell, shiftType)
    _extQueueSave(workerId, date, shiftType)
    affected.add(workerId)
  }
  affected.forEach(id => _extRecalcRow(id))
  _extPushUndo(undoItems)
  // 복사 아웃라인 유지 포함 선택 스타일 갱신
  _extUpdateSelectStyle()
}

// ── Undo/Redo ─────────────────────────────────────────────────
function _extPushUndo(items) {
  window._extUndoStack.push({ items, ts: Date.now() })
  if (window._extUndoStack.length > EXT_UNDO_LIMIT) window._extUndoStack.shift()
  window._extRedoStack = []
  _extSyncUndoBtns()
}
function _extSyncUndoBtns() {
  // 외부인력은 직원 공용 undo 버튼 대신 별도 버튼 없음 → 그냥 유지
}

window.extUndo = () => {
  if (!window._extUndoStack.length) { showToast('취소할 작업이 없습니다','info'); return }
  const batch = window._extUndoStack.pop()
  window._extRedoStack.push({ items: batch.items.map(i=>({...i, oldType:i.newType, newType:i.oldType})), ts: Date.now() })
  const affected = new Set()
  batch.items.forEach(({ workerId, date, oldType }) => {
    _extApplyDOM(workerId, date, null, oldType)
    _extQueueSave(workerId, date, oldType)
    affected.add(workerId)
  })
  affected.forEach(id => _extRecalcRow(id))
  showToast(`↩ ${batch.items.length}개 셀 실행취소 (파출/알바)`, 'info')
  _extSyncUndoBtns()
}

window.extRedo = () => {
  if (!window._extRedoStack.length) { showToast('다시실행할 작업이 없습니다','info'); return }
  const batch = window._extRedoStack.pop()
  window._extUndoStack.push({ items: batch.items.map(i=>({...i, oldType:i.newType, newType:i.oldType})), ts: Date.now() })
  const affected = new Set()
  batch.items.forEach(({ workerId, date, newType }) => {
    _extApplyDOM(workerId, date, null, newType)
    _extQueueSave(workerId, date, newType)
    affected.add(workerId)
  })
  affected.forEach(id => _extRecalcRow(id))
  showToast(`↪ ${batch.items.length}개 셀 다시실행 (파출/알바)`, 'info')
  _extSyncUndoBtns()
}

// ── 근무일 수 재계산 ─────────────────────────────────────────
function _extRecalcRow(workerId) {
  const days = getDaysInMonth(App.currentYear, App.currentMonth)
  let cnt = 0
  for (let d = 1; d <= days; d++) {
    const ds = `${App.currentYear}-${String(App.currentMonth).padStart(2,'0')}-${String(d).padStart(2,'0')}`
    if (scheduleExtSchedMap?.[`${workerId}_${ds}`]?.shift_type) cnt++
  }
  // 행 찾기
  const anyCell = document.querySelector(`.ext-cell[data-extid="${workerId}"]`)
  if (!anyCell) return
  const row = anyCell.closest('tr')
  if (!row) return
  const tds = row.querySelectorAll('td')
  if (tds && tds.length >= 2) {
    tds[1].textContent = cnt + '일'
    tds[1].style.cssText = 'text-align:center;font-size:10px;font-weight:600;color:#6b7280;padding:2px'
  }
}

// ── 선택 스타일 ───────────────────────────────────────────────
function _extUpdateSelectStyle() {
  // 복사된 셀 키 집합 (아웃라인 유지용)
  const copiedKeys = new Set(
    (_extCopiedData?.entries || []).map(e => `${e.workerId}_${e.date}`)
  )
  document.querySelectorAll('.ext-cell').forEach(c => {
    const k = _extCellKey(c)
    if (_extSelectedCells.has(k)) {
      c.style.outline = '2px solid #3b82f6'
      c.style.outlineOffset = '-2px'
      c.style.zIndex = '3'
    } else if (copiedKeys.has(k)) {
      // 복사된 셀: 점선 아웃라인 유지
      c.style.outline = '2px dashed #f97316'
      c.style.outlineOffset = '-2px'
      c.style.zIndex = '2'
    } else {
      c.style.outline = ''
      c.style.outlineOffset = ''
      c.style.zIndex = ''
      c.classList.remove('ext-cell-fill-preview')
    }
  })
  _extUpdateBar()
}

function _extClearSelection() {
  _extSelectedCells.clear()
  _extAnchorKey = null
  _extUpdateSelectStyle()
  // fill handle 제거
  document.querySelectorAll('.ext-fill-handle').forEach(h => h.remove())
  _extHideBar()
}

// ── 셀 클릭 처리 ─────────────────────────────────────────────
let _extClickTimer = null  // 재클릭 드롭다운 지연 타이머
function _extHandleCellClick(e, cell) {
  const key = _extCellKey(cell)
  const wid  = parseInt(cell.dataset.extid)
  const date = cell.dataset.date

  // mousedown에서 시작된 드래그 변수 초기화 (단순 클릭이었으므로)
  _extDragStartKey = null

  // 직원 셀 선택 해제
  if (_selectedCells.size > 0) clearMultiSelection()

  if (e.ctrlKey || e.metaKey) {
    // Ctrl+클릭: 토글 추가
    if (_extClickTimer) { clearTimeout(_extClickTimer); _extClickTimer = null }
    if (_extSelectedCells.has(key)) _extSelectedCells.delete(key)
    else _extSelectedCells.add(key)
    _extAnchorKey = key
  } else if (e.shiftKey && _extAnchorKey) {
    // Shift+클릭: 범위 선택
    if (_extClickTimer) { clearTimeout(_extClickTimer); _extClickTimer = null }
    _extSelectRange(_extAnchorKey, key)
  } else if (_extSelectedCells.has(key) && _extSelectedCells.size === 1) {
    // 이미 선택된 단일 셀 재클릭 → 지연 후 드롭다운 열기 (더블클릭이면 취소됨)
    if (_extClickTimer) clearTimeout(_extClickTimer)
    _extClickTimer = setTimeout(() => {
      _extClickTimer = null
      // 아직 드롭다운이 없는 경우만 열기
      if (!cell.querySelector('.ext-inline-select')) {
        _extOpenInlineInput(wid, date, cell, null)
      }
    }, 260)
    return  // 선택 스타일 이미 유지됨
  } else {
    // 단독 클릭 → 선택
    if (_extClickTimer) { clearTimeout(_extClickTimer); _extClickTimer = null }
    _extSelectedCells.clear()
    _extSelectedCells.add(key)
    _extAnchorKey = key
  }
  _extUpdateSelectStyle()
  _extShowFillHandle()
  _extUpdateBar()
}

// ── 범위 선택 ─────────────────────────────────────────────────
function _extSelectRange(fromKey, toKey) {
  const { workerId: wid1, date: d1 } = _extParseKey(fromKey)
  const { workerId: wid2, date: d2 } = _extParseKey(toKey)
  _extSelectedCells.clear()
  // 모든 ext-cell 순회하며 날짜 범위에 해당하는 항목 선택 (같은 worker or 전체)
  const minDate = d1 < d2 ? d1 : d2
  const maxDate = d1 < d2 ? d2 : d1
  document.querySelectorAll('.ext-cell').forEach(c => {
    if (c.dataset.date >= minDate && c.dataset.date <= maxDate) {
      _extSelectedCells.add(_extCellKey(c))
    }
  })
}

// ── fill handle 표시 ──────────────────────────────────────────
function _extShowFillHandle() {
  document.querySelectorAll('.ext-fill-handle').forEach(h => h.remove())
  if (_extSelectedCells.size === 0) return
  const keys = Array.from(_extSelectedCells).sort()
  const lastKey = keys[keys.length - 1]
  const { workerId, date } = _extParseKey(lastKey)
  const cell = _extGetCell(workerId, date)
  if (!cell) return
  const handle = document.createElement('div')
  handle.className = 'ext-fill-handle'
  handle.style.cssText = 'position:absolute;bottom:1px;right:1px;width:8px;height:8px;background:#3b82f6;cursor:crosshair;z-index:10;border-radius:1px'
  cell.style.position = 'relative'
  cell.appendChild(handle)
}

// ── 드래그 선택 ───────────────────────────────────────────────
function _extDragStart(cell, e) {
  if (e.ctrlKey || e.metaKey || e.shiftKey) return
  _extIsDragging = false  // mouseMove 발생 후에야 true로 변경
  _extDragStartKey = _extCellKey(cell)
  // mousedown에서 선택은 하지 않음 — click에서 처리
  // (drag가 실제로 일어나면 _extDragMove에서 선택 처리)
}
function _extDragMove(cell) {
  if (!_extDragStartKey) return
  const key = _extCellKey(cell)
  if (key === _extDragStartKey && !_extIsDragging) return  // 같은 셀에서는 drag 미시작
  // 실제로 다른 셀로 이동 → 드래그 모드 시작
  if (!_extIsDragging) {
    _extIsDragging = true
    // 드래그 시작 셀 선택
    _extSelectedCells.clear()
    _extSelectedCells.add(_extDragStartKey)
    _extAnchorKey = _extDragStartKey
  }
  _extSelectRange(_extDragStartKey, key)
  _extUpdateSelectStyle()
}
function _extDragEnd() {
  const wasDragging = _extIsDragging
  _extIsDragging = false
  _extDragStartKey = null
  // 실제 드래그가 일어난 경우에만 툴바 업데이트
  if (wasDragging) {
    _extShowFillHandle()
    _extUpdateBar()
  }
}

// ── Fill 드래그 ───────────────────────────────────────────────
function _extFillDragStart(srcCell) {
  _extIsFillDrag = true
  _extFillSrcKey = _extCellKey(srcCell)
  document.querySelectorAll('.ext-cell').forEach(c => c.classList.remove('ext-cell-fill-preview'))
}
function _extFillDragMove(cell) {
  if (!_extIsFillDrag) return
  const { workerId: srcWid, date: srcDate } = _extParseKey(_extFillSrcKey)
  const targetWid = parseInt(cell.dataset.extid)
  if (targetWid !== srcWid) return  // 같은 행만 드래그 Fill
  const targetDate = cell.dataset.date

  // 선택된 셀들의 날짜 범위와 srcDate 기준으로 Preview
  const srcDates = Array.from(_extSelectedCells)
    .filter(k => _extParseKey(k).workerId === srcWid)
    .map(k => _extParseKey(k).date).sort()

  const fillStart = srcDates[0] || srcDate
  const fillEnd   = targetDate >= srcDate ? targetDate : srcDate

  document.querySelectorAll(`.ext-cell[data-extid="${srcWid}"]`).forEach(c => {
    if (c.dataset.date >= fillStart && c.dataset.date <= fillEnd) {
      c.classList.add('ext-cell-fill-preview')
    } else {
      c.classList.remove('ext-cell-fill-preview')
    }
  })
}
function _extFillDragEnd() {
  _extIsFillDrag = false
  if (!_extFillSrcKey) return
  const { workerId: srcWid } = _extParseKey(_extFillSrcKey)

  // 소스 코드 가져오기 (선택 셀들에서)
  const srcCodes = Array.from(_extSelectedCells)
    .filter(k => _extParseKey(k).workerId === srcWid)
    .sort()
    .map(k => {
      const { workerId, date } = _extParseKey(k)
      const c = _extGetCell(workerId, date)
      return c?.dataset.extshift || ''
    })
  if (srcCodes.length === 0) return

  const previews = document.querySelectorAll(`.ext-cell[data-extid="${srcWid}"].ext-cell-fill-preview`)
  const fillItems = []
  previews.forEach((c, i) => {
    const shiftType = srcCodes[i % srcCodes.length]
    fillItems.push({ workerId: srcWid, date: c.dataset.date, shiftType })
    c.classList.remove('ext-cell-fill-preview')
  })
  if (fillItems.length > 0) {
    _extApplyBatch(fillItems)
    showToast(`${fillItems.length}개 셀 자동채우기 완료`, 'success')
  }
  _extFillSrcKey = null
}

// ── 복사/붙여넣기 ────────────────────────────────────────────
window.extCopyCells = () => {
  if (_extSelectedCells.size === 0) return
  const entries = Array.from(_extSelectedCells).sort().map(k => {
    const { workerId, date } = _extParseKey(k)
    const cell = _extGetCell(workerId, date)
    return { workerId, date, shiftType: cell?.dataset?.extshift || '' }
  })
  _extCopiedData = { entries }
  // 선택 스타일 갱신 (복사된 셀에 자동으로 점선 테두리 적용됨)
  _extUpdateSelectStyle()
  const label = entries.length === 1
    ? `[${EXT_SHIFT_LABEL_MAP[entries[0].shiftType] || entries[0].shiftType || '비어있음'}]`
    : `${entries.length}개 셀`
  showToast(`📋 ${label} 복사됨 — Ctrl+V로 붙여넣기`, 'success')
}

window.extPasteCells = () => {
  if (!_extCopiedData?.entries?.length) { showToast('복사된 셀이 없습니다', 'info'); return }
  // 선택된 셀이 없으면 앵커 셀만 대상으로
  const anchorKey = _extAnchorKey
  if (_extSelectedCells.size === 0 && !anchorKey) {
    showToast('붙여넣기할 대상 셀을 먼저 선택하세요', 'info'); return
  }
  const targets = _extSelectedCells.size > 0
    ? Array.from(_extSelectedCells).sort()
    : [anchorKey]
  const src = _extCopiedData.entries
  const items = []
  if (src.length === 1) {
    // 단일 소스 → 선택 전체에 동일 코드 붙여넣기
    targets.forEach(k => {
      const { workerId, date } = _extParseKey(k)
      items.push({ workerId, date, shiftType: src[0].shiftType })
    })
  } else {
    // 다중 소스 → 대상 첫 셀 기준으로 날짜 오프셋
    const { workerId: tWid, date: tStartDate } = _extParseKey(targets[0])
    const srcStartDate = src[0].date
    const msPerDay = 86400000
    const dateDiff = (new Date(tStartDate) - new Date(srcStartDate)) / msPerDay
    src.forEach((s) => {
      const d = new Date(s.date)
      d.setDate(d.getDate() + dateDiff)
      const newDate = d.toISOString().slice(0,10)
      items.push({ workerId: tWid, date: newDate, shiftType: s.shiftType })
    })
  }
  _extApplyBatch(items)
  // 복사 아웃라인은 유지 (재사용 가능)
  const label = src.length === 1
    ? `[${EXT_SHIFT_LABEL_MAP[src[0].shiftType] || src[0].shiftType || '비움'}]`
    : `${src.length}개 코드`
  showToast(`✅ ${label} → ${items.length}개 셀 붙여넣기 완료 (Ctrl+V 재사용 가능)`, 'success')
}

window.extDeleteCells = () => {
  if (_extSelectedCells.size === 0) return
  const items = Array.from(_extSelectedCells).map(k => {
    const { workerId, date } = _extParseKey(k)
    return { workerId, date, shiftType: '' }
  })
  _extApplyBatch(items)
  showToast(`${items.length}개 셀 삭제`, 'info')
  _extClearSelection()
}

// ── 방향키 이동 ───────────────────────────────────────────────
function _extMoveSelection(dir) {
  if (_extSelectedCells.size === 0) return
  const keys = Array.from(_extSelectedCells).sort()
  const anchor = _extAnchorKey || keys[0]
  const { workerId, date } = _extParseKey(anchor)

  const days = getDaysInMonth(App.currentYear, App.currentMonth)
  const d = parseInt(date.slice(8))
  const workers = scheduleExternalWorkers || []
  const wIdx = workers.findIndex(w => w.id === workerId)

  let newWorkerId = workerId, newDay = d
  if (dir === 'right' && d < days) newDay = d + 1
  else if (dir === 'left'  && d > 1) newDay = d - 1
  else if (dir === 'down'  && wIdx < workers.length - 1) newWorkerId = workers[wIdx + 1].id
  else if (dir === 'up'    && wIdx > 0)                  newWorkerId = workers[wIdx - 1].id
  else return

  const newDate = `${App.currentYear}-${String(App.currentMonth).padStart(2,'0')}-${String(newDay).padStart(2,'0')}`
  const newKey  = `${newWorkerId}_${newDate}`
  _extSelectedCells.clear()
  _extSelectedCells.add(newKey)
  _extAnchorKey = newKey
  _extUpdateSelectStyle()
  _extShowFillHandle()
  // 스크롤 into view
  _extGetCell(newWorkerId, newDate)?.scrollIntoView({ block:'nearest', inline:'nearest' })
}

// ── 직접 타이핑 입력 ─────────────────────────────────────────
function _extOpenInlineInput(workerId, date, cell, initChar) {
  if (!cell) cell = _extGetCell(workerId, date)
  if (!cell) return
  // 이미 열린 드롭다운이 있으면 — initChar가 없으면 그냥 focus만 (닫지 않음)
  const existing = cell.querySelector('.ext-inline-select')
  if (existing) {
    if (!initChar) { existing.focus(); return }
    existing.remove()
  }
  const seq = getExtShiftSeq().filter(s => s !== '')
  if (seq.length === 0) { showToast('활성화된 근무유형이 없습니다. 근무조 설정에서 활성화하세요.', 'info'); return }
  // select 드롭다운 생성
  const sel = document.createElement('select')
  sel.className = 'ext-inline-select'
  sel.style.cssText = 'position:absolute;top:0;left:0;width:100%;height:100%;font-size:10px;border:2px solid #3b82f6;border-radius:3px;background:white;z-index:20;cursor:pointer'
  sel.innerHTML = seq.map(s => {
    const cfg = _getExtShiftCfg(s)
    const label = cfg?.label || EXT_SHIFT_LABEL_MAP[s] || s
    return `<option value="${s}" ${cell.dataset.extshift===s?'selected':''}>${label}</option>`
  }).join('')
  // 초기 문자로 미리 매핑
  if (initChar) {
    const labelMap = { '오':'morning', 'ㅇ':'morning', 'a':'morning', 'A':'morning',
      'b':'afternoon', 'B':'afternoon', '9':'full_9h', '1':'full_12h', 'F':'full_12h', 'f':'full_12h' }
    const matched = labelMap[initChar] || labelMap[initChar.toUpperCase()]
    if (matched && seq.includes(matched)) sel.value = matched
  }
  cell.style.position = 'relative'
  cell.appendChild(sel)
  // 짧은 딜레이 후 focus (이벤트 버블링 방지)
  requestAnimationFrame(() => { sel.focus() })
  const _commit = (v) => {
    const oldShift = cell.dataset.extshift || ''
    if (v !== oldShift) {
      _extPushUndo([{ workerId, date, oldType: oldShift, newType: v }])
      _extApplyDOM(workerId, date, cell, v)
      _extQueueSave(workerId, date, v)
      _extRecalcRow(workerId)
    }
    sel.remove()
    _extSelectedCells.clear()
    _extSelectedCells.add(`${workerId}_${date}`)
    _extAnchorKey = `${workerId}_${date}`
    _extUpdateSelectStyle()
    _extUpdateBar()
  }
  sel.onchange = () => _commit(sel.value)
  sel.onblur = () => { setTimeout(() => { if (cell.contains(sel)) sel.remove() }, 150) }
  sel.onkeydown = (ev) => {
    if (ev.key === 'Escape') { sel.remove(); ev.preventDefault() }
    if (ev.key === 'Enter') { ev.preventDefault(); _commit(sel.value) }
  }
}

// 헬퍼: extShiftConfig에서 특정 키의 설정 가져오기
function _getExtShiftCfg(key) {
  try {
    const cfg = JSON.parse(localStorage.getItem('extShiftConfig') || '[]')
    return cfg.find(c => c.key === key) || null
  } catch(e) { return null }
}

// ── 하단 툴바 (외부인력 선택 시) ─────────────────────────────
function _extUpdateBar() {
  if (!_toolbarEnabled || _extSelectedCells.size === 0) { _extHideBar(); return }
  const bar = document.getElementById('multiSelectBar')
  if (!bar) return
  bar.classList.remove('hidden')

  // 선택 카운트 표시
  const countEl = document.getElementById('multiSelectCount')
  const n = _extSelectedCells.size
  // 현재 앵커 셀의 코드 표시
  const anchorCell = _extAnchorKey ? (() => {
    const { workerId, date } = _extParseKey(_extAnchorKey)
    return _extGetCell(workerId, date)
  })() : null
  const curShift = anchorCell?.dataset?.extshift || ''
  const curLabel = curShift ? (EXT_SHIFT_LABEL_MAP[curShift] || curShift) : ''
  if (countEl) countEl.textContent = n === 1
    ? `${n}개 선택 (파출/알바)${curLabel ? ` · [${curLabel}]` : ''}`
    : `${n}개 선택 (파출/알바)`

  // 근무 코드 버튼을 외부인력용으로 교체 (extShiftConfig 기반)
  const btnsEl = document.getElementById('multiSelectCodeBtns')
  if (btnsEl) {
    const seq = getExtShiftSeq().filter(s => s !== '')
    btnsEl.innerHTML = seq.map(s => {
      const cfg = _getExtShiftCfg(s)
      const label = cfg?.label || EXT_SHIFT_LABEL_MAP[s] || s
      // 색상: cfg에서 bg/color 우선, 없으면 EXT_SHIFT_COLORS fallback
      const colStr = EXT_SHIFT_COLORS[s] || 'background:#f9fafb;color:#374151'
      const col = colStr.match(/color:([^;]+)/)?.[1] || '#374151'
      const bg  = colStr.match(/background:([^;]+)/)?.[1] || '#f9fafb'
      const isActive = curShift === s
      return `<button onclick="extApplyCodeInstant('${s}')"
        style="padding:3px 9px;border-radius:4px;font-size:11px;font-weight:700;
               background:${bg};color:${col};
               border:${isActive?'2px':'1px'} solid ${col}${isActive?'':'44'};
               cursor:pointer;transform:${isActive?'scale(1.1)':'scale(1)'};
               box-shadow:${isActive?`0 0 0 2px ${col}33`:'none'};
               transition:all 0.1s"
        title="${label} 적용 (파출/알바)">${label}</button>`
    }).join('')
  }

  // 상단 #schedQuickCodeBtns 버튼도 파출/알바 활성 코드 하이라이트
  document.querySelectorAll('#schedQuickCodeBtns button[data-extkey]').forEach(b => {
    const isActive = b.dataset.extkey === curShift
    b.style.borderWidth = isActive ? '2.5px' : '1.5px'
    b.style.transform   = isActive ? 'scale(1.15)' : 'scale(1)'
    b.style.boxShadow   = isActive ? `0 0 0 2px ${b.style.color}44` : ''
  })

  // 복사/붙여넣기/삭제 버튼을 외부인력용으로 교체
  _extSyncToolbarButtons(true)
}

// 툴바 버튼을 직원/외부인력 모드로 전환
function _extSyncToolbarButtons(isExt) {
  const copyBtn = document.getElementById('toolbar-copy-btn')
  const pasteBtn = document.getElementById('multiSelectPasteBtn')
  const delBtn  = document.getElementById('toolbar-del-btn')
  if (copyBtn) {
    copyBtn.onclick = isExt ? () => extCopyCells() : () => schedCopyCells()
    copyBtn.title = isExt ? '파출/알바 셀 복사 (Ctrl+C)' : '선택 셀 복사 (Ctrl+C)'
  }
  if (pasteBtn) {
    pasteBtn.onclick = isExt ? () => extPasteCells() : () => schedPasteCells()
    pasteBtn.title = isExt ? '파출/알바 붙여넣기 (Ctrl+V)' : '붙여넣기 (Ctrl+V)'
  }
  if (delBtn) {
    delBtn.onclick = isExt ? () => extDeleteCells() : () => schedDeleteCells()
    delBtn.title = isExt ? '파출/알바 셀 삭제 (Del)' : '선택 셀 삭제 (Delete/Backspace)'
  }
}

function _extHideBar() {
  // 직원 셀이 선택된 상태면 숨기지 않음
  if (_selectedCells && _selectedCells.size > 0) return
  // 외부인력 셀도 없고 직원 셀도 없을 때만 숨김
  const bar = document.getElementById('multiSelectBar')
  if (bar) bar.classList.add('hidden')
  // 툴바 버튼을 직원 모드로 복원
  _extSyncToolbarButtons(false)
}

window.extApplyCodeInstant = (shiftType) => {
  if (_extSelectedCells.size === 0) {
    showToast('파출/알바 셀을 먼저 클릭하여 선택하세요', 'info')
    return
  }
  const items = Array.from(_extSelectedCells).map(k => {
    const { workerId, date } = _extParseKey(k)
    return { workerId, date, shiftType }
  })
  _extApplyBatch(items)
  showToast(`${items.length}개 셀 → ${EXT_SHIFT_LABEL_MAP[shiftType]||shiftType} 적용`, 'success')
}

// ── 키보드 이벤트 (기존 keydown 핸들러에 ext 추가) ─────────────
// 기존 scheduleTab 키다운 핸들러에서 ext 셀 선택 상태도 처리 (아래 _extHandleKeydown에서)
window._extHandleKeydown = (e) => {
  if (_extSelectedCells.size === 0) return false
  const tag = document.activeElement?.tagName
  if (tag === 'INPUT' || tag === 'TEXTAREA' || tag === 'SELECT') return false
  if (e.ctrlKey || e.metaKey) {
    if (e.key === 'c' || e.key === 'C') { e.preventDefault(); extCopyCells(); return true }
    if (e.key === 'v' || e.key === 'V') { e.preventDefault(); extPasteCells(); return true }
    // Z/Y undo/redo는 전역 keydown 핸들러(document.addEventListener)에서 처리
    return false
  }
  if (e.key === 'ArrowRight') { e.preventDefault(); _extMoveSelection('right'); return true }
  if (e.key === 'ArrowLeft')  { e.preventDefault(); _extMoveSelection('left');  return true }
  if (e.key === 'ArrowDown')  { e.preventDefault(); _extMoveSelection('down');  return true }
  if (e.key === 'ArrowUp')    { e.preventDefault(); _extMoveSelection('up');    return true }
  if (e.key === 'Delete' || e.key === 'Backspace') { e.preventDefault(); extDeleteCells(); return true }
  if (e.key === 'Escape') { _extClearSelection(); return true }
  // 직접 타이핑
  if (e.key.length === 1 && !e.ctrlKey && !e.metaKey) {
    const anchor = _extAnchorKey
    if (!anchor) return false
    const { workerId, date } = _extParseKey(anchor)
    const cell = _extGetCell(workerId, date)
    if (cell) { _extOpenInlineInput(workerId, date, cell, e.key); e.preventDefault(); return true }
  }
  return false
}

// ── CSS 주입 (ext 셀 fill preview 스타일) ─────────────────────
;(() => {
  if (document.getElementById('ext-cell-css')) return
  const st = document.createElement('style')
  st.id = 'ext-cell-css'
  st.textContent = `
    .ext-cell-fill-preview { outline: 2px dashed #f97316 !important; outline-offset: -2px !important; }
    .ext-cell-copied       { outline: 2px dashed #3b82f6 !important; outline-offset: -2px !important; }
    .ext-fill-handle:hover { background: #1d4ed8 !important; transform: scale(1.3); }
  `
  document.head.appendChild(st)
})()

// ── 외부인력 삭제 ─────────────────────────────────────────────
window.deleteExternalWorker = async (workerId, workerName) => {
  if (!confirm(`"${workerName}" 외부인력을 삭제하시겠습니까?\n이 직원의 모든 스케줄도 함께 삭제됩니다.`)) return
  try {
    const res = await api('DELETE', `/api/schedule/external-workers/${workerId}`)
    if (res?.success !== false) {
      showToast('외부인력이 삭제되었습니다', 'success')
      const monthData = await api('GET', `/api/schedule/${App.currentYear}/${App.currentMonth}`).catch(() => null)
      if (monthData) {
        scheduleMonthData = monthData
        scheduleExternalWorkers = monthData.external_workers || []
        scheduleExtSchedMap = monthData.ext_sched_map || {}
      }
      const tc = document.getElementById('scheduleTabContent')
      if (tc && scheduleTab === 'schedule') {
        tc.innerHTML = renderMonthlyScheduleTab()
        setTimeout(initExtWorkerEvents, 0)
      }
    } else {
      showToast('삭제 실패', 'error')
    }
  } catch(e) {
    showToast('오류가 발생했습니다', 'error')
  }
}

// ── 운영진 뷰 전용 인쇄 함수 ─────────────────────────────────
window.printExecutiveView = function() {
  const execView = document.querySelector('[data-exec-view]')
  if (!execView) { window.print(); return }

  const year  = App.currentYear
  const month = App.currentMonth

  // ── DOM에서 데이터 추출 ─────────────────────────────────────
  // KPI 카드 수치 추출
  const kpiCards = execView.querySelectorAll('div[style*="border-radius:12px"][style*="text-align:center"]')
  const kpiData = []
  kpiCards.forEach(card => {
    const num   = card.querySelector('div[style*="font-size:26px"]')?.textContent?.trim() || ''
    const label = card.querySelector('div[style*="font-size:10px"]')?.textContent?.trim() || ''
    const bgStyle = card.getAttribute('style') || ''
    const bgMatch = bgStyle.match(/background:([^;]+)/)
    const bg = bgMatch ? bgMatch[1] : '#374151'
    if (num) kpiData.push({ num, label, bg })
  })

  // 직원별 근무일수 바 차트 데이터 추출
  const barRows = execView.querySelectorAll('div[style*="display:flex;align-items:center;gap:6px;margin-bottom:5px"]')
  const barData = []
  barRows.forEach(row => {
    const name   = row.querySelector('div[style*="min-width:64px"]')?.textContent?.trim() || ''
    const bar    = row.querySelector('div[style*="border-radius:4px;height:16px"]')
    const days   = row.querySelector('span[style*="right:5px"]')?.textContent?.trim() || ''
    const badge  = row.querySelector('span[style*="font-size:9px"]')?.textContent?.trim() || ''
    const bgStyle = bar?.querySelector('div')?.getAttribute('style') || ''
    const colorMatch = bgStyle.match(/background:([^;]+)/)
    const color = colorMatch ? colorMatch[1] : '#2563eb'
    const pctMatch  = bgStyle.match(/width:(\d+)%/)
    const pct = pctMatch ? parseInt(pctMatch[1]) : 0
    if (name) barData.push({ name, days, badge, color, pct })
  })

  // 주차별 막대 데이터 추출
  const weekBarEls = execView.querySelectorAll('div[style*="flex-direction:column;align-items:center;flex:1"]')
  const weekData = []
  weekBarEls.forEach(el => {
    const val  = el.querySelector('div[style*="font-size:10px;font-weight:700"]')?.textContent?.trim() || ''
    const lbl  = el.querySelectorAll('div[style*="font-size:10px"]')
    const week = lbl[lbl.length - 1]?.textContent?.trim() || ''
    const bar  = el.querySelector('div[style*="border-radius:4px;height:60px"]')
    const innerBar = bar?.querySelector('div')
    const pctMatch = innerBar?.getAttribute('style')?.match(/height:(\d+)%/)
    const pct = pctMatch ? parseInt(pctMatch[1]) : 0
    if (week) weekData.push({ val, week, pct })
  })

  // 근무조별 집중도 카드 추출
  const codeCardEls = execView.querySelectorAll('div[style*="display:flex;align-items:center;gap:8px;padding:7px"]')
  const codeData = []
  codeCardEls.forEach(el => {
    const code  = el.querySelector('span[style*="border-radius:6px"]')?.textContent?.trim() || ''
    const count = el.querySelector('div[style*="font-size:11px;font-weight:700"]')?.textContent?.trim() || ''
    const pctEl = el.querySelector('span[style*="font-size:10px"]')
    const pct   = pctEl?.textContent?.trim() || ''
    const bg    = (el.getAttribute('style') || '').match(/background:([^;]+0e)/)?.[1] || '#f3f4f6'
    const innerBar = el.querySelector('div[style*="border-radius:3px;height:4px"] > div')
    const barBg = innerBar?.getAttribute('style')?.match(/background:([^;]+)/)?.[1] || '#6b7280'
    const barW  = innerBar?.getAttribute('style')?.match(/width:([^;]+)/)?.[1] || '0%'
    if (code) codeData.push({ code, count, pct, bg, barBg, barW })
  })

  // 경고 메시지 추출
  const warnEls = execView.querySelectorAll('div[style*="border-radius:8px;padding:7px 12px;font-size:11px"]')
  const warnHtml = Array.from(warnEls).map(el => el.outerHTML).join('')

  // 균형 지표 추출
  const balanceScore = execView.querySelector('span[style*="font-size:12px;font-weight:900"]')?.textContent?.trim() || ''
  const balanceLabel = execView.querySelector('div[style*="font-size:13px;font-weight:800"]')?.textContent?.trim() || ''

  // ── 인쇄용 HTML 생성 ───────────────────────────────────────
  const kpiHtml = kpiData.map(k => `
    <div style="background:${k.bg};color:white;border-radius:10px;padding:14px 10px;text-align:center;break-inside:avoid">
      <div style="font-size:28px;font-weight:900;line-height:1">${k.num}</div>
      <div style="font-size:11px;opacity:.9;margin-top:4px">${k.label}</div>
    </div>`).join('')

  const barHtml = barData.map(b => `
    <div style="display:flex;align-items:center;gap:8px;margin-bottom:7px">
      <div style="min-width:72px;font-size:12px;font-weight:600;color:#374151;text-align:right;white-space:nowrap">${b.name}</div>
      <div style="flex:1;background:#e5e7eb;border-radius:4px;height:18px;position:relative">
        <div style="width:${b.pct}%;background:${b.color};height:100%;border-radius:4px"></div>
        <span style="position:absolute;right:6px;top:50%;transform:translateY(-50%);font-size:11px;font-weight:700;color:#1f2937">${b.days}</span>
      </div>
      ${b.badge ? `<span style="font-size:10px;font-weight:700;color:${b.color};min-width:36px">${b.badge}</span>` : '<span style="min-width:36px"></span>'}
    </div>`).join('')

  const weekHtml = weekData.length ? weekData.map(w => `
    <div style="display:flex;flex-direction:column;align-items:center;flex:1;gap:3px">
      <div style="font-size:11px;font-weight:700;color:#374151">${w.val}</div>
      <div style="width:100%;background:#e5e7eb;border-radius:4px;height:70px;display:flex;align-items:flex-end">
        <div style="width:100%;background:linear-gradient(180deg,#6366f1,#4338ca);height:${Math.max(w.pct,4)}%;border-radius:4px"></div>
      </div>
      <div style="font-size:11px;color:#6b7280">${w.week}</div>
    </div>`).join('') : '<p style="color:#9ca3af;font-size:12px">데이터 없음</p>'

  const codeHtml = codeData.length ? `
    <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(130px,1fr));gap:8px">
      ${codeData.map(c => `
      <div style="display:flex;align-items:center;gap:8px;padding:8px 10px;background:${c.bg};border-radius:8px;border:1px solid ${c.barBg}40">
        <span style="display:inline-flex;align-items:center;justify-content:center;min-width:30px;height:30px;border-radius:6px;background:${c.barBg}28;color:${c.barBg};font-weight:900;font-size:13px">${c.code}</span>
        <div style="flex:1">
          <div style="font-size:12px;font-weight:700;color:#374151">${c.count}</div>
          <div style="background:#e5e7eb;border-radius:3px;height:4px;margin-top:3px">
            <div style="width:${c.barW};background:${c.barBg};height:100%;border-radius:3px"></div>
          </div>
        </div>
        <span style="font-size:11px;color:${c.barBg};font-weight:700">${c.pct}</span>
      </div>`).join('')}
    </div>` : ''

  const printWin = window.open('', '_blank', 'width=900,height=1200')
  if (!printWin) { window.print(); return }

  printWin.document.write(`<!DOCTYPE html>
<html lang="ko">
<head>
  <meta charset="UTF-8">
  <title>${year}년 ${month}월 운영진 보고서</title>
  <link href="https://cdn.jsdelivr.net/npm/@fortawesome/fontawesome-free@6.4.0/css/all.min.css" rel="stylesheet">
  <style>
    * { box-sizing:border-box; margin:0; padding:0; }
    body { font-family:-apple-system,BlinkMacSystemFont,'Malgun Gothic','Apple SD Gothic Neo',sans-serif;
           background:white; color:#1f2937; }
    .page { width:210mm; min-height:297mm; padding:16mm 14mm; margin:0 auto; background:white; }
    h2 { font-size:20px; font-weight:900; }
    section { margin-bottom:18px; break-inside:avoid; }
    .section-title { font-size:13px; font-weight:700; color:#374151; margin-bottom:10px;
                     padding-bottom:6px; border-bottom:2px solid #e5e7eb;
                     display:flex; align-items:center; gap:6px; }
    .kpi-grid { display:grid; grid-template-columns:repeat(6,1fr); gap:8px; }
    .warn-block { margin-bottom:6px; }
    .week-chart { display:flex; gap:10px; align-items:flex-end; height:80px; padding:0 4px; }
    @media print {
      body { -webkit-print-color-adjust:exact; print-color-adjust:exact; }
      .page { padding:10mm 10mm; }
      .no-print { display:none!important; }
    }
  </style>
</head>
<body>
<div class="page">

  <!-- 헤더 -->
  <div style="background:linear-gradient(135deg,#4c1d95,#7c3aed);border-radius:12px;padding:16px 20px;margin-bottom:18px;color:white">
    <div style="display:flex;align-items:center;justify-content:space-between">
      <div>
        <div style="font-size:11px;opacity:.7;letter-spacing:1px;margin-bottom:4px">HOSPITAL MEAL MANAGEMENT · 운영진 요약 보고서</div>
        <h2>${year}년 ${month}월 운영진 요약</h2>
        <div style="font-size:11px;opacity:.8;margin-top:3px">전체 인력 운영 현황 · 경영진 의사결정 지원</div>
      </div>
      <div style="text-align:right;font-size:11px;opacity:.8">
        <div>출력일: ${new Date().toLocaleDateString('ko-KR')}</div>
      </div>
    </div>
  </div>

  <!-- ① KPI 카드 -->
  <section>
    <div class="section-title"><i class="fas fa-chart-bar" style="color:#7c3aed"></i> 핵심 지표</div>
    <div class="kpi-grid">${kpiHtml}</div>
  </section>

  <!-- ② 균형 지표 + 경고 -->
  <section>
    <div class="section-title"><i class="fas fa-bell" style="color:#f59e0b"></i> 운영 알림</div>
    <div class="warn-block">${warnHtml || '<div style="background:#f0fdf4;border:1px solid #bbf7d0;border-radius:8px;padding:8px 12px;font-size:12px;color:#166534"><i class="fas fa-check-circle" style="margin-right:6px"></i>근무 분포 이상 없음</div>'}</div>
  </section>

  <!-- ③ 직원별 근무일수 바차트 -->
  <section>
    <div class="section-title"><i class="fas fa-users" style="color:#2563eb"></i> 직원별 근무일수</div>
    <div style="font-size:10px;color:#9ca3af;display:flex;gap:12px;margin-bottom:8px">
      <span style="color:#2563eb">■ 정상</span>
      <span style="color:#ef4444">■ 과중(130%+)</span>
      <span style="color:#f59e0b">■ 부족(70%-)</span>
    </div>
    <div>${barHtml || '<p style="color:#9ca3af;font-size:12px">데이터 없음</p>'}</div>
  </section>

  <!-- ④ 주차별 근무 배치 -->
  <section>
    <div class="section-title"><i class="fas fa-calendar-week" style="color:#6366f1"></i> 주차별 근무 배치</div>
    <div class="week-chart">${weekHtml}</div>
  </section>

  ${codeHtml ? `
  <!-- ⑤ 근무조별 집중도 -->
  <section>
    <div class="section-title"><i class="fas fa-layer-group" style="color:#7c3aed"></i> 근무조별 집중도</div>
    ${codeHtml}
  </section>` : ''}

  <!-- 푸터 -->
  <div style="margin-top:24px;padding-top:10px;border-top:1px solid #e5e7eb;display:flex;justify-content:space-between;font-size:10px;color:#9ca3af">
    <span>Re&H Hospital Meal Management System</span>
    <span>${year}년 ${month}월 운영진 보고서</span>
  </div>

</div>
<script>
  window.onload = function() {
    setTimeout(function() { window.print(); }, 800)
  }
<\/script>
</body>
</html>`)
  printWin.document.close()
}

// ── 월간 분석 리포트 인쇄 (일별 인원표 + 안정성 + 파출/알바 분석 + 종합평가) ──
window.printMonthlyAnalysisReport = function() {
  const year  = App.currentYear
  const month = App.currentMonth
  const md    = scheduleMonthData
  if (!md) { showToast('스케줄 데이터를 먼저 로드하세요', 'error'); return }

  const sm         = md?.sched_map || {}
  const emps       = scheduleEmployees || []
  const shifts     = scheduleShifts || []
  const extWorkers = (md?.ext_workers || md?.external_workers) || []
  const extSchedMap= scheduleExtSchedMap || {}
  const holidays   = md?.holidays || []
  const ws_r       = scheduleWorkSettings || {}
  const days       = new Date(year, month, 0).getDate()
  const requiredR  = parseInt(ws_r.required_staff_count || '0')
  const hospitalName = md?.hospital_name || ''
  const REST_CODES_R = CALC_ENGINE.REST_CODES_SET // ✅ CALC_ENGINE
  const DOW_LABELS = ['일','월','화','수','목','금','토']

  // ── 일별 인원 집계 ──────────────────────────────────────────
  const dailyReport = []
  for(let d=1; d<=days; d++) {
    const ds  = `${year}-${String(month).padStart(2,'0')}-${String(d).padStart(2,'0')}`
    const dow = new Date(ds).getDay()
    const isHol = (holidays || []).some(h => (h.date||h) === ds)
    let regular=0, dispatch=0, parttime=0
    for(const emp of emps) {
      if(emp.team === 'nutrition') continue // 영양사 제외
      const code = (sm[`${emp.id}_${ds}`] || {}).shift_code || ''
      if(code && code!=='-' && !REST_CODES_R.has(code)) regular++
    }
    for(const w of extWorkers) {
      const entry = extSchedMap[`${w.id}_${ds}`]
      if(entry && (entry.shift_type || entry.shift_code)) {
        if(w.worker_type === 'dispatch') dispatch++
        else parttime++
      }
    }
    const total = regular + dispatch + parttime
    let status = '', statusColor = '#374151'
    if(requiredR > 0) {
      const r = total / requiredR
      if(r < 0.9) { status='부족'; statusColor='#dc2626' }
      else if(r > 1.1) { status='과다'; statusColor='#2563eb' }
      else { status='정상'; statusColor='#16a34a' }
    }
    dailyReport.push({ d, ds, dow, isHol, regular, dispatch, parttime, total, status, statusColor })
  }

  // ── 통계 집계 ───────────────────────────────────────────────
  const totalArr  = dailyReport.map(r => r.total)
  const avgTotal  = (totalArr.reduce((a,v)=>a+v,0)/days).toFixed(1)
  const maxTotal  = Math.max(...totalArr)
  const minTotal  = Math.min(...totalArr)
  const variance2 = totalArr.reduce((a,v)=>a+Math.pow(v-parseFloat(avgTotal),2),0)/days
  const stddev2   = Math.sqrt(variance2).toFixed(2)
  const shortageDaysR = requiredR > 0 ? dailyReport.filter(r=>r.status==='부족').length : 0
  const overDaysR     = requiredR > 0 ? dailyReport.filter(r=>r.status==='과다').length : 0

  // ── 주별 외부인력 집계 ─────────────────────────────────────
  const weekCount_r = Math.ceil(days/7)
  const weeklyExt = Array.from({length:weekCount_r},(_,wk)=>{
    const wkDays = dailyReport.filter(r=>Math.floor((r.d-1)/7)===wk)
    return {
      wk: wk+1,
      dispatch: wkDays.reduce((a,r)=>a+r.dispatch,0),
      parttime: wkDays.reduce((a,r)=>a+r.parttime,0),
      avgTotal: wkDays.length ? (wkDays.reduce((a,r)=>a+r.total,0)/wkDays.length).toFixed(1) : '0'
    }
  })
  const totalDispatchDays = dailyReport.reduce((a,r)=>a+r.dispatch,0)
  const totalParttimeDays = dailyReport.reduce((a,r)=>a+r.parttime,0)
  const totalExtDays      = totalDispatchDays + totalParttimeDays
  const totalAllPersonDays= dailyReport.reduce((a,r)=>a+r.total,0)
  const extPct = totalAllPersonDays > 0 ? ((totalExtDays/totalAllPersonDays)*100).toFixed(1) : '0'

  // ── 인력 안정성 점수 ────────────────────────────────────────
  let stabScore_r = 100
  let stabLabel_r = '안정', stabColor_r = '#16a34a'
  if(requiredR > 0) {
    stabScore_r = Math.max(0, Math.round(100 - shortageDaysR*6 - overDaysR*3))
    if(stabScore_r >= 90)      { stabLabel_r='안정'; stabColor_r='#16a34a' }
    else if(stabScore_r >= 70) { stabLabel_r='주의'; stabColor_r='#f59e0b' }
    else                       { stabLabel_r='위험'; stabColor_r='#ef4444' }
  }

  // ── 종합 평가 ───────────────────────────────────────────────
  const evalR = []
  if(requiredR > 0) {
    if(shortageDaysR===0 && overDaysR===0) evalR.push({ t:'good', msg:`전 기간 기준인원(${requiredR}명) 충족 — 인력 운영 매우 안정적` })
    else {
      if(shortageDaysR>0) evalR.push({ t:'bad',  msg:`인력 부족 ${shortageDaysR}일 발생 — 기준인원 90% 미달. 파출·알바 확충 또는 근무조 조정 필요` })
      if(overDaysR>0)     evalR.push({ t:'info', msg:`인력 과다 ${overDaysR}일 발생 — 기준인원 110% 초과. 비용 최적화 여지 있음` })
    }
  }
  const dep_r = parseFloat(extPct)
  if(dep_r >= 20)     evalR.push({ t:'warn', msg:`외부인력 의존도 ${extPct}% — 높은 편. 정규직 충원 검토 권장` })
  else if(dep_r > 0)  evalR.push({ t:'good', msg:`외부인력 의존도 ${extPct}% — 적정 수준` })
  if(evalR.length===0) evalR.push({ t:'good', msg:'전반적으로 안정적인 인력 운영 상태' })

  // ── HTML 생성 ───────────────────────────────────────────────
  // 일별 인원표 행
  const dailyTableRows = dailyReport.map(r => {
    const rowBg = r.dow===0||r.isHol ? '#fff8f8' : r.dow===6 ? '#f0f4ff' : (r.d%2===0?'#f9fafb':'white')
    const dowColor = r.dow===0||r.isHol?'#dc2626':r.dow===6?'#2563eb':'#374151'
    const totalCell = requiredR>0
      ? `<td style="padding:3px 6px;text-align:center;font-size:11px;font-weight:700;color:${r.statusColor}">${r.total} <span style="font-size:9px">(${r.status})</span></td>`
      : `<td style="padding:3px 6px;text-align:center;font-size:11px;font-weight:700;color:#374151">${r.total}</td>`
    const diffCell = requiredR > 0
      ? (() => { const diff=r.total-requiredR; const c=diff<0?'#dc2626':diff>0?'#2563eb':'#16a34a'; return `<td style="padding:3px 6px;text-align:center;font-size:11px;font-weight:600;color:${c}">${diff>0?'+'+diff:diff===0?'±0':diff}</td>` })()
      : ''
    return `<tr style="background:${rowBg};border-bottom:1px solid #e5e7eb">
      <td style="padding:3px 6px;text-align:center;font-size:11px;font-weight:600;color:${dowColor}">${month}/${r.d}(${DOW_LABELS[r.dow]})</td>
      ${totalCell}
      ${diffCell}
      <td style="padding:3px 6px;text-align:center;font-size:11px;color:#374151">${r.regular}</td>
      <td style="padding:3px 6px;text-align:center;font-size:11px;color:${r.dispatch>0?'#ea580c':'#d1d5db'}">${r.dispatch||'-'}</td>
      <td style="padding:3px 6px;text-align:center;font-size:11px;color:${r.parttime>0?'#db2777':'#d1d5db'}">${r.parttime||'-'}</td>
    </tr>`
  }).join('')

  // 주별 외부인력 표 행
  const weekExtRows = weeklyExt.map(w => `
    <tr style="border-bottom:1px solid #e5e7eb">
      <td style="padding:4px 8px;font-size:11px;font-weight:600;color:#374151">${w.wk}주차</td>
      <td style="padding:4px 8px;text-align:center;font-size:11px;font-weight:700;color:#374151">${w.avgTotal}명</td>
      <td style="padding:4px 8px;text-align:center;font-size:11px;color:${w.dispatch>0?'#ea580c':'#d1d5db'}">${w.dispatch||'-'}</td>
      <td style="padding:4px 8px;text-align:center;font-size:11px;color:${w.parttime>0?'#db2777':'#d1d5db'}">${w.parttime||'-'}</td>
      <td style="padding:4px 8px;text-align:center;font-size:11px;color:#374151">${w.dispatch+w.parttime||'-'}</td>
    </tr>`).join('')

  // 종합평가 항목
  const evalHtmlR = evalR.map(e => {
    const bg=e.t==='good'?'#f0fdf4':e.t==='bad'?'#fff1f2':e.t==='warn'?'#fffbeb':'#eff6ff'
    const border=e.t==='good'?'#bbf7d0':e.t==='bad'?'#fecaca':e.t==='warn'?'#fde68a':'#bfdbfe'
    const color=e.t==='good'?'#166534':e.t==='bad'?'#b91c1c':e.t==='warn'?'#92400e':'#1e40af'
    const icon=e.t==='good'?'✔':e.t==='bad'?'✖':e.t==='warn'?'△':'ℹ'
    return `<div style="background:${bg};border:1px solid ${border};border-radius:7px;padding:8px 12px;font-size:11px;color:${color};margin-bottom:5px;display:flex;gap:7px">
      <span style="flex-shrink:0;font-weight:700">${icon}</span><span>${e.msg}</span>
    </div>`
  }).join('')

  // 일별 흐름 미니 막대차트 (CSS)
  const maxBar = Math.max(...totalArr, 1)
  const flowBars = dailyReport.map(r => {
    const h = Math.round((r.total/maxBar)*60)
    const c = r.status==='부족'?'#ef4444':r.status==='과다'?'#3b82f6':'#22c55e'
    return `<div style="display:flex;flex-direction:column;align-items:center;gap:1px;flex:1;min-width:0">
      <div style="width:100%;background:#e5e7eb;border-radius:2px;height:60px;display:flex;align-items:flex-end">
        <div style="width:100%;background:${c};height:${Math.max(h,2)}px;border-radius:2px"></div>
      </div>
      <div style="font-size:6px;color:#9ca3af;transform:rotate(-60deg);transform-origin:top;margin-top:2px;white-space:nowrap">${r.d}</div>
    </div>`
  }).join('')

  const printWin2 = window.open('', '_blank', 'width=1000,height=1400')
  if (!printWin2) { showToast('팝업이 차단되었습니다. 팝업 허용 후 다시 시도하세요', 'error'); return }

  printWin2.document.write(`<!DOCTYPE html>
<html lang="ko">
<head>
  <meta charset="UTF-8">
  <title>${year}년 ${month}월 월간 인력 분석 리포트</title>
  <style>
    *{box-sizing:border-box;margin:0;padding:0}
    body{font-family:-apple-system,BlinkMacSystemFont,'Malgun Gothic','Apple SD Gothic Neo',sans-serif;background:white;color:#1f2937;font-size:12px}
    .page{width:210mm;min-height:297mm;padding:14mm 12mm;margin:0 auto;background:white}
    h2{font-size:18px;font-weight:900}
    section{margin-bottom:16px;break-inside:avoid}
    .section-title{font-size:12px;font-weight:700;color:#374151;margin-bottom:8px;padding-bottom:5px;border-bottom:2px solid #e5e7eb;display:flex;align-items:center;gap:5px}
    table{width:100%;border-collapse:collapse}
    th{background:#f1f5f9;padding:5px 6px;font-size:10px;color:#374151;font-weight:700;text-align:center}
    td{padding:3px 5px;border-bottom:1px solid #f3f4f6;font-size:11px}
    .stat-grid{display:grid;grid-template-columns:repeat(4,1fr);gap:8px}
    .stat-card{background:#f8fafc;border:1px solid #e5e7eb;border-radius:8px;padding:10px;text-align:center}
    .stat-num{font-size:22px;font-weight:900}
    .stat-lbl{font-size:10px;color:#6b7280;margin-top:2px}
    .no-print{display:none!important}
    @media print{
      body{-webkit-print-color-adjust:exact;print-color-adjust:exact}
      .page{padding:8mm 8mm}
      .no-print{display:none!important}
    }
  </style>
</head>
<body>
<div class="page">

  <!-- 헤더 -->
  <div style="background:linear-gradient(135deg,#1e3a5f,#2563eb);border-radius:12px;padding:14px 18px;margin-bottom:16px;color:white">
    <div style="display:flex;align-items:flex-start;justify-content:space-between">
      <div>
        <div style="font-size:10px;opacity:.7;letter-spacing:1px;margin-bottom:3px">STAFFING ANALYSIS REPORT</div>
        <h2>${year}년 ${month}월 월간 인력 분석 리포트</h2>
        ${hospitalName ? `<div style="font-size:11px;opacity:.8;margin-top:3px">${hospitalName}</div>` : ''}
      </div>
      <div style="text-align:right;font-size:11px;opacity:.8">
        <div>출력일: ${new Date().toLocaleDateString('ko-KR')}</div>
        ${requiredR > 0 ? `<div style="margin-top:3px">기준인원: <strong>${requiredR}명</strong></div>` : ''}
      </div>
    </div>
  </div>

  <!-- ① 핵심 통계 요약 -->
  <section>
    <div class="section-title">① 핵심 통계 요약</div>
    <div class="stat-grid">
      <div class="stat-card">
        <div class="stat-num" style="color:#2563eb">${avgTotal}</div>
        <div class="stat-lbl">일평균 근무인원</div>
      </div>
      <div class="stat-card">
        <div class="stat-num" style="color:#2563eb">${maxTotal}</div>
        <div class="stat-lbl">최대 인원</div>
      </div>
      <div class="stat-card">
        <div class="stat-num" style="color:#dc2626">${minTotal}</div>
        <div class="stat-lbl">최소 인원</div>
      </div>
      <div class="stat-card">
        <div class="stat-num" style="color:#6b7280">${stddev2}</div>
        <div class="stat-lbl">일별 표준편차</div>
      </div>
      ${requiredR > 0 ? `
      <div class="stat-card">
        <div class="stat-num" style="color:${stabColor_r}">${stabScore_r}점</div>
        <div class="stat-lbl">인력 안정성 점수 (${stabLabel_r})</div>
      </div>
      <div class="stat-card">
        <div class="stat-num" style="color:#dc2626">${shortageDaysR}</div>
        <div class="stat-lbl">인력 부족일 수</div>
      </div>
      <div class="stat-card">
        <div class="stat-num" style="color:#2563eb">${overDaysR}</div>
        <div class="stat-lbl">인력 과다일 수</div>
      </div>` : ''}
      <div class="stat-card">
        <div class="stat-num" style="color:#ea580c">${extPct}%</div>
        <div class="stat-lbl">외부인력 의존도</div>
      </div>
    </div>
  </section>

  <!-- ② 일별 인원 흐름 차트 -->
  <section>
    <div class="section-title">② 일별 인원 흐름</div>
    ${requiredR > 0 ? `<div style="font-size:10px;color:#6b7280;margin-bottom:5px;display:flex;gap:10px">
      <span style="color:#ef4444">■ 부족(&lt;기준 90%)</span>
      <span style="color:#22c55e">■ 정상</span>
      <span style="color:#3b82f6">■ 과다(&gt;기준 110%)</span>
      ${requiredR>0?`<span style="color:#374151">기준: ${requiredR}명</span>`:''}
    </div>` : ''}
    <div style="display:flex;gap:2px;align-items:flex-end;padding:4px 0 8px">${flowBars}</div>
  </section>

  <!-- ③ 일별 인원 상세 표 -->
  <section style="break-before:auto">
    <div class="section-title">③ 일별 인원 상세 표</div>
    <div style="overflow-x:auto">
      <table>
        <thead>
          <tr>
            <th>날짜</th>
            <th>합계</th>
            ${requiredR>0?`<th>기준대비</th>`:''}
            <th>정규</th>
            <th style="color:#ea580c">파출</th>
            <th style="color:#db2777">알바</th>
          </tr>
        </thead>
        <tbody>${dailyTableRows}</tbody>
      </table>
    </div>
  </section>

  <!-- ④ 외부인력 분석 -->
  <section>
    <div class="section-title">④ 외부인력(파출·알바) 분석</div>
    <div style="display:grid;grid-template-columns:1fr 1fr;gap:12px">
      <div>
        <div style="font-size:11px;font-weight:600;color:#374151;margin-bottom:5px">월간 외부인력 사용 요약</div>
        <div style="background:#fff7ed;border:1px solid #fed7aa;border-radius:8px;padding:10px">
          <div style="display:flex;justify-content:space-between;margin-bottom:4px"><span style="font-size:11px;color:#9a3412">파출 총 사용일</span><strong style="color:#ea580c">${totalDispatchDays}일</strong></div>
          <div style="display:flex;justify-content:space-between;margin-bottom:4px"><span style="font-size:11px;color:#9a3412">알바 총 사용일</span><strong style="color:#db2777">${totalParttimeDays}일</strong></div>
          <div style="display:flex;justify-content:space-between;margin-bottom:4px"><span style="font-size:11px;color:#9a3412">외부인력 총 합계</span><strong style="color:#b45309">${totalExtDays}일</strong></div>
          <div style="display:flex;justify-content:space-between"><span style="font-size:11px;color:#9a3412">전체 대비 비중</span><strong style="color:#b45309">${extPct}%</strong></div>
        </div>
      </div>
      <div>
        <div style="font-size:11px;font-weight:600;color:#374151;margin-bottom:5px">주별 외부인력 현황</div>
        <table>
          <thead><tr><th>주차</th><th>평균인원</th><th style="color:#ea580c">파출</th><th style="color:#db2777">알바</th><th>소계</th></tr></thead>
          <tbody>${weekExtRows}</tbody>
        </table>
      </div>
    </div>
  </section>

  <!-- ⑤ 종합 평가 -->
  <section>
    <div class="section-title">⑤ 종합 평가 및 개선 제안</div>
    ${evalHtmlR}
  </section>

  <!-- 푸터 -->
  <div style="margin-top:20px;padding-top:8px;border-top:1px solid #e5e7eb;display:flex;justify-content:space-between;font-size:10px;color:#9ca3af">
    <span>Re&H Hospital Meal Management System</span>
    <span>${year}년 ${month}월 월간 인력 분석 리포트</span>
  </div>

</div>
<script>
  window.onload = function() { setTimeout(function() { window.print(); }, 800) }
<\/script>
</body>
</html>`)
  printWin2.document.close()
}

// ── 파출/알바 근무유형 행 삭제 ────────────────────────────────
window.deleteExtShiftRow = (idx) => {
  const row = document.getElementById(`extShiftRow_${idx}`)
  if (!row) return
  const label = document.getElementById(`extLabel_${idx}`)?.value || `항목 ${idx+1}`
  if (!confirm(`"${label}" 근무유형을 삭제하시겠습니까?`)) return
  row.remove()
  showToast('삭제되었습니다. 저장 버튼을 눌러 적용하세요.', 'info')
}

// ── 파출/알바 근무유형 행 추가 ────────────────────────────────
window.addExtShiftRow = () => {
  const container = document.getElementById('extShiftConfigRows')
  if (!container) return
  const existing = container.querySelectorAll('div[id^="extShiftRow_"]')
  const idx = existing.length
  const newKey = `custom_${Date.now()}`
  const div = document.createElement('div')
  div.className = 'flex items-center gap-3 p-3 rounded-xl border border-orange-200 bg-orange-50'
  div.id = `extShiftRow_${idx}`
  div.innerHTML = `
    <label class="flex items-center gap-1.5 cursor-pointer shrink-0">
      <input type="checkbox" checked onchange="toggleExtShiftRow(${idx}, this.checked)"
        class="rounded border-orange-300 text-orange-500">
      <span class="text-xs font-semibold text-orange-700">사용</span>
    </label>
    <div class="w-10 h-10 rounded-lg flex items-center justify-center text-sm font-bold shrink-0"
      style="background:#fff7ed;color:#ea580c">신규</div>
    <div class="grid grid-cols-2 gap-2 flex-1 min-w-0">
      <div>
        <label class="text-xs text-gray-500 block mb-0.5">표시 이름</label>
        <input type="text" value="" id="extLabel_${idx}" class="w-full border border-gray-200 rounded px-2 py-1 text-xs" placeholder="근무유형 이름">
      </div>
      <div>
        <label class="text-xs text-gray-500 block mb-0.5">근무시간 (h)</label>
        <input type="number" value="8" id="extHours_${idx}" min="1" max="24" class="w-full border border-gray-200 rounded px-2 py-1 text-xs">
      </div>
      <div>
        <label class="text-xs text-gray-500 block mb-0.5">시작 시간</label>
        <input type="time" value="07:00" id="extStart_${idx}" class="w-full border border-gray-200 rounded px-2 py-1 text-xs">
      </div>
      <div>
        <label class="text-xs text-gray-500 block mb-0.5">종료 시간</label>
        <input type="time" value="19:00" id="extEnd_${idx}" class="w-full border border-gray-200 rounded px-2 py-1 text-xs">
      </div>
    </div>
    <div class="shrink-0 text-xs text-gray-400 text-center" style="min-width:52px">
      <div class="font-mono text-[10px] text-gray-400">${newKey}</div>
      <button onclick="deleteExtShiftRow(${idx})" title="이 근무유형 삭제"
        class="mt-1 w-full px-1 py-0.5 rounded text-[10px] bg-red-50 hover:bg-red-100 text-red-400 hover:text-red-600 border border-red-200 transition-colors">
        <i class="fas fa-trash"></i> 삭제
      </button>
    </div>
  `
  container.appendChild(div)
  showToast('항목이 추가되었습니다. 이름 입력 후 저장하세요.', 'info')
}

// ── 파출/알바 근무유형 기본값 초기화 ─────────────────────────
window.resetExtShiftConfig = () => {
  if (!confirm('파출/알바 근무유형을 기본값(오전/오후/9H/12H)으로 초기화하시겠습니까?')) return
  localStorage.removeItem('extShiftConfig')
  showToast('기본값으로 초기화되었습니다', 'success')
  // 근무조 탭 재렌더링
  const content = document.getElementById('pageContent')
  if (content) renderScheduleTab(content)
}

// ── 법정근무시간 설정 모달 열기/저장 ──────────────────────────
window.openWorkSettingsModal = async () => {
  const modal = document.getElementById('workSettingsModal')
  if (!modal) return
  modal.classList.remove('hidden')
  // 기존 설정 로드 (admin이면 현재 병원 ID를 쿼리로 전달)
  const hospQuery = App.role === 'admin' && App.currentHospitalId ? `?hospitalId=${App.currentHospitalId}` : ''
  const data = await api('GET', `/api/schedule/work-settings${hospQuery}`).catch(() => null)
  const ws = data || {}
  const setVal = (id, val) => { const el = document.getElementById(id); if (el) el.value = val }
  const setChk = (id, val) => { const el = document.getElementById(id); if (el) el.checked = val === '1' || val === true }
  setVal('ws_daily_max_hours',         ws.daily_max_hours         ?? '8')
  setVal('ws_weekly_max_hours',        ws.weekly_max_hours        ?? '52')
  setVal('ws_consecutive_max_days',    ws.consecutive_max_days    ?? '6')
  setVal('ws_leave_cluster_threshold', ws.leave_cluster_threshold ?? '40')
  setVal('ws_required_staff_count',    ws.required_staff_count    ?? '0')
  setVal('ws_required_staff_count_weekend', ws.required_staff_count_weekend ?? '0')
  setChk('ws_legal_warning_enabled',   ws.legal_warning_enabled   ?? '1')
  setChk('ws_ot_cost_enabled',         ws.ot_cost_enabled         ?? '1')
  setChk('ws_dispatch_enabled',        ws.dispatch_enabled        ?? '1')
  // ① 근무제 유형
  const ogt = ws.off_grant_type || 'weekly5'
  const radioEl = document.getElementById(`ws_ogt_${ogt}`)
  if (radioEl) radioEl.checked = true
  setVal('ws_off_cycle_work_days',      ws.off_cycle_work_days      ?? '5')
  setVal('ws_off_cycle_rest_days',      ws.off_cycle_rest_days      ?? '2')
  setVal('ws_off_cycle_start_date',     ws.off_cycle_start_date     ?? '')
  setVal('ws_monthly_fixed_off_days',   ws.monthly_fixed_off_days   ?? '10')
  // ② 공휴일 처리 정책
  const hp = ws.holiday_policy || 'off'
  const hpEl = document.getElementById(`ws_hp_${hp}`)
  if (hpEl) hpEl.checked = true
  const chp = ws.cycle_holiday_policy || 'add'
  const chpEl = document.getElementById(`ws_chp_${chp}`)
  if (chpEl) chpEl.checked = true
  // ③ 월 최소 휴무 보장
  setVal('ws_monthly_min_off_days', ws.monthly_min_off_days ?? '0')
  wsToggleOffGrantType(ogt)
  // ⑤ 월차 자동 생성 정책
  setChk('ws_monthly_leave_enabled',   ws.monthly_leave_enabled   ?? '1')
  setVal('ws_ml_max_days',             ws.monthly_leave_max_days  ?? '11')
  setChk('ws_ml_auto_transition',      ws.monthly_leave_auto_transition ?? '1')
  setVal('ws_ml_attendance_ratio',     ws.monthly_leave_attendance_ratio ?? '80')
  const mlRule = ws.monthly_leave_attendance_rule || 'full'
  const mlRuleEl = document.getElementById(`ws_ml_rule_${mlRule}`)
  if (mlRuleEl) mlRuleEl.checked = true
  const ratioRow = document.getElementById('ws_ml_ratio_row')
  if (ratioRow) ratioRow.classList.toggle('hidden', mlRule !== 'ratio')
  // ⑥ 급여 공개 정책
  setChk('ws_show_base_salary', ws.show_base_salary ?? '0')
  scheduleWorkSettings = ws

  // hospital(영양사) 역할은 읽기 전용 처리 - 모든 입력 요소 비활성화
  if (App.role === 'hospital') {
    setTimeout(() => {
      const m = document.getElementById('workSettingsModal')
      if (!m) return
      // 모든 입력 비활성화
      m.querySelectorAll('input, select, textarea, button[onclick*="save"]').forEach(el => {
        if (el.id === 'workSettingsModal' || el.closest('button[onclick*="hidden"]')) return
        el.disabled = true
        el.style.opacity = '0.6'
        el.style.cursor = 'not-allowed'
        el.style.pointerEvents = 'none'
      })
      // 저장 버튼 숨기기
      m.querySelectorAll('button[onclick*="saveWorkSettings"]').forEach(btn => {
        btn.style.display = 'none'
      })
      // 읽기 전용 배너 삽입
      const contentArea = m.querySelector('.p-6')
      if (contentArea && !contentArea.querySelector('#wsReadonlyBanner')) {
        const banner = document.createElement('div')
        banner.id = 'wsReadonlyBanner'
        banner.className = 'bg-blue-50 border border-blue-200 rounded-lg p-3 text-sm text-blue-700 flex items-center gap-2'
        banner.innerHTML = '<i class="fas fa-lock text-blue-500"></i><span>조회 전용 — 설정 변경은 관리자(리엔에이치)에게 문의하세요.</span>'
        contentArea.insertBefore(banner, contentArea.firstChild)
      }
    }, 50)
  }
}

window.saveWorkSettings = async () => {
  const getVal = (id) => document.getElementById(id)?.value || ''
  const getChk = (id) => document.getElementById(id)?.checked ? '1' : '0'
  const getRadio = (name) => document.querySelector(`input[name="${name}"]:checked`)?.value || ''
  const body = {
    daily_max_hours:           getVal('ws_daily_max_hours'),
    weekly_max_hours:          getVal('ws_weekly_max_hours'),
    consecutive_max_days:      getVal('ws_consecutive_max_days'),
    leave_cluster_threshold:   getVal('ws_leave_cluster_threshold'),
    required_staff_count:      getVal('ws_required_staff_count') || '0',
    required_staff_count_weekend: getVal('ws_required_staff_count_weekend') || '0',
    legal_warning_enabled:     getChk('ws_legal_warning_enabled'),
    ot_cost_enabled:           getChk('ws_ot_cost_enabled'),
    dispatch_enabled:          getChk('ws_dispatch_enabled'),
    // ① 근무제 유형
    off_grant_type:            getRadio('ws_off_grant_type') || 'weekly5',
    off_cycle_work_days:       getVal('ws_off_cycle_work_days')    || '5',
    off_cycle_rest_days:       getVal('ws_off_cycle_rest_days')    || '2',
    off_cycle_start_date:      getVal('ws_off_cycle_start_date'),
    monthly_fixed_off_days:    getVal('ws_monthly_fixed_off_days') || '10',
    // ② 공휴일 처리 정책
    holiday_policy:            getRadio('ws_holiday_policy')        || 'off',
    cycle_holiday_policy:      getRadio('ws_cycle_holiday_policy')  || 'add',
    // ③ 월 최소 휴무 보장
    monthly_min_off_days:      getVal('ws_monthly_min_off_days')   || '0',
    // ⑤ 월차 자동 생성 정책
    monthly_leave_enabled:           getChk('ws_monthly_leave_enabled'),
    monthly_leave_attendance_rule:   getRadio('ws_ml_attendance_rule') || 'full',
    monthly_leave_attendance_ratio:  getVal('ws_ml_attendance_ratio') || '80',
    monthly_leave_max_days:          getVal('ws_ml_max_days') || '11',
    monthly_leave_auto_transition:   getChk('ws_ml_auto_transition'),
    // ⑥ 급여 공개 정책
    show_base_salary:                getChk('ws_show_base_salary'),
    // admin이면 현재 병원 ID 포함
    ...(App.role === 'admin' && App.currentHospitalId ? { hospitalId: App.currentHospitalId } : {})
  }
  const res = await api('POST', '/api/schedule/work-settings', body).catch(() => null)
  if (res?.success !== false) {
    showToast('근무 환경 설정이 저장되었습니다', 'success')
    scheduleWorkSettings = body
    document.getElementById('workSettingsModal')?.classList.add('hidden')
    // 근무설정 변경 후 off-grants 데이터 새로 불러와서 즉시 반영
    await reloadScheduleMonth()
  } else {
    showToast('저장 실패', 'error')
  }
}

// ── 파출/알바 근무유형 설정 저장/토글 ──────────────────────────
window.saveExtShiftConfig = () => {
  const rows = document.querySelectorAll('#extShiftConfigRows > div[id^="extShiftRow_"]')
  const EXT_KEYS = ['morning','afternoon','full_9h','full_12h']
  const EXT_DEFAULTS_BG = { morning:'#fff7ed', afternoon:'#fef3c7', full_9h:'#ffedd5', full_12h:'#fee2e2' }
  const EXT_DEFAULTS_COLOR = { morning:'#c2410c', afternoon:'#b45309', full_9h:'#ea580c', full_12h:'#dc2626' }
  const cfg = []
  rows.forEach((row, pos) => {
    // 실제 row id에서 인덱스 추출 (삭제 후 id가 불연속적일 수 있음)
    const rowIdMatch = row.id.match(/extShiftRow_(\d+)/)
    const idx = rowIdMatch ? parseInt(rowIdMatch[1]) : pos
    const defaultKey = EXT_KEYS[pos] // 저장 위치 기준으로 키 재배정
    // 기존 키 정보는 font-mono div에서 읽기
    const keyEl = row.querySelector('.font-mono')
    const storedKey = keyEl?.textContent?.trim() || ''
    const key = EXT_KEYS.indexOf(storedKey) >= 0 ? storedKey : (EXT_KEYS[pos] || `custom_${pos}`)
    const label = document.getElementById(`extLabel_${idx}`)?.value?.trim() || key
    const hours = document.getElementById(`extHours_${idx}`)?.value || '8'
    const start = document.getElementById(`extStart_${idx}`)?.value || '07:00'
    const end   = document.getElementById(`extEnd_${idx}`)?.value || '19:00'
    const chk   = row.querySelector('input[type="checkbox"]')?.checked ?? true
    if (!label) return // 이름 없는 항목은 저장 제외
    cfg.push({
      key, label, hours, startTime: start, endTime: end,
      enabled: chk,
      bg:    EXT_DEFAULTS_BG[key]    || '#fff7ed',
      color: EXT_DEFAULTS_COLOR[key] || '#ea580c'
    })
  })
  localStorage.setItem('extShiftConfig', JSON.stringify(cfg))
  showToast('파출/알바 근무유형 설정이 저장되었습니다', 'success')

  // EXT_SHIFT_LABEL_MAP 동적 업데이트
  cfg.forEach(c => { EXT_SHIFT_LABEL_MAP[c.key] = c.label })
}

window.toggleExtShiftRow = (idx, enabled) => {
  const row = document.getElementById(`extShiftRow_${idx}`)
  if (!row) return
  row.classList.toggle('border-orange-200', enabled)
  row.classList.toggle('bg-orange-50', enabled)
  row.classList.toggle('border-gray-200', !enabled)
  row.classList.toggle('bg-gray-50', !enabled)
  const label = row.querySelector('span.text-xs.font-semibold')
  if (label) {
    label.classList.toggle('text-orange-700', enabled)
    label.classList.toggle('text-gray-400', !enabled)
  }
}

// 휴무 부여 방식 라디오 토글
window.wsToggleOffGrantType = (type) => {
  const el = document.getElementById('ws_ogt_' + type)
  if (el) el.checked = true

  // 순환 패턴 옵션 (cycle / mixed 선택 시 표시)
  const cycleOpts = document.getElementById('ws_cycle_options')
  if (cycleOpts) {
    if (type === 'cycle' || type === 'mixed') cycleOpts.classList.remove('hidden')
    else cycleOpts.classList.add('hidden')
  }

  // 월 고정 휴무제 옵션 (monthly_fixed 선택 시 표시)
  const monthlyOpts = document.getElementById('ws_monthly_fixed_options')
  if (monthlyOpts) {
    if (type === 'monthly_fixed') monthlyOpts.classList.remove('hidden')
    else monthlyOpts.classList.add('hidden')
  }

  // 순환/혼합형 공휴일 충돌 처리 옵션 (cycle / mixed 선택 시 표시)
  const cycleHolOpts = document.getElementById('ws_cycle_holiday_options')
  if (cycleHolOpts) {
    if (type === 'cycle' || type === 'mixed') cycleHolOpts.classList.remove('hidden')
    else cycleHolOpts.classList.add('hidden')
  }

  // ② 공휴일 처리 정책 비활성화: cycle 선택 시 라디오 비활성 + 안내 문구 표시
  const hpNotice  = document.getElementById('ws_holiday_policy_cycle_notice')
  const hpRadios  = document.getElementById('ws_holiday_policy_radios')
  if (type === 'cycle') {
    // cycle: holiday_policy 완전 무시 → 비활성화 + 안내 표시
    if (hpNotice) hpNotice.classList.remove('hidden')
    if (hpRadios) {
      hpRadios.style.opacity = '0.35'
      hpRadios.style.pointerEvents = 'none'
      hpRadios.title = '순환근무 모드에서는 공휴일 처리 정책이 적용되지 않습니다'
    }
    // cycle_holiday_policy 기본값 ignore 자동 선택
    const ignoreEl = document.getElementById('ws_chp_ignore')
    if (ignoreEl && !document.querySelector('input[name="ws_cycle_holiday_policy"]:checked')) {
      ignoreEl.checked = true
    }
  } else {
    // 다른 모드: 활성화
    if (hpNotice) hpNotice.classList.add('hidden')
    if (hpRadios) {
      hpRadios.style.opacity = ''
      hpRadios.style.pointerEvents = ''
      hpRadios.title = ''
    }
  }

  wsUpdateCyclePreview()
}

// 순환패턴 미리보기 업데이트
window.wsUpdateCyclePreview = () => {
  const preview = document.getElementById('ws_cycle_preview')
  if (!preview) return
  const w = parseInt(document.getElementById('ws_off_cycle_work_days')?.value || '5')
  const r = parseInt(document.getElementById('ws_off_cycle_rest_days')?.value || '2')
  if (!w || !r || w < 1 || r < 1) { preview.textContent = ''; return }
  const total = w + r
  const monthDays = 30
  const cycles = Math.floor(monthDays / total)
  const rem = monthDays % total
  const restInMonth = cycles * r + Math.max(0, rem - w)
  preview.innerHTML = `<i class="fas fa-info-circle mr-1"></i>패턴: <b>${w}일 근무 → ${r}일 휴무</b> 반복 (주기 ${total}일) · 월 약 <b>${restInMonth}일</b> 휴무`
}

window.openLaborCostSettings = async () => {
  const modal = document.getElementById('laborCostSettingsModal')
  if (!modal) return
  modal.classList.remove('hidden')
  // 기존 설정 로드
  const data = await api('GET', '/api/schedule/labor-costs').catch(() => [])
  const costMap = {}
  ;(data||[]).forEach((d) => { costMap[d.cost_type] = d.unit_price })
  const ALL_KEYS = ['dispatch_morning','dispatch_afternoon','dispatch_9h','dispatch_12h',
                    'parttime_morning','parttime_afternoon','parttime_9h','parttime_12h','parttime_hourly']
  ALL_KEYS.forEach(k => {
    const el = document.getElementById(`lc_${k}`)
    if (el) el.value = costMap[k] != null ? String(costMap[k]) : ''
  })
}

window.saveLaborCostSettings = async () => {
  const ALL_KEYS = ['dispatch_morning','dispatch_afternoon','dispatch_9h','dispatch_12h',
                    'parttime_morning','parttime_afternoon','parttime_9h','parttime_12h','parttime_hourly']
  for (const t of ALL_KEYS) {
    const el = document.getElementById(`lc_${t}`)
    if (!el) continue
    const price = parseFloat(el.value || '0')
    await api('POST', '/api/schedule/labor-costs', { cost_type: t, unit_price: price }).catch(()=>null)
  }
  showToast('단가 설정이 저장되었습니다', 'success')
  document.getElementById('laborCostSettingsModal')?.classList.add('hidden')
  // 리포트 새로고침
  const _hqLC = (App.role === 'admin' && App.currentHospitalId) ? `?hospitalId=${App.currentHospitalId}` : ''
  scheduleLaborCostData = await api('GET', `/api/schedule/labor-cost-report/${App.currentYear}/${App.currentMonth}${_hqLC}`).catch(()=>null)
  const tc = document.getElementById('scheduleTabContent')
  if (tc && scheduleTab === 'laborCost') tc.innerHTML = renderLaborCostTab()
}

window.openEmpModal = async (mode, empId, defaultTeam) => {
  empModalMode = mode
  empModalData = null
  if (mode === 'edit' && empId) {
    empModalData = await api('GET', `/api/schedule/employees/${empId}`).catch(() => null)
  } else if (defaultTeam) {
    empModalData = { team: defaultTeam }
    empModalMode = 'add'
  }
  const content = document.getElementById('pageContent')
  renderScheduleTab(content)
  setTimeout(() => {
    document.getElementById('empCardModal').classList.remove('hidden')
    // 0057: 모달 열릴 때 근무정책 UI 초기화
    initEmpWorkPolicyUI()
  }, 50)
}

// 0057: 직원 근무정책 UI 초기화 및 이벤트 바인딩
function initEmpWorkPolicyUI() {
  // ① 근무유형 라디오 버튼 클릭 시 선택 스타일 + cycle 옵션 표시/숨김
  document.querySelectorAll('input[name="ei_work_type"]').forEach(radio => {
    radio.addEventListener('change', () => {
      // 모든 버튼 스타일 초기화
      document.querySelectorAll('.select-work-type-btn').forEach(btn => {
        btn.className = btn.className
          .replace(/bg-\w+-50\s*/g, '')
          .replace(/border-\w+-500\s*/g, '')
          .replace(/text-\w+-800\s*/g, '')
          .replace(/font-semibold\s*/g, '')
          .replace(/ring-2\s*/g, '')
          .replace(/ring-\w+-[0-9]+\s*/g, '')
      })
      // 선택된 버튼 스타일 적용
      const sel = document.querySelector('input[name="ei_work_type"]:checked')
      if (sel) {
        const colorMap = {
          '': 'gray', weekly5: 'blue', cycle: 'purple', monthly_fixed: 'green', mixed: 'orange'
        }
        const c = colorMap[sel.value] || 'gray'
        const selSpan = sel.nextElementSibling
        if (selSpan) {
          selSpan.classList.add(`bg-${c}-50`, `border-${c}-500`, `text-${c}-800`, 'font-semibold', 'ring-2', `ring-${c}-200`)
        }
      }
      // cycle/mixed 선택 시 패턴 옵션 표시
      const cycleOpts = document.getElementById('ei_cycle_options')
      if (cycleOpts) {
        const v = document.querySelector('input[name="ei_work_type"]:checked')?.value
        cycleOpts.classList.toggle('hidden', v !== 'cycle' && v !== 'mixed')
      }
    })
  })

  // ② 운영방식 라디오 버튼 클릭 시 카드 스타일 업데이트
  document.querySelectorAll('input[name="ei_schedule_type"]').forEach(radio => {
    radio.addEventListener('change', () => {
      document.querySelectorAll('.schedule-type-option').forEach((card, i) => {
        const isFlexible = i === 0
        const checked = document.querySelectorAll('input[name="ei_schedule_type"]')[i]?.checked
        if (checked) {
          card.classList.remove('border-gray-200', 'bg-white')
          if (isFlexible) card.classList.add('border-blue-500', 'bg-blue-50')
          else card.classList.add('border-amber-500', 'bg-amber-50')
        } else {
          if (isFlexible) card.classList.remove('border-blue-500', 'bg-blue-50')
          else card.classList.remove('border-amber-500', 'bg-amber-50')
          card.classList.add('border-gray-200', 'bg-white')
        }
      })
    })
  })
}

window.saveEmployeeCard = async (empId) => {
  const name = document.getElementById('ei_name')?.value?.trim()
  if (!name) { showToast('이름은 필수입니다', 'error'); return }

  const workParts = ['cooking','serving','washing','nutrition','breakfast','lunch','dinner','preprocess']
    .filter(p => document.getElementById(`ei_wp_${p}`)?.checked)

  const body = {
    name,
    team: document.getElementById('ei_team')?.value || 'cook',
    position: (() => { const sel = document.getElementById('ei_position')?.value || ''; return sel === '기타' ? (document.getElementById('ei_position_custom')?.value?.trim() || '기타') : sel })(),
    empNumber: document.getElementById('ei_empNumber')?.value || '',
    birthDate: document.getElementById('ei_birthDate')?.value || '',
    hireDate: document.getElementById('ei_hireDate')?.value || '',
    employmentType: document.getElementById('ei_employmentType')?.value || 'full',
    workParts,
    phone: document.getElementById('ei_phone')?.value || '',
    emergencyContact: document.getElementById('ei_emergencyContact')?.value || '',
    address: document.getElementById('ei_address')?.value || '',
    healthCertExpire: document.getElementById('ei_healthCertExpire')?.value || '',
    healthExamDate: document.getElementById('ei_healthExamDate')?.value || '',
    healthExamStatus: document.getElementById('ei_healthExamStatus')?.value || 'pending',
    annualLeaveTotal: parseFloat(document.getElementById('ei_annualLeave')?.value || '15'),
    note: document.getElementById('ei_note')?.value || '',
    salaryType: document.getElementById('ei_salaryType')?.value || 'monthly',
    baseSalary: parseFloat(document.getElementById('ei_baseSalary')?.value || '0'),
    otEnabled: document.getElementById('ei_otEnabled')?.checked ? 1 : 0,
    nightEnabled: document.getElementById('ei_nightEnabled')?.checked ? 1 : 0,
    holidayEnabled: document.getElementById('ei_holidayEnabled')?.checked ? 1 : 0,
    // Phase D: 공휴일 정책 오버라이드 (빈 문자열 = 병원 기본값 상속)
    holidayPolicyOverride: document.getElementById('ei_holidayPolicyOverride')?.value || null,
    // 0057: 직원별 근무정책
    workType: document.querySelector('input[name="ei_work_type"]:checked')?.value || null,
    scheduleType: document.querySelector('input[name="ei_schedule_type"]:checked')?.value || 'flexible',
    workCycleStartDate: document.getElementById('ei_work_cycle_start_date')?.value || null,
    cycleWorkDays: document.getElementById('ei_cycle_work_days')?.value ? parseInt(document.getElementById('ei_cycle_work_days').value) : null,
    cycleRestDays: document.getElementById('ei_cycle_rest_days')?.value ? parseInt(document.getElementById('ei_cycle_rest_days').value) : null,
  }

  let res
  if (empId) {
    res = await api('PUT', `/api/schedule/employees/${empId}`, body)
  } else {
    res = await api('POST', '/api/schedule/employees', body)
  }

  if (res?.success) {
    document.getElementById('empCardModal').classList.add('hidden')
    showToast(empId ? '수정되었습니다' : '직원이 추가되었습니다', 'success')
    // 데이터 리로드
    const _ym = `${App.currentYear}-${String(App.currentMonth).padStart(2,'0')}`
    scheduleEmployees = await api('GET', `/api/schedule/employees?yearMonth=${_ym}`).catch(() => [])
    const content = document.getElementById('pageContent')
    renderScheduleTab(content)
  } else {
    showToast(res?.error || '저장 실패', 'error')
  }
}

window.confirmResignEmployee = (empId, name) => {
  if (!confirm(`"${name}" 직원을 퇴사 처리하시겠습니까?\n퇴사일이 오늘로 설정됩니다.`)) return
  api('DELETE', `/api/schedule/employees/${empId}`).then(res => {
    if (res?.success) {
      showToast(`${name}님 퇴사 처리됨`, 'success')
      const _ym2 = `${App.currentYear}-${String(App.currentMonth).padStart(2,'0')}`
      api('GET', `/api/schedule/employees?yearMonth=${_ym2}`).then(data => {
        scheduleEmployees = data || []
        const content = document.getElementById('pageContent')
        renderScheduleTab(content)
      })
    }
  })
}

