window.txLoadAnnualReport = async function() {
  const authH = { Authorization: `Bearer ${localStorage.getItem('token')}` }
  const hospitalId = TXState.selectedHospitalId || window._adminHospitalId || ''
  const hParam = hospitalId ? `?hospital_id=${hospitalId}` : '?'
  const hSep = hospitalId ? '&' : ''
  const year = parseInt(document.getElementById('txAnnualYear')?.value) || TXState.year || new Date().getFullYear()
  const content = document.getElementById('txAnnualContent')
  if (content) content.innerHTML = `<div class="text-center text-gray-400 py-12"><i class="fas fa-spinner fa-spin text-2xl"></i></div>`

  try {
    const res = await axios.get(`/api/transaction/invoice/annual-summary${hParam}${hSep}year=${year}`, { headers: authH })
    const d = res.data
    if (!d.ok) throw new Error(d.error)

    window._txAnnualData = d
    const fmt = v => (Number(v)||0).toLocaleString()
    const fmtM = v => v >= 100000000 ? (v/100000000).toFixed(1)+'억' : v >= 10000 ? Math.round(v/10000)+'만' : fmt(v)

    // 월별 전체 합계
    const moTotals = {}
    d.monthly.forEach(r => {
      if (!moTotals[r.mo]) moTotals[r.mo] = 0
      moTotals[r.mo] += Number(r.total_amount)||0
    })
    const grandTotal = Object.values(moTotals).reduce((s, v) => s + (Number(v)||0), 0)

    // 분기별 합계
    const qTotals = {1:0, 2:0, 3:0, 4:0}
    d.quarterly.forEach((r) => {
      qTotals[r.quarter] = (qTotals[r.quarter]||0) + (Number(r.total_amount)||0)
    })

    // 업체별 합계
    const vendorMap = {}
    d.vendors.forEach((r) => { vendorMap[r.vendor_name] = Number(r.total_amount)||0 })
    const topVendors = d.vendors.slice(0, 5)

    if (!content) return

    // 데이터가 없을 때 안내 화면 표시
    if (grandTotal === 0 && d.monthly.length === 0) {
      const hospName = TXState.selectedHospitalName || ''
      content.innerHTML = `
      <div class="bg-white rounded-xl shadow-sm border border-orange-100 p-8 text-center">
        <div class="w-16 h-16 bg-orange-100 rounded-full flex items-center justify-center mx-auto mb-4">
          <i class="fas fa-calendar-alt text-orange-400 text-2xl"></i>
        </div>
        <h3 class="text-base font-bold text-gray-700 mb-2">
          ${hospName ? `<span class="text-blue-600">${hospName}</span>의 ` : ''}${year}년 거래명세서 데이터가 없습니다
        </h3>
        <p class="text-sm text-gray-400 mb-4">
          거래명세서 파일을 업로드하면 연간/분기별 분석 보고서가 자동으로 생성됩니다.
        </p>
        <button onclick="txSwitchTab('upload')"
          class="inline-flex items-center gap-2 bg-blue-600 text-white px-4 py-2 rounded-lg text-sm font-medium hover:bg-blue-700 transition">
          <i class="fas fa-upload"></i> 거래명세서 업로드하기
        </button>
      </div>`
      return
    }

    content.innerHTML = `
    <div class="space-y-4">

      <!-- 연간 요약 카드 -->
      <div class="grid grid-cols-2 sm:grid-cols-4 gap-3">
        ${[
          { label: `${year}년 총 납품액`, val: fmtM(grandTotal)+'원', sub: `${fmt(grandTotal)}원`, icon: 'fa-won-sign', color: '#1d4ed8' },
          { label: '1분기 (1~3월)', val: fmtM(qTotals[1])+'원', sub: `전체의 ${grandTotal > 0 ? Math.round(qTotals[1]/grandTotal*100) : 0}%`, icon: 'fa-chart-bar', color: '#059669' },
          { label: '2분기 (4~6월)', val: fmtM(qTotals[2])+'원', sub: `전체의 ${grandTotal > 0 ? Math.round(qTotals[2]/grandTotal*100) : 0}%`, icon: 'fa-chart-bar', color: '#d97706' },
          { label: '3·4분기 합계', val: fmtM(qTotals[3]+qTotals[4])+'원', sub: `전체의 ${grandTotal > 0 ? Math.round((qTotals[3]+qTotals[4])/grandTotal*100) : 0}%`, icon: 'fa-chart-bar', color: '#7c3aed' },
        ].map(k => `
          <div class="bg-white rounded-xl border border-gray-100 shadow-sm p-4">
            <div class="flex items-center gap-2 mb-2">
              <i class="fas ${k.icon} text-sm" style="color:${k.color}"></i>
              <span class="text-xs text-gray-500">${k.label}</span>
            </div>
            <div class="text-lg font-bold" style="color:${k.color}">${k.val}</div>
            <div class="text-xs text-gray-400 mt-0.5">${k.sub}</div>
          </div>
        `).join('')}
      </div>

      <!-- 월별 납품 현황 -->
      <div class="bg-white rounded-xl border border-gray-100 shadow-sm p-4">
        <h3 class="font-bold text-gray-700 text-sm mb-3">
          <i class="fas fa-table text-indigo-500 mr-1"></i>${year}년 월별 납품 현황
        </h3>
        <div class="overflow-x-auto">
          <table class="w-full text-xs">
            <thead>
              <tr class="bg-gray-50 text-gray-500">
                <th class="text-left py-2 px-3">월</th>
                <th class="text-right py-2 px-3">공급가액</th>
                <th class="text-right py-2 px-3">부가세</th>
                <th class="text-right py-2 px-3">합계</th>
                <th class="text-left py-2 px-3">업체</th>
                <th class="py-2 px-3">비중 바</th>
              </tr>
            </thead>
            <tbody>
              ${Array.from({length:12}, (_,i) => i+1).map(mo => {
                const moRows = d.monthly.filter((r) => r.mo === mo)
                const moTotal = moRows.reduce((s,r) => s+Number(r.total_amount||0), 0)
                const moSupply = moRows.reduce((s,r) => s+Number(r.supply_amount||0), 0)
                const moVat = moRows.reduce((s,r) => s+Number(r.vat_amount||0), 0)
                const vendors = moRows.map((r) => r.vendor_name).join(', ')
                const pct = grandTotal > 0 ? Math.min(100, Math.round(moTotal/grandTotal*100)) : 0
                const qLabel = mo <= 3 ? '1Q' : mo <= 6 ? '2Q' : mo <= 9 ? '3Q' : '4Q'
                const qColor = mo <= 3 ? '#3b82f6' : mo <= 6 ? '#10b981' : mo <= 9 ? '#f59e0b' : '#8b5cf6'
                return `<tr class="border-b border-gray-50 ${mo%2===0?'bg-gray-50/30':''}">
                  <td class="py-2 px-3 font-medium text-gray-800">
                    ${mo}월 <span style="font-size:9px;background:${qColor}22;color:${qColor};padding:1px 4px;border-radius:4px;font-weight:700">${qLabel}</span>
                  </td>
                  <td class="py-2 px-3 text-right text-gray-600">${moSupply > 0 ? fmt(moSupply)+'원' : '-'}</td>
                  <td class="py-2 px-3 text-right text-gray-500">${moVat > 0 ? fmt(moVat)+'원' : '-'}</td>
                  <td class="py-2 px-3 text-right font-bold text-gray-900">${moTotal > 0 ? fmt(moTotal)+'원' : '-'}</td>
                  <td class="py-2 px-3 text-gray-500 text-xs max-w-xs truncate">${vendors || '-'}</td>
                  <td class="py-2 px-3">
                    <div style="display:flex;align-items:center;gap:6px">
                      <div style="background:#f3f4f6;border-radius:4px;height:8px;width:80px;overflow:hidden">
                        <div style="height:100%;width:${pct}%;background:${qColor};border-radius:4px"></div>
                      </div>
                      <span style="font-size:10px;color:#9ca3af">${pct}%</span>
                    </div>
                  </td>
                </tr>`
              }).join('')}
              <tr class="bg-indigo-50 font-bold">
                <td class="py-2 px-3 text-indigo-700">합 계</td>
                <td class="py-2 px-3 text-right text-gray-700">${fmt(d.monthly.reduce((s,r)=>s+Number(r.supply_amount||0),0))}원</td>
                <td class="py-2 px-3 text-right text-gray-700">${fmt(d.monthly.reduce((s,r)=>s+Number(r.vat_amount||0),0))}원</td>
                <td class="py-2 px-3 text-right text-indigo-700">${fmt(grandTotal)}원</td>
                <td class="py-2 px-3"></td>
                <td class="py-2 px-3 text-xs text-gray-500">100%</td>
              </tr>
            </tbody>
          </table>
        </div>
      </div>

      <!-- 분기별 업체 비교 -->
      <div class="bg-white rounded-xl border border-gray-100 shadow-sm p-4">
        <h3 class="font-bold text-gray-700 text-sm mb-3">
          <i class="fas fa-chart-bar text-purple-500 mr-1"></i>${year}년 분기별 업체 납품 비교
        </h3>
        ${d.quarterly.length === 0 ? `<div class="text-center text-gray-400 py-6 text-sm">데이터가 없습니다</div>` : `
        <div class="overflow-x-auto">
          <table class="w-full text-xs">
            <thead>
              <tr class="bg-gray-50 text-gray-500">
                <th class="text-left py-2 px-3">업체</th>
                <th class="text-right py-2 px-3">1분기 (1~3월)</th>
                <th class="text-right py-2 px-3">2분기 (4~6월)</th>
                <th class="text-right py-2 px-3">3분기 (7~9월)</th>
                <th class="text-right py-2 px-3">4분기 (10~12월)</th>
                <th class="text-right py-2 px-3">연간 합계</th>
              </tr>
            </thead>
            <tbody>
              ${(() => {
                const allVendors = [...new Set(d.quarterly.map((r) => r.vendor_name))]
                return allVendors.map((v, idx) => {
                  const qData = {1:0, 2:0, 3:0, 4:0}
                  d.quarterly.filter((r) => r.vendor_name === v).forEach((r) => {
                    qData[r.quarter] = Number(r.total_amount)||0
                  })
                  const vTotal = Object.values(qData).reduce((s,v) => s+v, 0)
                  return `<tr class="border-b border-gray-50 ${idx%2===0?'':'bg-gray-50/30'}">
                    <td class="py-2 px-3 font-medium text-gray-800">${v}</td>
                    ${[1,2,3,4].map(q => `<td class="py-2 px-3 text-right ${qData[q]>0?'text-gray-800':'text-gray-300'}">${qData[q]>0?fmt(qData[q])+'원':'-'}</td>`).join('')}
                    <td class="py-2 px-3 text-right font-bold text-indigo-600">${fmt(vTotal)}원</td>
                  </tr>`
                }).join('')
              })()}
              <tr class="bg-indigo-50 font-bold">
                <td class="py-2 px-3 text-indigo-700">합 계</td>
                ${[1,2,3,4].map(q => `<td class="py-2 px-3 text-right text-gray-700">${fmt(qTotals[q])}원</td>`).join('')}
                <td class="py-2 px-3 text-right text-indigo-700">${fmt(grandTotal)}원</td>
              </tr>
            </tbody>
          </table>
        </div>`}
      </div>

      <!-- 업체별 연간 비중 -->
      <div class="bg-white rounded-xl border border-gray-100 shadow-sm p-4">
        <h3 class="font-bold text-gray-700 text-sm mb-3">
          <i class="fas fa-truck text-blue-500 mr-1"></i>업체별 연간 납품 현황 (${year}년)
        </h3>
        ${d.vendors.length === 0 ? `<div class="text-center text-gray-400 py-6 text-sm">데이터가 없습니다</div>` : `
        <div class="overflow-x-auto">
          <table class="w-full text-xs">
            <thead>
              <tr class="bg-gray-50 text-gray-500">
                <th class="text-left py-2 px-3">업체명</th>
                <th class="text-right py-2 px-3">납품월수</th>
                <th class="text-right py-2 px-3">품목수</th>
                <th class="text-right py-2 px-3">공급가액</th>
                <th class="text-right py-2 px-3">부가세</th>
                <th class="text-right py-2 px-3">합계금액</th>
                <th class="text-right py-2 px-3">비중(%)</th>
                <th class="py-2 px-3">비중 바</th>
              </tr>
            </thead>
            <tbody>
              ${d.vendors.map((v, idx) => {
                const pct = grandTotal > 0 ? Math.round(Number(v.total_amount)/grandTotal*1000)/10 : 0
                const barColor = ['#3b82f6','#10b981','#f59e0b','#ef4444','#8b5cf6'][idx % 5]
                return `<tr class="border-b border-gray-50 ${idx%2===0?'':'bg-gray-50/30'}">
                  <td class="py-2 px-3 font-medium text-gray-800">${v.vendor_name}</td>
                  <td class="py-2 px-3 text-right text-gray-600">${v.active_months}개월</td>
                  <td class="py-2 px-3 text-right text-gray-600">${fmt(v.item_count)}종</td>
                  <td class="py-2 px-3 text-right text-gray-600">${fmt(v.supply_amount)}원</td>
                  <td class="py-2 px-3 text-right text-gray-500">${fmt(v.vat_amount)}원</td>
                  <td class="py-2 px-3 text-right font-bold text-gray-900">${fmt(v.total_amount)}원</td>
                  <td class="py-2 px-3 text-right font-bold" style="color:${barColor}">${pct}%</td>
                  <td class="py-2 px-3">
                    <div style="background:#f3f4f6;border-radius:4px;height:8px;width:80px;overflow:hidden">
                      <div style="height:100%;width:${Math.min(100,pct)}%;background:${barColor};border-radius:4px"></div>
                    </div>
                  </td>
                </tr>`
              }).join('')}
            </tbody>
          </table>
        </div>`}
      </div>

    </div>`

  } catch(e) {
    const content = document.getElementById('txAnnualContent')
    if (content) content.innerHTML = `<div class="text-center text-red-400 py-12 text-sm"><i class="fas fa-exclamation-triangle mr-2"></i>데이터 로드 실패: ${e.message}</div>`
  }
}

window.txExportAnnualExcel = async function() {
  const d = window._txAnnualData
  if (!d) { showToast('먼저 조회해주세요', 'warning'); return }

  const year     = d.year
  const hospName = TXState.selectedHospitalName || window._adminHospitalName || ''
  const nowStr   = new Date().toLocaleString('ko-KR')
  const wb = XLSX.utils.book_new()

  const FMT_NUM = '#,##0'
  const FMT_WON = '#,##0\"원\"'
  const FMT_PCT = '0.0\"%\"'

  const FONT_BASE  = { name: '맑은 고딕', sz: 10 }
  const FONT_BOLD  = { name: '맑은 고딕', sz: 10, bold: true }
  const FONT_TITLE = { name: '맑은 고딕', sz: 16, bold: true, color: { rgb: '1E3A5F' } }
  const FONT_SUB   = { name: '맑은 고딕', sz: 10, italic: true, color: { rgb: '555555' } }
  const FONT_HDR   = { name: '맑은 고딕', sz: 10, bold: true, color: { rgb: 'FFFFFF' } }
  const FONT_SEC   = { name: '맑은 고딕', sz: 11, bold: true, color: { rgb: '1E3A5F' } }
  const FONT_Q     = { name: '맑은 고딕', sz: 10, bold: true, color: { rgb: 'FFFFFF' } }

  const BG_TITLE = { fgColor: { rgb: '1E3A5F' } }
  const BG_HDR   = { fgColor: { rgb: '2E6DA4' } }
  const BG_SEC   = { fgColor: { rgb: 'EBF3FB' } }
  const BG_SUM   = { fgColor: { rgb: 'FFF3CD' } }
  const BG_SUM2  = { fgColor: { rgb: 'E8F5E9' } }
  const BG_META  = { fgColor: { rgb: 'F0F7FF' } }
  const BG_ODD   = { fgColor: { rgb: 'FAFAFA' } }
  const BG_EVEN  = { fgColor: { rgb: 'FFFFFF' } }
  const BG_Q1    = { fgColor: { rgb: '1565C0' } }
  const BG_Q2    = { fgColor: { rgb: '2E7D32' } }
  const BG_Q3    = { fgColor: { rgb: 'E65100' } }
  const BG_Q4    = { fgColor: { rgb: '6A1B9A' } }

  const BD_THIN  = { style: 'thin',   color: { rgb: 'CCCCCC' } }
  const BD_MED   = { style: 'medium', color: { rgb: '2E6DA4' } }
  const bdr  = (t,r,b,l) => ({ top:t, right:r, bottom:b, left:l })
  const BD_ALL_THIN = bdr(BD_THIN, BD_THIN, BD_THIN, BD_THIN)
  const BD_ALL_MED  = bdr(BD_MED,  BD_MED,  BD_MED,  BD_MED)

  const AL_CC = { horizontal:'center', vertical:'center' }
  const AL_LC = { horizontal:'left',   vertical:'center' }
  const AL_RC = { horizontal:'right',  vertical:'center' }

  const ST  = (font, fill, align, border) => ({ font:font||FONT_BASE, fill:fill||{}, alignment:align||AL_LC, border:border||BD_ALL_THIN })
  const CS  = (v, s) => ({ v, s })
  const CN  = (v, fmt, s) => ({ v: Number(v)||0, t:'n', z: fmt||FMT_NUM, s })
  const mrg = (rs,re,cs,ce) => ({ s:{r:rs,c:cs}, e:{r:re,c:ce} })

  const S_TITLE  = ST(FONT_TITLE, BG_TITLE, AL_CC, BD_ALL_MED)
  const S_META   = ST(FONT_SUB,  BG_META,  AL_LC, BD_ALL_THIN)
  const S_HDR    = ST(FONT_HDR,  BG_HDR,   AL_CC, BD_ALL_MED)
  const S_SEC    = ST(FONT_SEC,  BG_SEC,   AL_LC, bdr(BD_MED,BD_THIN,BD_THIN,BD_MED))
  const S_SUM    = ST(FONT_BOLD, BG_SUM,   AL_LC, BD_ALL_MED)
  const S_SUM_N  = (fmt) => ({ ...ST(FONT_BOLD, BG_SUM, AL_RC, BD_ALL_MED), z:fmt||FMT_NUM })
  const S_SUM2   = ST(FONT_BOLD, BG_SUM2,  AL_LC, BD_ALL_MED)
  const S_SUM2_N = (fmt) => ({ ...ST(FONT_BOLD, BG_SUM2, AL_RC, BD_ALL_MED), z:fmt||FMT_NUM })
  const S_BODY   = (odd) => ST(FONT_BASE, odd?BG_ODD:BG_EVEN, AL_LC, BD_ALL_THIN)
  const S_BODY_N = (odd,fmt) => ({ ...ST(FONT_BASE, odd?BG_ODD:BG_EVEN, AL_RC, BD_ALL_THIN), z:fmt||FMT_NUM })
  const S_BODY_C = (odd) => ST(FONT_BASE, odd?BG_ODD:BG_EVEN, AL_CC, BD_ALL_THIN)
  const S_BOLD   = ST(FONT_BOLD, BG_ODD, AL_LC, BD_ALL_THIN)
  const S_BOLD_N = (fmt) => ({ ...ST(FONT_BOLD, BG_ODD, AL_RC, BD_ALL_THIN), z:fmt||FMT_NUM })
  const S_EMPTY  = { font:FONT_BASE, fill:{}, border:{}, alignment:AL_LC }
  const S_Q      = (bg) => ST(FONT_Q, bg, AL_CC, BD_ALL_MED)
  const S_Q_N    = (bg,fmt) => ({ ...ST(FONT_Q, bg, AL_RC, BD_ALL_MED), z:fmt||FMT_NUM })

  const makeWS = (rows, cols, merges) => {
    const ws = {}
    let maxC = 0
    rows.forEach((row, r) => {
      row.forEach((cell, c) => {
        if (c > maxC) maxC = c
        if (cell == null) return
        const ref = XLSX.utils.encode_cell({r, c})
        if (typeof cell === 'object' && 'v' in cell) {
          ws[ref] = { v: cell.v, t: cell.t||(typeof cell.v==='number'?'n':'s'), z: cell.z, s: cell.s }
        } else {
          ws[ref] = { v: cell, t: typeof cell==='number'?'n':'s', s: {} }
        }
      })
    })
    ws['!ref'] = XLSX.utils.encode_range({s:{r:0,c:0}, e:{r:rows.length-1, c:maxC}})
    if (cols)   ws['!cols']   = cols
    if (merges) ws['!merges'] = merges
    return ws
  }

  const grandTotal = d.vendors.reduce((s, r) => s + (Number(r.total_amount)||0), 0)
  const qTotals = {1:0, 2:0, 3:0, 4:0}
  d.quarterly.forEach(r => { qTotals[r.quarter] = (qTotals[r.quarter]||0) + (Number(r.total_amount)||0) })

  showToast('보고서 생성 중...', 'info')

  // Sheet 1: 연간 요약
  ;(() => {
    const NCOL = 7
    const rows = [], merges = []
    let r = 0

    rows.push([CS(`${year}년 거래명세서 연간 분석 보고서`, S_TITLE)])
    merges.push(mrg(r,r,0,NCOL-1)); r++
    rows.push([CS(`병원: ${hospName||'-'}   |   기준연도: ${year}년   |   생성일시: ${nowStr}`, S_META)])
    merges.push(mrg(r,r,0,NCOL-1)); r++
    rows.push(Array(NCOL).fill(CS('',S_EMPTY))); r++

    rows.push([CS('【 1. 연간 총괄 요약 】', S_SEC)])
    merges.push(mrg(r,r,0,NCOL-1)); r++
    rows.push([CS('구분',S_HDR),CS('금액',S_HDR),CS('비중(%)',S_HDR),CS('전분기대비',S_HDR),CS('비고',S_HDR),CS('',S_HDR),CS('',S_HDR)]); r++
    rows.push([CS('연간 납품 총액',S_SUM),CN(grandTotal,FMT_WON,S_SUM_N(FMT_WON)),CN(100,FMT_PCT,S_SUM_N(FMT_PCT)),CS('-',{...ST(FONT_BOLD,BG_SUM,AL_CC,BD_ALL_MED)}),CS(d.vendors.length+'개 업체',S_SUM),CS('',S_SUM),CS('',S_SUM)]); r++

    const qColors=[BG_Q1,BG_Q2,BG_Q3,BG_Q4]
    const qLabels=['1분기 (1~3월)','2분기 (4~6월)','3분기 (7~9월)','4분기 (10~12월)']
    ;[1,2,3,4].forEach((q,i)=>{
      const amt=qTotals[q], pct=grandTotal>0?Math.round(amt/grandTotal*1000)/10:0
      const prevQ=q>1?qTotals[q-1]:null
      const chg=prevQ!=null&&prevQ>0?Math.round((amt-prevQ)/prevQ*1000)/10:null
      rows.push([CS(qLabels[i],S_Q(qColors[i])),CN(amt,FMT_WON,S_Q_N(qColors[i],FMT_WON)),CN(pct,FMT_PCT,S_Q_N(qColors[i],FMT_PCT)),CS(chg!=null?(chg>0?'+'+chg+'%':chg+'%'):'-',{...ST(FONT_Q,qColors[i],AL_CC,BD_ALL_MED)}),CS('',S_Q(qColors[i])),CS('',S_Q(qColors[i])),CS('',S_Q(qColors[i]))]); r++
    })

    rows.push(Array(NCOL).fill(CS('',S_EMPTY))); r++
    rows.push([CS('【 2. 업체별 연간 납품 현황 】',S_SEC)]); merges.push(mrg(r,r,0,NCOL-1)); r++
    rows.push([CS('업체명',S_HDR),CS('납품월수',S_HDR),CS('품목수',S_HDR),CS('공급가액',S_HDR),CS('부가세',S_HDR),CS('합계금액',S_HDR),CS('비중(%)',S_HDR)]); r++

    let odd=true
    d.vendors.forEach(v=>{
      const amt=Number(v.total_amount)||0, pct=grandTotal>0?Math.round(amt/grandTotal*1000)/10:0
      rows.push([CS(v.vendor_name||'-',S_BODY(odd)),CN(v.active_months||0,'#,##0',S_BODY_C(odd)),CN(v.item_count||0,'#,##0',S_BODY_C(odd)),CN(Number(v.supply_amount)||0,FMT_WON,S_BODY_N(odd,FMT_WON)),CN(Number(v.vat_amount)||0,FMT_WON,S_BODY_N(odd,FMT_WON)),CN(amt,FMT_WON,S_BODY_N(odd,FMT_WON)),CN(pct,FMT_PCT,S_BODY_N(odd,FMT_PCT))]); odd=!odd; r++
    })
    rows.push([CS('합  계',S_SUM2),CS('-',{...ST(FONT_BOLD,BG_SUM2,AL_CC,BD_ALL_MED)}),CN(d.vendors.reduce((s,v)=>s+(Number(v.item_count)||0),0),'#,##0',S_SUM2_N('#,##0')),CN(d.vendors.reduce((s,v)=>s+(Number(v.supply_amount)||0),0),FMT_WON,S_SUM2_N(FMT_WON)),CN(d.vendors.reduce((s,v)=>s+(Number(v.vat_amount)||0),0),FMT_WON,S_SUM2_N(FMT_WON)),CN(grandTotal,FMT_WON,S_SUM2_N(FMT_WON)),CN(100,FMT_PCT,S_SUM2_N(FMT_PCT))]); r++

    const ws1=makeWS(rows,[{wch:22},{wch:10},{wch:9},{wch:16},{wch:14},{wch:16},{wch:10}],merges)
    ws1['!rows']=[{hpx:32},{hpx:20},{hpx:8}]
    XLSX.utils.book_append_sheet(wb,ws1,'①연간요약')
  })()

  // Sheet 2: 월별 납품 현황
  ;(() => {
    const NCOL=8, rows=[], merges=[]
    let r=0
    const moTotals={}
    d.monthly.forEach(rec=>{
      if(!moTotals[rec.mo]) moTotals[rec.mo]={supply:0,vat:0,total:0,vendors:[]}
      moTotals[rec.mo].supply+=Number(rec.supply_amount)||0
      moTotals[rec.mo].vat+=Number(rec.vat_amount)||0
      moTotals[rec.mo].total+=Number(rec.total_amount)||0
      if(!moTotals[rec.mo].vendors.includes(rec.vendor_name)) moTotals[rec.mo].vendors.push(rec.vendor_name)
    })
    const activeMonths=Object.values(moTotals).filter(m=>m.total>0).length

    rows.push([CS(`${year}년 월별 납품 현황`,S_TITLE)]); merges.push(mrg(r,r,0,NCOL-1)); r++
    rows.push([CS(`병원: ${hospName||'-'}   |   납품 실적 ${activeMonths}개월   |   생성일시: ${nowStr}`,S_META)]); merges.push(mrg(r,r,0,NCOL-1)); r++
    rows.push(Array(NCOL).fill(CS('',S_EMPTY))); r++
    rows.push([CS('월',S_HDR),CS('분기',S_HDR),CS('공급가액',S_HDR),CS('부가세',S_HDR),CS('합계금액',S_HDR),CS('업체수',S_HDR),CS('업체명',S_HDR),CS('비중(%)',S_HDR)]); r++

    const qBgArr=[BG_Q1,BG_Q1,BG_Q1,BG_Q2,BG_Q2,BG_Q2,BG_Q3,BG_Q3,BG_Q3,BG_Q4,BG_Q4,BG_Q4]
    Array.from({length:12},(_,i)=>{
      const mo=i+1, m=moTotals[mo]||{supply:0,vat:0,total:0,vendors:[]}, q=mo<=3?'1Q':mo<=6?'2Q':mo<=9?'3Q':'4Q'
      const pct=grandTotal>0?Math.round(m.total/grandTotal*1000)/10:0, bg=qBgArr[i], odd=i%2===0
      rows.push([CS(`${mo}월`,{...ST(FONT_Q,bg,AL_CC,BD_ALL_MED)}),CS(q,{...ST(FONT_Q,bg,AL_CC,BD_ALL_MED)}),CN(m.supply,FMT_WON,S_BODY_N(odd,FMT_WON)),CN(m.vat,FMT_WON,S_BODY_N(odd,FMT_WON)),CN(m.total,FMT_WON,m.total>0?S_BOLD_N(FMT_WON):S_BODY_N(odd,FMT_WON)),CN(m.vendors.length,'#,##0',S_BODY_C(odd)),CS(m.vendors.join(', '),S_BODY(odd)),CN(pct,FMT_PCT,S_BODY_N(odd,FMT_PCT))]); r++
    })
    rows.push([CS('합  계',S_SUM2),CS('',S_SUM2),CN(d.monthly.reduce((s,x)=>s+(Number(x.supply_amount)||0),0),FMT_WON,S_SUM2_N(FMT_WON)),CN(d.monthly.reduce((s,x)=>s+(Number(x.vat_amount)||0),0),FMT_WON,S_SUM2_N(FMT_WON)),CN(grandTotal,FMT_WON,S_SUM2_N(FMT_WON)),CS('',S_SUM2),CS('',S_SUM2),CN(100,FMT_PCT,S_SUM2_N(FMT_PCT))]); merges.push(mrg(r,r,0,1)); r++

    const ws2=makeWS(rows,[{wch:8},{wch:6},{wch:16},{wch:14},{wch:16},{wch:7},{wch:34},{wch:10}],merges)
    ws2['!rows']=[{hpx:28},{hpx:18},{hpx:8}]
    XLSX.utils.book_append_sheet(wb,ws2,'②월별납품현황')
  })()

  // Sheet 3: 분기별 업체 비교
  ;(() => {
    const allVendorNames=[...new Set(d.quarterly.map(r=>r.vendor_name))], NCOL=6, rows=[], merges=[]
    let r=0

    rows.push([CS(`${year}년 분기별 업체 납품 비교`,S_TITLE)]); merges.push(mrg(r,r,0,NCOL-1)); r++
    rows.push([CS(`병원: ${hospName||'-'}   |   업체 ${allVendorNames.length}개   |   생성일시: ${nowStr}`,S_META)]); merges.push(mrg(r,r,0,NCOL-1)); r++
    rows.push(Array(NCOL).fill(CS('',S_EMPTY))); r++
    rows.push([CS('업체명',S_HDR),CS('1분기 (1~3월)',S_Q(BG_Q1)),CS('2분기 (4~6월)',S_Q(BG_Q2)),CS('3분기 (7~9월)',S_Q(BG_Q3)),CS('4분기 (10~12월)',S_Q(BG_Q4)),CS('연간 합계',S_HDR)]); r++

    let odd=true
    allVendorNames.forEach(vname=>{
      const qData={1:0,2:0,3:0,4:0}
      d.quarterly.filter(x=>x.vendor_name===vname).forEach(x=>{qData[x.quarter]=Number(x.total_amount)||0})
      const vTotal=Object.values(qData).reduce((s,v)=>s+v,0)
      rows.push([CS(vname,S_BODY(odd)),CN(qData[1],FMT_WON,S_BODY_N(odd,FMT_WON)),CN(qData[2],FMT_WON,S_BODY_N(odd,FMT_WON)),CN(qData[3],FMT_WON,S_BODY_N(odd,FMT_WON)),CN(qData[4],FMT_WON,S_BODY_N(odd,FMT_WON)),CN(vTotal,FMT_WON,S_BOLD_N(FMT_WON))]); odd=!odd; r++
    })
    rows.push([CS('합  계',S_SUM2),CN(qTotals[1],FMT_WON,S_Q_N(BG_Q1,FMT_WON)),CN(qTotals[2],FMT_WON,S_Q_N(BG_Q2,FMT_WON)),CN(qTotals[3],FMT_WON,S_Q_N(BG_Q3,FMT_WON)),CN(qTotals[4],FMT_WON,S_Q_N(BG_Q4,FMT_WON)),CN(grandTotal,FMT_WON,S_SUM2_N(FMT_WON))]); r++

    const ws3=makeWS(rows,[{wch:22},{wch:16},{wch:16},{wch:16},{wch:16},{wch:16}],merges)
    ws3['!rows']=[{hpx:28},{hpx:18},{hpx:8}]
    XLSX.utils.book_append_sheet(wb,ws3,'③분기별업체비교')
  })()

  const fname=`거래명세서_연간분석보고서_${hospName||'병원'}_${year}년.xlsx`
  XLSX.writeFile(wb,fname)
  showToast(`✅ ${year}년 연간 보고서 다운로드: ${fname} (3개 시트)`,'success')
}

// ── TAB 5: 식재료 단가 분석 ──────────────────────────────────────────────
async function txRenderIngredientTab(container) {
  const authH = { Authorization: `Bearer ${localStorage.getItem('token')}` }
  const hospitalId = TXState.selectedHospitalId || window._adminHospitalId || ''
  const hParam = hospitalId ? `?hospital_id=${hospitalId}` : ''
  const hParamAmp = hospitalId ? `&hospital_id=${hospitalId}` : ''

  container.innerHTML = `
  <div class="space-y-4">
    <div class="bg-white rounded-xl shadow-sm border border-gray-100 p-4 flex flex-wrap gap-3 items-center justify-between">
      <div>
        <h2 class="text-base font-bold text-gray-800 flex items-center gap-2">
          <i class="fas fa-leaf text-green-500"></i>주요 식재료 단가 분석
        </h2>
        <p class="text-xs text-gray-400 mt-0.5">거래명세서 발주 데이터 기반 · 수동 입력 병행</p>
      </div>
      <div class="flex gap-2">
        <button onclick="txIngSwitchSubTab('tx')" id="txIngSubTab-tx"
          class="px-3 py-1.5 rounded-lg text-sm font-medium bg-green-600 text-white">
          <i class="fas fa-chart-line mr-1"></i>단가 추이 분석
        </button>
        <button onclick="txIngSwitchSubTab('manual')" id="txIngSubTab-manual"
          class="px-3 py-1.5 rounded-lg text-sm font-medium bg-gray-100 text-gray-600">
          <i class="fas fa-store mr-1"></i>주요품목 분석
        </button>
      </div>
    </div>
    <div id="txIngSubContent">
      <div class="text-center text-gray-400 py-16">
        <i class="fas fa-spinner fa-spin text-3xl mb-3 block"></i>데이터 로딩 중...
      </div>
    </div>
  </div>`

  // 기본: 거래명세서 분석 탭
  await txIngLoadTxTab(authH, hParam, hParamAmp)
}

window.txIngSwitchSubTab = async function(tab) {
  const authH = { Authorization: `Bearer ${localStorage.getItem('token')}` }
  const hospitalId = TXState.selectedHospitalId || window._adminHospitalId || ''
  const hParam = hospitalId ? `?hospital_id=${hospitalId}` : ''
  const hParamAmp = hospitalId ? `&hospital_id=${hospitalId}` : ''

  // 버튼 스타일 갱신
  ;['tx','manual'].forEach(t => {
    const btn = document.getElementById(`txIngSubTab-${t}`)
    if (!btn) return
    if (t === tab) {
      btn.className = 'px-3 py-1.5 rounded-lg text-sm font-medium bg-green-600 text-white'
    } else {
      btn.className = 'px-3 py-1.5 rounded-lg text-sm font-medium bg-gray-100 text-gray-600'
    }
  })

  if (tab === 'tx') {
    await txIngLoadTxTab(authH, hParam, hParamAmp)
  } else {
    await txIngLoadManualTab(authH, hospitalId)
  }
}

// ── 거래명세서 기반 식재료 단가 분석 탭 ────────────────────────
async function txIngLoadTxTab(authH, hParam, hParamAmp) {
  const sub = document.getElementById('txIngSubContent')
  if (!sub) return
  sub.innerHTML = `<div class="text-center text-gray-400 py-10"><i class="fas fa-spinner fa-spin text-2xl"></i></div>`

  try {
    // 병렬 로드: Top 품목, 월별 예산 비교, 업체 목록, 단가 추이
    const [topRes, budgetRes, vendorRes, trendRes] = await Promise.all([
      axios.get(`/api/transaction/invoice/top-items${hParam}`, { headers: authH }),
      axios.get(`/api/transaction/invoice/monthly-budget-compare${hParam}${hParam ? '&' : '?'}months=6`, { headers: authH })
        .catch(() => ({ data: { ok: false, data: [] } })),
      axios.get(`/api/transaction/invoice/vendor-list${hParam}`, { headers: authH })
        .catch(() => ({ data: { ok: true, data: [] } })),
      axios.get(`/api/transaction/invoice/ingredient-price-trend${hParam}${hParam ? '&' : '?'}period=monthly&months=12`, { headers: authH })
        .catch(() => ({ data: { ok: true, data: {} } }))
    ])

    const topItems = topRes.data.data || []
    const budgetData = budgetRes.data.data || []
    const vendorList = (vendorRes.data.data || []).map(v => v.vendor_name)
    const trendData = trendRes.data.data || {}

    // 선택된 품목 (기본: Top12)
    const defaultSelected = topItems.slice(0, 12).map(i => i.item_name)
    window._txIngSelectedItems = window._txIngSelectedItems || defaultSelected

    const fmt = v => (Number(v)||0).toLocaleString()
    const fmtK = v => v >= 10000 ? Math.round(v/10000)+'만' : fmt(v)

    // 12종 식재료 기본 목록 (단가 추이 그래프용)
    const MAIN_INGREDIENTS = ['쌀','닭고기','돼지고기','쇠고기','두부','계란','양파','감자','당근','배추','대파','마늘']

    // 단가 추이 그래프 데이터 정리
    const trendIngNames = Object.keys(trendData).filter(k => {
      const arr = trendData[k] || []
      return arr.length > 0 && arr.some(r => Number(r.avg_price) > 0)
    })

    // 업체별 색상
    const vendorColors = ['#3b82f6','#10b981','#f59e0b','#ef4444','#8b5cf6','#06b6d4','#f97316','#84cc16']

    sub.innerHTML = `
    <div class="space-y-4">

      <!-- ⓪ 주요 식재료 단가 추이 그래프 -->
      <div class="bg-white rounded-xl border border-gray-100 shadow-sm p-4">
        <div class="flex items-center justify-between mb-3 flex-wrap gap-2">
          <h3 class="font-bold text-gray-700 text-sm">
            <i class="fas fa-chart-line text-green-500 mr-1"></i>주요 식재료 단가 추이
            <span class="text-xs font-normal text-gray-400 ml-1">(명세서 날짜 기준 · 업체별)</span>
          </h3>
          <div class="flex items-center gap-2">
            <select id="txTrendPeriod" class="border border-gray-200 rounded px-2 py-1 text-xs" onchange="txLoadIngTrend()">
              <option value="monthly">월별</option>
              <option value="weekly">주별</option>
            </select>
            <select id="txTrendVendor" class="border border-gray-200 rounded px-2 py-1 text-xs" onchange="txLoadIngTrend()">
              <option value="">전체 업체</option>
              ${vendorList.map(v => `<option value="${v}">${v}</option>`).join('')}
            </select>
            <select id="txTrendIngredient" class="border border-gray-200 rounded px-2 py-1 text-xs" onchange="txLoadIngTrend()">
              ${MAIN_INGREDIENTS.map((n,i) => `<option value="${n}" ${i===4?'selected':''}>${n}</option>`).join('')}
            </select>
          </div>
        </div>
        <div id="txTrendChartArea" style="min-height:220px">
          ${trendIngNames.length === 0 ?
            `<div class="text-center text-gray-400 py-12 text-sm"><i class="fas fa-chart-line text-3xl mb-3 block opacity-30"></i>거래명세서를 업로드하면 단가 추이가 표시됩니다</div>` :
            `<canvas id="txTrendChart" style="max-height:220px"></canvas>`
          }
        </div>
        <!-- 단가 요약 카드 -->
        <div id="txTrendSummary" class="mt-3 grid grid-cols-2 sm:grid-cols-4 gap-2">
        </div>
      </div>

      <!-- ① 품목 선택 패널 -->
      <div class="bg-white rounded-xl border border-gray-100 shadow-sm p-4">
        <div class="flex items-center justify-between mb-3">
          <h3 class="font-bold text-gray-700 text-sm">
            <i class="fas fa-list-check text-green-500 mr-1"></i>
            주요 품목 선택 <span class="text-xs font-normal text-gray-400">(발주량 기준 자동 선정 · 수동 조정 가능)</span>
          </h3>
          <div class="flex gap-2">
            <button onclick="txIngSelectAll()" class="text-xs text-blue-500 hover:underline">전체선택</button>
            <button onclick="txIngSelectTop12()" class="text-xs text-green-600 hover:underline font-medium">Top12 자동</button>
            <button onclick="txIngClearAll()" class="text-xs text-gray-400 hover:underline">전체해제</button>
          </div>
        </div>
        <div class="flex flex-wrap gap-2" id="txIngItemChips">
          ${topItems.slice(0, 20).map((it, i) => {
            const isSelected = window._txIngSelectedItems.includes(it.item_name)
            return `<button id="txIngChip-${i}" onclick="txIngToggleItem('${it.item_name.replace(/'/g,"\\'")}',${i})"
              class="px-3 py-1 rounded-full text-xs font-medium border transition-all ${isSelected ? 'bg-green-500 text-white border-green-500' : 'bg-white text-gray-600 border-gray-200 hover:border-green-400'}"
              title="평균단가: ${fmt(it.avg_price)}원 | 발주량: ${fmt(it.total_qty)} | 총금액: ${fmtK(it.total_amount)}">
              ${it.item_name}
              <span class="ml-1 opacity-70">${fmtK(it.total_amount)}</span>
            </button>`
          }).join('')}
        </div>
        ${topItems.length > 20 ? `<div class="mt-2">
          <input type="text" id="txIngCustomItem" placeholder="직접 품목 추가..."
            class="border border-gray-200 rounded-lg px-3 py-1.5 text-xs w-full focus:ring-2 focus:ring-green-400 focus:outline-none"
            onkeydown="if(event.key==='Enter') txIngAddCustomItem()">
        </div>` : ''}
      </div>

      <!-- ② 발주 이력 상세 테이블 -->
      <div class="bg-white rounded-xl border border-gray-100 shadow-sm">
        <div class="px-4 py-3 border-b border-gray-100 flex items-center justify-between">
          <h3 class="font-bold text-gray-700 text-sm">
            <i class="fas fa-history text-blue-500 mr-1"></i>발주 이력 상세
            <span class="text-xs font-normal text-gray-400 ml-1">(품목명 · 발주량 · 금액 · 날짜 · 업체)</span>
          </h3>
          <button onclick="txIngLoadHistory()" class="text-xs bg-blue-50 text-blue-600 px-3 py-1 rounded-lg hover:bg-blue-100">
            <i class="fas fa-search mr-1"></i>조회
          </button>
        </div>
        <div id="txIngHistoryArea" class="p-4">
          <div class="text-center text-gray-400 py-6 text-sm">
            품목을 선택하고 <strong>조회</strong> 버튼을 클릭하세요
          </div>
        </div>
      </div>

      <!-- ③ 월별 예산 대비 사용량 -->
      <div class="bg-white rounded-xl border border-gray-100 shadow-sm p-4">
        <h3 class="font-bold text-gray-700 text-sm mb-3">
          <i class="fas fa-chart-bar text-orange-500 mr-1"></i>월별 전체 예산 대비 사용량
          <span class="text-xs font-normal text-gray-400 ml-1">(최근 6개월)</span>
        </h3>
        <div id="txIngBudgetArea">
          ${budgetData.length === 0 ? `
          <div class="text-center text-gray-400 py-6 text-sm">거래명세서 데이터가 없습니다. 명세서를 업로드해 주세요.</div>` : `
          <div class="overflow-x-auto">
            <table class="w-full text-sm">
              <thead>
                <tr class="bg-gray-50 text-xs text-gray-500">
                  <th class="text-left py-2 px-3">기간</th>
                  <th class="text-right py-2 px-3">예산</th>
                  <th class="text-right py-2 px-3">발주금액</th>
                  <th class="text-right py-2 px-3">사용률</th>
                  <th class="text-center py-2 px-3">업체수</th>
                  <th class="text-right py-2 px-3">품목수</th>
                  <th class="py-2 px-3">예산 소진 바</th>
                </tr>
              </thead>
              <tbody>
                ${budgetData.map((r, i) => {
                  const pct = r.usage_pct
                  const barColor = pct === null ? '#9ca3af' : pct >= 100 ? '#ef4444' : pct >= 80 ? '#f59e0b' : '#10b981'
                  const barW = pct !== null ? Math.min(100, pct) : 0
                  return `<tr class="border-b border-gray-50 ${i%2===0?'':'bg-gray-50/30'}">
                    <td class="py-2 px-3 font-medium text-gray-800">${r.year}년 ${r.month}월</td>
                    <td class="py-2 px-3 text-right text-gray-500">${r.total_budget > 0 ? fmtK(r.total_budget) : '-'}</td>
                    <td class="py-2 px-3 text-right font-bold text-gray-900">${fmtK(r.tx_total)}</td>
                    <td class="py-2 px-3 text-right">
                      ${pct !== null ? `<span style="color:${barColor};font-weight:700">${pct}%</span>` : '<span class="text-gray-400">-</span>'}
                    </td>
                    <td class="py-2 px-3 text-center text-gray-500">${r.vendor_count}개</td>
                    <td class="py-2 px-3 text-right text-gray-500">${r.item_count}건</td>
                    <td class="py-2 px-3">
                      <div style="background:#f3f4f6;border-radius:6px;height:12px;overflow:hidden;min-width:80px">
                        <div style="height:100%;width:${barW}%;background:${barColor};border-radius:6px;transition:width 0.3s"></div>
                      </div>
                    </td>
                  </tr>`
                }).join('')}
              </tbody>
            </table>
          </div>
          <div class="mt-3 grid grid-cols-3 gap-3">
            ${(() => {
              const hasData = budgetData.filter(r => r.tx_total > 0)
              const avgPct  = hasData.filter(r=>r.usage_pct!==null).reduce((s,r,_,a) => s + r.usage_pct/a.length, 0)
              const maxMon  = hasData.sort((a,b) => b.tx_total - a.tx_total)[0]
              const minMon  = hasData.filter(r=>r.tx_total>0).sort((a,b) => a.tx_total - b.tx_total)[0]
              return [
                { label: '평균 예산 사용률', val: hasData.some(r=>r.usage_pct!==null) ? avgPct.toFixed(1)+'%' : '-', color: '#f59e0b' },
                { label: '최고 발주월', val: maxMon ? `${maxMon.year}/${maxMon.month}월 ${fmtK(maxMon.tx_total)}` : '-', color: '#3b82f6' },
                { label: '최저 발주월', val: minMon ? `${minMon.year}/${minMon.month}월 ${fmtK(minMon.tx_total)}` : '-', color: '#10b981' },
              ].map(k => `<div class="bg-gray-50 rounded-lg p-3 text-center">
                <div class="text-xs text-gray-400">${k.label}</div>
                <div class="text-sm font-bold mt-1" style="color:${k.color}">${k.val}</div>
              </div>`).join('')
            })()}
          </div>`}
        </div>
      </div>

      <!-- ④ 업체별 단가 비교 (선택된 품목) -->
      <div class="bg-white rounded-xl border border-gray-100 shadow-sm p-4">
        <h3 class="font-bold text-gray-700 text-sm mb-3">
          <i class="fas fa-balance-scale text-purple-500 mr-1"></i>업체별 단가 비교
          <span class="text-xs font-normal text-gray-400 ml-1">(선택된 품목 기준)</span>
        </h3>
        <div id="txIngVendorCompare" class="text-center text-gray-400 py-4 text-sm">
          품목 선택 후 조회 버튼을 눌러주세요
        </div>
      </div>

    </div>`

    // 선택 상태 저장
    window._txIngTopItems = topItems
    window._txIngAuthH = authH
    window._txIngHParamAmp = hParamAmp
    window._txIngTrendData = trendData
    window._txIngVendorList = vendorList
    window._txIngHParam = hParam

    // 초기 그래프 렌더링 (계란 기본 선택)
    if (trendIngNames.length > 0) {
      setTimeout(() => txRenderTrendChart(trendData, '계란', '', 'monthly', vendorList), 100)
    }

  } catch(e) {
    const sub = document.getElementById('txIngSubContent')
    if (sub) sub.innerHTML = `<div class="bg-white rounded-xl p-8 text-center text-red-500">
      <i class="fas fa-exclamation-triangle mr-2"></i>데이터 로드 실패: ${e.message}
    </div>`
  }
}

window.txIngToggleItem = function(itemName, idx) {
  if (!window._txIngSelectedItems) window._txIngSelectedItems = []
  const i = window._txIngSelectedItems.indexOf(itemName)
  if (i >= 0) {
    window._txIngSelectedItems.splice(i, 1)
  } else {
    window._txIngSelectedItems.push(itemName)
  }
  const btn = document.getElementById(`txIngChip-${idx}`)
  if (btn) {
    const isSelected = window._txIngSelectedItems.includes(itemName)
    btn.className = `px-3 py-1 rounded-full text-xs font-medium border transition-all ${isSelected ? 'bg-green-500 text-white border-green-500' : 'bg-white text-gray-600 border-gray-200 hover:border-green-400'}`
  }
}

window.txIngSelectAll = function() {
  const items = window._txIngTopItems || []
  window._txIngSelectedItems = items.slice(0,20).map(i => i.item_name)
  document.querySelectorAll('[id^="txIngChip-"]').forEach(btn => {
    btn.className = 'px-3 py-1 rounded-full text-xs font-medium border transition-all bg-green-500 text-white border-green-500'
  })
}

window.txIngSelectTop12 = function() {
  const items = window._txIngTopItems || []
  window._txIngSelectedItems = items.slice(0,12).map(i => i.item_name)
  items.slice(0,20).forEach((it, i) => {
    const btn = document.getElementById(`txIngChip-${i}`)
    if (!btn) return
    const isSelected = i < 12
    btn.className = `px-3 py-1 rounded-full text-xs font-medium border transition-all ${isSelected ? 'bg-green-500 text-white border-green-500' : 'bg-white text-gray-600 border-gray-200 hover:border-green-400'}`
  })
}

window.txIngClearAll = function() {
  window._txIngSelectedItems = []
  document.querySelectorAll('[id^="txIngChip-"]').forEach(btn => {
    btn.className = 'px-3 py-1 rounded-full text-xs font-medium border transition-all bg-white text-gray-600 border-gray-200 hover:border-green-400'
  })
}

window.txIngAddCustomItem = function() {
  const input = document.getElementById('txIngCustomItem')
  const val = input?.value?.trim()
  if (!val) return
  if (!window._txIngSelectedItems) window._txIngSelectedItems = []
  if (!window._txIngSelectedItems.includes(val)) {
    window._txIngSelectedItems.push(val)
    // 칩 추가
    const chips = document.getElementById('txIngItemChips')
    if (chips) {
      const idx = Date.now()
      chips.insertAdjacentHTML('beforeend', `
        <button id="txIngChip-custom-${idx}" onclick="txIngRemoveCustom('${val.replace(/'/g,"\\'")}','custom-${idx}')"
          class="px-3 py-1 rounded-full text-xs font-medium border transition-all bg-green-500 text-white border-green-500">
          ${val} <span class="ml-1">✕</span>
        </button>`)
    }
  }
  if (input) input.value = ''
}

window.txIngRemoveCustom = function(itemName, idx) {
  if (window._txIngSelectedItems) {
    const i = window._txIngSelectedItems.indexOf(itemName)
    if (i >= 0) window._txIngSelectedItems.splice(i, 1)
  }
  document.getElementById(`txIngChip-${idx}`)?.remove()
}

// ── 단가 추이 그래프 렌더링 ──────────────────────────────────────────
window.txLoadIngTrend = async function() {
  const period = document.getElementById('txTrendPeriod')?.value || 'monthly'
  const vendor = document.getElementById('txTrendVendor')?.value || ''
  const ingName = document.getElementById('txTrendIngredient')?.value || '계란'
  const authH = window._txIngAuthH || { Authorization: `Bearer ${localStorage.getItem('token')}` }
  const hParam = window._txIngHParam || ''

  const area = document.getElementById('txTrendChartArea')
  if (area) area.innerHTML = `<div class="text-center text-gray-400 py-8"><i class="fas fa-spinner fa-spin"></i></div>`

  try {
    const vendorQ = vendor ? `&vendor_name=${encodeURIComponent(vendor)}` : ''
    const res = await axios.get(
      `/api/transaction/invoice/ingredient-price-trend${hParam}${hParam?'&':'?'}period=${period}&months=12&item_names=${encodeURIComponent(ingName)}${vendorQ}`,
      { headers: authH }
    )
    const data = res.data.data || {}
    const vendorList = window._txIngVendorList || []
    txRenderTrendChart(data, ingName, vendor, period, vendorList)
  } catch(e) {
    const area = document.getElementById('txTrendChartArea')
    if (area) area.innerHTML = `<div class="text-center text-red-400 py-8 text-sm">조회 실패: ${e.message}</div>`
  }
}

function txRenderTrendChart(trendData, ingName, filterVendor, period, vendorList) {
  const area = document.getElementById('txTrendChartArea')
  const summaryArea = document.getElementById('txTrendSummary')
  if (!area) return

  const rows = trendData[ingName] || []
  if (rows.length === 0) {
    area.innerHTML = `<div class="text-center text-gray-400 py-10 text-sm">
      <i class="fas fa-info-circle mr-1"></i><strong>${ingName}</strong> 단가 데이터가 없습니다. 거래명세서를 업로드해 주세요.
    </div>`
    if (summaryArea) summaryArea.innerHTML = ''
    return
  }

  // 업체별 그룹화
  const vendorMap = {}
  rows.forEach(r => {
    const v = r.vendor_name || '기타'
    if (filterVendor && v !== filterVendor && !v.replace(/\s/g,'').includes(filterVendor.replace(/\s/g,''))) return
    if (!vendorMap[v]) vendorMap[v] = []
    vendorMap[v].push(r)
  })

  // 기간 라벨 정리 (월별)
  const allPeriods = [...new Set(rows.map(r =>
    period === 'daily' ? (r.period_date||'') :
    period === 'weekly' ? `${r.yr}년 ${r.week_num}주` :
    `${r.yr}.${String(r.mo).padStart(2,'0')}`
  ))].sort()

  const vendorColors = ['#3b82f6','#10b981','#f59e0b','#ef4444','#8b5cf6','#06b6d4','#f97316','#84cc16']
  const datasets = Object.entries(vendorMap).map(([vendor, vRows], idx) => {
    const priceMap = {}
    vRows.forEach(r => {
      const key = period === 'daily' ? (r.period_date||'') :
                  period === 'weekly' ? `${r.yr}년 ${r.week_num}주` :
                  `${r.yr}.${String(r.mo).padStart(2,'0')}`
      priceMap[key] = Math.round(Number(r.avg_price)||0)
    })
    return {
      label: vendor,
      data: allPeriods.map(p => priceMap[p] || null),
      borderColor: vendorColors[idx % vendorColors.length],
      backgroundColor: vendorColors[idx % vendorColors.length] + '22',
      tension: 0.3,
      fill: false,
      pointRadius: 4,
      pointHoverRadius: 6,
      spanGaps: true
    }
  })

  area.innerHTML = `<canvas id="txTrendChart" style="max-height:240px"></canvas>`
  const ctx = document.getElementById('txTrendChart')?.getContext('2d')
  if (!ctx) return

  // 기존 차트 destroy
  if (window._txTrendChartInstance) {
    try { window._txTrendChartInstance.destroy() } catch(e) {}
  }

  window._txTrendChartInstance = new Chart(ctx, {
    type: 'line',
    data: { labels: allPeriods, datasets },
    options: {
      responsive: true,
      maintainAspectRatio: true,
      interaction: { mode: 'index', intersect: false },
      plugins: {
        legend: { position: 'top', labels: { font: { size: 11 }, boxWidth: 14 } },
        tooltip: {
          callbacks: {
            label: ctx => `${ctx.dataset.label}: ${(ctx.raw||0).toLocaleString()}원`
          }
        }
      },
      scales: {
        x: { ticks: { font: { size: 10 }, maxRotation: 45 } },
        y: {
          ticks: {
            font: { size: 10 },
            callback: v => v >= 10000 ? Math.round(v/1000)+'천원' : v.toLocaleString()+'원'
          }
        }
      }
    }
  })

  // 요약 카드
  if (summaryArea) {
    const allPrices = rows.filter(r => Number(r.avg_price) > 0).map(r => Number(r.avg_price))
    const avgPrice = allPrices.length ? Math.round(allPrices.reduce((s,v)=>s+v,0)/allPrices.length) : 0
    const maxPrice = allPrices.length ? Math.max(...allPrices) : 0
    const minPrice = allPrices.length ? Math.min(...allPrices) : 0
    const latestRow = rows[0]
    const latestPrice = latestRow ? Math.round(Number(latestRow.avg_price)||0) : 0
    const prevRow = rows[1]
    const prevPrice = prevRow ? Math.round(Number(prevRow.avg_price)||0) : 0
    const diff = prevPrice > 0 ? latestPrice - prevPrice : 0
    const diffPct = prevPrice > 0 ? ((diff/prevPrice)*100).toFixed(1) : null

    summaryArea.innerHTML = [
      { label: '최근 단가', val: latestPrice > 0 ? latestPrice.toLocaleString()+'원' : '-', color: '#1d4ed8',
        sub: diffPct ? `<span style="color:${diff>0?'#dc2626':'#16a34a'}">${diff>0?'▲':'▼'}${Math.abs(diff).toLocaleString()}원(${diffPct}%)</span>` : '' },
      { label: '평균 단가', val: avgPrice > 0 ? avgPrice.toLocaleString()+'원' : '-', color: '#374151', sub: `${allPrices.length}건 평균` },
      { label: '최저 단가', val: minPrice > 0 ? minPrice.toLocaleString()+'원' : '-', color: '#16a34a', sub: '기간 내 최저' },
      { label: '최고 단가', val: maxPrice > 0 ? maxPrice.toLocaleString()+'원' : '-', color: '#dc2626', sub: '기간 내 최고' },
    ].map(k => `<div class="bg-gray-50 rounded-lg p-2.5 text-center">
      <div class="text-xs text-gray-400">${k.label}</div>
      <div class="text-sm font-bold mt-0.5" style="color:${k.color}">${k.val}</div>
      <div class="text-xs text-gray-400 mt-0.5">${k.sub||''}</div>
    </div>`).join('')
  }
}

window.txIngLoadHistory = async function() {
  const selected = window._txIngSelectedItems || []
  if (selected.length === 0) { showToast('품목을 선택해주세요', 'warning'); return }

  const authH = window._txIngAuthH || { Authorization: `Bearer ${localStorage.getItem('token')}` }
  const hParamAmp = window._txIngHParamAmp || ''
  const area = document.getElementById('txIngHistoryArea')
  const vcArea = document.getElementById('txIngVendorCompare')
  if (area) area.innerHTML = `<div class="text-center text-gray-400 py-6"><i class="fas fa-spinner fa-spin"></i></div>`

  try {
    const namesParam = selected.join('||')
    const res = await axios.get(
      `/api/transaction/invoice/ingredient-price-history?item_names=${encodeURIComponent(namesParam)}&months=12${hParamAmp}`,
      { headers: authH }
    )
    const data = res.data.data || []
    const fmt = v => (Number(v)||0).toLocaleString()
    const fmtK = v => v >= 10000 ? Math.round(v/10000)+'만' : fmt(v)

    if (data.length === 0) {
      if (area) area.innerHTML = `<div class="text-center text-gray-400 py-6 text-sm">선택된 품목의 발주 이력이 없습니다.</div>`
      return
    }

    // 품목별로 그룹화
    const grouped = {}
    data.forEach(r => {
      const k = r.item_name
      if (!grouped[k]) grouped[k] = []
      grouped[k].push(r)
    })

    // 발주 이력 테이블 (품목명, 발주량, 금액, 날짜, 업체 모두 포함)
    if (area) area.innerHTML = `
    <div class="overflow-x-auto max-h-96 overflow-y-auto">
      <table class="w-full text-xs">
        <thead class="sticky top-0 bg-white shadow-sm">
          <tr class="bg-gray-50 text-gray-500">
            <th class="text-left py-2 px-2 font-semibold">품목명</th>
            <th class="text-left py-2 px-2 font-semibold">업체</th>
            <th class="text-center py-2 px-2 font-semibold">발주 날짜</th>
            <th class="text-right py-2 px-2 font-semibold">발주량</th>
            <th class="text-right py-2 px-2 font-semibold">평균단가</th>
            <th class="text-right py-2 px-2 font-semibold">총금액</th>
            <th class="text-center py-2 px-2 font-semibold">발주횟수</th>
          </tr>
        </thead>
        <tbody>
          ${data.map((r, i) => {
            const mm = String(r.document_month).padStart(2,'0')
            const dateLabel = `${r.document_year}.${mm}`
            return `
          <tr class="border-b border-gray-50 ${i%2===0?'':'bg-gray-50/50'} hover:bg-blue-50/30 transition-colors">
            <td class="py-1.5 px-2 font-semibold text-gray-800">${r.item_name}</td>
            <td class="py-1.5 px-2">
              <span class="inline-flex items-center gap-1 bg-blue-50 text-blue-700 px-2 py-0.5 rounded text-xs">${r.vendor_name}</span>
            </td>
            <td class="py-1.5 px-2 text-center">
              <span class="bg-gray-100 text-gray-600 px-2 py-0.5 rounded text-xs font-mono">${dateLabel}</span>
            </td>
            <td class="py-1.5 px-2 text-right font-medium text-gray-700">${fmt(r.total_qty)}</td>
            <td class="py-1.5 px-2 text-right font-bold text-indigo-700">${fmt(Math.round(r.avg_price))}원</td>
            <td class="py-1.5 px-2 text-right font-bold text-gray-900">${fmtK(r.total_amount)}</td>
            <td class="py-1.5 px-2 text-center text-gray-400">${r.order_count}회</td>
          </tr>`}).join('')}
        </tbody>
      </table>
    </div>
    <div class="mt-2 flex gap-4 text-xs text-gray-400 px-2">
      <span>총 ${data.length}건 · 품목 ${Object.keys(grouped).length}개 · 업체 ${[...new Set(data.map(r=>r.vendor_name))].length}개</span>
    </div>`

    // 업체별 단가 비교
    if (vcArea) {
      // 품목 × 업체별 평균단가 비교
      const allVendors = [...new Set(data.map(r => r.vendor_name))]
      const compRows = Object.entries(grouped).map(([name, rows]) => {
        const vendorPrices = {}
        rows.forEach(r => {
          if (!vendorPrices[r.vendor_name]) vendorPrices[r.vendor_name] = []
          vendorPrices[r.vendor_name].push(Number(r.avg_price)||0)
        })
        const vendorAvg = {}
        Object.entries(vendorPrices).forEach(([v, prices]) => {
          vendorAvg[v] = Math.round(prices.reduce((s,p)=>s+p,0) / prices.length)
        })
        const prices = Object.values(vendorAvg).filter(p => p > 0)
        const minP = prices.length ? Math.min(...prices) : 0
        const maxP = prices.length ? Math.max(...prices) : 0
        return { name, vendorAvg, minP, maxP }
      })

      vcArea.innerHTML = `
      <div class="overflow-x-auto">
        <table class="w-full text-xs">
          <thead>
            <tr class="bg-purple-50 text-gray-600">
              <th class="text-left py-2 px-3">품목명</th>
              ${allVendors.map(v => `<th class="text-right py-2 px-3">${v}</th>`).join('')}
              <th class="text-right py-2 px-3">최저가</th>
              <th class="text-right py-2 px-3">최고가</th>
              <th class="text-right py-2 px-3">차이</th>
            </tr>
          </thead>
          <tbody>
            ${compRows.map((r, i) => `
            <tr class="border-b border-gray-50 ${i%2===0?'':'bg-gray-50/30'}">
              <td class="py-2 px-3 font-medium text-gray-800">${r.name}</td>
              ${allVendors.map(v => {
                const p = r.vendorAvg[v]
                const isMin = p && p === r.minP
                const isMax = p && p === r.maxP
                return `<td class="py-2 px-3 text-right ${isMin ? 'text-green-600 font-bold' : isMax ? 'text-red-500' : 'text-gray-600'}">${p ? fmt(p)+'원' : '-'}</td>`
              }).join('')}
              <td class="py-2 px-3 text-right text-green-600 font-bold">${r.minP ? fmt(r.minP)+'원' : '-'}</td>
              <td class="py-2 px-3 text-right text-red-500">${r.maxP ? fmt(r.maxP)+'원' : '-'}</td>
              <td class="py-2 px-3 text-right text-orange-500 font-bold">${r.minP && r.maxP && r.maxP > r.minP ? '+'+fmt(r.maxP - r.minP)+'원' : '-'}</td>
            </tr>`).join('')}
          </tbody>
        </table>
        <div class="mt-2 text-xs text-gray-400"><span class="text-green-600 font-bold">녹색</span>=최저가 · <span class="text-red-500">빨강</span>=최고가</div>
      </div>`
    }

  } catch(e) {
    if (area) area.innerHTML = `<div class="text-center text-red-400 py-6 text-sm">조회 실패: ${e.message}</div>`
  }
}

// ── 주요품목 분석 탭 (업체별 12종 단가 관리) ────────────────
async function txIngLoadManualTab(authH, hospitalId) {
  const sub = document.getElementById('txIngSubContent')
  if (!sub) return
  sub.innerHTML = `<div class="text-center text-gray-400 py-10"><i class="fas fa-spinner fa-spin text-2xl"></i></div>`

  const year  = TXState.year  || new Date().getFullYear()
  const month = TXState.month || (new Date().getMonth() + 1)
  const hParam = hospitalId ? `?hospital_id=${hospitalId}` : ''

  try {
    // 업체 목록 가져오기
    const vendorRes = await axios.get(`/api/transaction/invoice/vendor-list${hParam}`, { headers: authH })
      .catch(() => ({ data: { ok: true, data: [] } }))
    const vendors = (vendorRes.data.data || []).map(v => v.vendor_name)

    window._txIngManualHospitalId = hospitalId
    window._txIngManualAuthH = authH
    window._txIngManualYear = year
    window._txIngManualMonth = month
    window._txIngManualVendors = vendors
    window._txIngManualSelectedVendor = window._txIngManualSelectedVendor || vendors[0] || ''

    sub.innerHTML = `
    <div class="space-y-4">
      <!-- 헤더: 연월 선택 + 업체 탭 -->
      <div class="bg-white rounded-xl border border-gray-100 shadow-sm p-4">
        <div class="flex items-center justify-between flex-wrap gap-3 mb-3">
          <div>
            <h3 class="font-bold text-gray-800 text-sm flex items-center gap-2">
              <i class="fas fa-store text-green-500"></i>주요품목 단가 분석 (업체별)
            </h3>
            <p class="text-xs text-gray-400 mt-0.5">업체마다 동일 품목이라도 가격이 다르므로 업체별 개별 관리</p>
          </div>
          <div class="flex items-center gap-2">
            <select id="txIngYearSel" class="border border-gray-200 rounded px-2 py-1 text-xs" onchange="txIngReloadManual()">
              ${[year-1, year].map(y => `<option value="${y}" ${y===year?'selected':''}>${y}년</option>`).join('')}
            </select>
            <select id="txIngMonthSel" class="border border-gray-200 rounded px-2 py-1 text-xs" onchange="txIngReloadManual()">
              ${Array.from({length:12},(_,i)=>i+1).map(m => `<option value="${m}" ${m===month?'selected':''}>${m}월</option>`).join('')}
            </select>
          </div>
        </div>
        <!-- 업체 탭 버튼 -->
        <div class="flex flex-wrap gap-2" id="txIngVendorTabs">
          ${vendors.length === 0 ?
            `<div class="text-sm text-gray-400"><i class="fas fa-info-circle mr-1"></i>거래명세서를 업로드하면 업체 탭이 생성됩니다</div>` :
            vendors.map((v, i) => `
              <button onclick="txIngSelectVendorTab('${v.replace(/'/g,"\\'")}')"
                id="txIngVTab-${i}"
                class="px-4 py-2 rounded-lg text-sm font-medium border transition-all ${window._txIngManualSelectedVendor===v ? 'bg-green-600 text-white border-green-600' : 'bg-white text-gray-600 border-gray-200 hover:border-green-400'}">
                <i class="fas fa-truck mr-1 text-xs"></i>${v}
              </button>
            `).join('')
          }
        </div>
      </div>
      <!-- 업체별 단가 테이블 영역 -->
      <div id="txIngVendorContent">
        <div class="text-center text-gray-400 py-8 text-sm"><i class="fas fa-spinner fa-spin"></i></div>
      </div>
    </div>`

    // 선택된 업체 단가 로드
    if (window._txIngManualSelectedVendor) {
      await txIngLoadVendorPrices(authH, hospitalId, year, month, window._txIngManualSelectedVendor)
    } else if (vendors.length === 0) {
      document.getElementById('txIngVendorContent').innerHTML = `
        <div class="bg-white rounded-xl border border-gray-100 shadow-sm p-8 text-center text-gray-400">
          <i class="fas fa-truck text-4xl mb-3 block opacity-30"></i>
          <div class="text-sm">거래명세서를 업로드하면 업체별 탭이 자동 생성됩니다</div>
        </div>`
    }

  } catch(e) {
    if (sub) sub.innerHTML = `<div class="text-center text-red-400 py-8 text-sm">로드 실패: ${e.message}</div>`
  }
}

window.txIngSelectVendorTab = async function(vendorName) {
  window._txIngManualSelectedVendor = vendorName
  // 탭 버튼 스타일 갱신
  const tabs = document.getElementById('txIngVendorTabs')
  if (tabs) {
    tabs.querySelectorAll('button').forEach(btn => {
      const isActive = btn.textContent.trim().replace(/^[^ ]+ /,'').startsWith(vendorName)
      btn.className = `px-4 py-2 rounded-lg text-sm font-medium border transition-all ${isActive ? 'bg-green-600 text-white border-green-600' : 'bg-white text-gray-600 border-gray-200 hover:border-green-400'}`
    })
  }
  const authH = window._txIngManualAuthH || { Authorization: `Bearer ${localStorage.getItem('token')}` }
  const hospitalId = window._txIngManualHospitalId
  const year = window._txIngManualYear || TXState.year
  const month = window._txIngManualMonth || TXState.month
  await txIngLoadVendorPrices(authH, hospitalId, year, month, vendorName)
}

async function txIngLoadVendorPrices(authH, hospitalId, year, month, vendorName) {
  const content = document.getElementById('txIngVendorContent')
  if (!content) return
  content.innerHTML = `<div class="text-center text-gray-400 py-8"><i class="fas fa-spinner fa-spin"></i></div>`

  try {
    const hParam = hospitalId ? `?hospital_id=${hospitalId}` : '?'
    const sep = hospitalId ? '&' : ''
    const prevM = month === 1 ? 12 : month - 1
    const prevY = month === 1 ? year - 1 : year

    // 현재월 + 전월 + 전년동월 데이터
    const [curRes, prevRes, prevYRes] = await Promise.all([
      axios.get(`/api/transaction/invoice/vendor-ingredient-prices${hParam}${sep}vendor_name=${encodeURIComponent(vendorName)}&year=${year}&month=${month}`, { headers: authH })
        .then(r => r.data.data || []).catch(() => []),
      axios.get(`/api/transaction/invoice/vendor-ingredient-prices${hParam}${sep}vendor_name=${encodeURIComponent(vendorName)}&year=${prevY}&month=${prevM}`, { headers: authH })
        .then(r => r.data.data || []).catch(() => []),
      axios.get(`/api/transaction/invoice/vendor-ingredient-prices${hParam}${sep}vendor_name=${encodeURIComponent(vendorName)}&year=${year-1}&month=${month}`, { headers: authH })
        .then(r => r.data.data || []).catch(() => []),
    ])

    const DEFAULT_INGREDIENTS = [
      { name: '쌀', unit: 'kg' }, { name: '닭고기', unit: 'kg' }, { name: '돼지고기', unit: 'kg' },
      { name: '쇠고기', unit: 'kg' }, { name: '두부', unit: 'kg' }, { name: '계란', unit: '개' },
      { name: '양파', unit: 'kg' }, { name: '감자', unit: 'kg' }, { name: '당근', unit: 'kg' },
      { name: '배추', unit: 'kg' }, { name: '대파', unit: 'kg' }, { name: '마늘', unit: 'kg' },
    ]

    const curMap = {}, prevMap = {}, prevYMap = {}
    curRes.forEach(r => { curMap[r.ingredient_name] = r })
    prevRes.forEach(r => { prevMap[r.ingredient_name] = r })
    prevYRes.forEach(r => { prevYMap[r.ingredient_name] = r })

    const allNames = [...new Set([...DEFAULT_INGREDIENTS.map(d=>d.name), ...curRes.map(r=>r.ingredient_name)])]
    const rows = allNames.map(name => {
      const def = DEFAULT_INGREDIENTS.find(d=>d.name===name) || { name, unit:'kg' }
      const ex   = curMap[name]  || {}
      const prev = prevMap[name] || {}
      const pyR  = prevYMap[name]|| {}
      return {
        name, unit: ex.unit || def.unit,
        price: ex.unit_price || '',
        amount: ex.total_amount || 0,
        qty: ex.total_quantity || 0,
        prevPrice: prev.unit_price || 0,
        prevYearPrice: pyR.unit_price || 0,
        memo: ex.memo || '',
        source: ex.source || ''
      }
    })

    const prevMLabel = `${prevY}년 ${prevM}월`
    const prevYLabel = `${year-1}년 ${month}월`

    content.innerHTML = `
    <div class="bg-white rounded-xl border border-gray-100 shadow-sm overflow-hidden">
      <div class="px-4 py-3 border-b border-gray-100 flex items-center justify-between flex-wrap gap-2">
        <div class="flex items-center gap-2">
          <i class="fas fa-truck text-green-500"></i>
          <span class="font-bold text-gray-800 text-sm">${vendorName} · ${year}년 ${month}월 주요품목 단가</span>
          <span class="text-xs text-gray-400">(12종 고정 + 추가 가능)</span>
        </div>
        <div class="flex gap-2">
          <button onclick="txIngAddVendorRow()" class="text-xs bg-gray-100 text-gray-600 px-2 py-1 rounded hover:bg-gray-200">
            <i class="fas fa-plus mr-1"></i>품목 추가
          </button>
          <button onclick="txIngSaveVendorPrices('${vendorName.replace(/'/g,"\\'")}',${year},${month},'${hospitalId||''}')"
            class="text-xs bg-green-600 text-white px-3 py-1 rounded hover:bg-green-700">
            <i class="fas fa-save mr-1"></i>저장
          </button>
        </div>
      </div>
      <div class="overflow-x-auto">
        <table class="w-full text-xs" id="txIngVendorTable">
          <thead>
            <tr class="bg-gray-50 text-gray-500">
              <th class="text-left py-2 px-3">식재료명</th>
              <th class="text-center py-2 px-3">단위</th>
              <th class="text-right py-2 px-3">당월 단가</th>
              <th class="text-right py-2 px-3">당월 금액</th>
              <th class="text-right py-2 px-3">${prevMLabel}</th>
              <th class="text-right py-2 px-3">전월 대비</th>
              <th class="text-right py-2 px-3">${prevYLabel}</th>
              <th class="text-right py-2 px-3">전년 대비</th>
            </tr>
          </thead>
          <tbody id="txIngVendorTbody">
            ${rows.map((r, i) => txIngBuildVendorRow(i, r)).join('')}
          </tbody>
        </table>
      </div>
    </div>`

    window._txIngVendorRows = rows
    window._txIngVendorName = vendorName

  } catch(e) {
    if (content) content.innerHTML = `<div class="text-center text-red-400 py-8 text-sm">로드 실패: ${e.message}</div>`
  }
}

function txIngBuildVendorRow(i, r) {
  const diff = (cur, prev) => {
    if (!cur || !prev) return '<span class="text-gray-300">-</span>'
    const d = cur - prev, p = ((d/prev)*100).toFixed(1)
    return `<span style="color:${d>0?'#dc2626':d<0?'#16a34a':'#6b7280'};font-weight:700">${d>0?'▲':'▼'} ${Math.abs(d).toLocaleString()}원(${p}%)</span>`
  }
  const isAuto = r.source === 'auto'
  const autoBadge = isAuto ? `<span style="font-size:9px;background:#dbeafe;color:#1d4ed8;border-radius:4px;padding:1px 4px;margin-left:2px;font-weight:600">자동</span>` : ''
  const amountCell = r.amount > 0
    ? `<div style="color:#374151;font-size:11px">${r.amount.toLocaleString()}원</div><div style="color:#9ca3af;font-size:9px">${r.qty > 0 ? r.qty + r.unit : ''}</div>`
    : '<span style="color:#d1d5db">-</span>'

  const rowBg = r.price && r.prevPrice ? (r.price > r.prevPrice ? '#fff5f5' : r.price < r.prevPrice ? '#f0fdf4' : '') : ''

  return `<tr class="border-b border-gray-50" data-vendor-row="${i}" style="${rowBg ? 'background:'+rowBg : ''}">
    <td class="py-1.5 px-3">
      <div style="display:flex;align-items:center">
        <input type="text" id="txVIng-name-${i}" value="${r.name||''}" class="border border-gray-200 rounded px-2 py-1 text-xs w-20">
        ${autoBadge}
      </div>
    </td>
    <td class="py-1.5 px-3 text-center">
      <select id="txVIng-unit-${i}" class="border border-gray-200 rounded px-1 py-1 text-xs">
        ${['kg','개','박스','묶음','L','봉','팩'].map(u=>`<option value="${u}" ${r.unit===u?'selected':''}>${u}</option>`).join('')}
      </select>
    </td>
    <td class="py-1.5 px-3">
      <input type="text" inputmode="numeric" id="txVIng-price-${i}" value="${r.price > 0 ? r.price.toLocaleString('ko-KR') : ''}" placeholder="0"
        class="border border-gray-200 rounded px-2 py-1 text-xs w-24 text-right comma-input"
        oninput="txIngRefreshVendorRow(${i},${r.prevPrice||0},${r.prevYearPrice||0})">
    </td>
    <td class="py-1.5 px-3 text-right">${amountCell}</td>
    <td class="py-1.5 px-3 text-right text-gray-400">${r.prevPrice > 0 ? r.prevPrice.toLocaleString()+'원' : '-'}</td>
    <td class="py-1.5 px-3 text-right" id="txVIng-diff-${i}">${diff(r.price, r.prevPrice)}</td>
    <td class="py-1.5 px-3 text-right text-gray-400">${r.prevYearPrice > 0 ? r.prevYearPrice.toLocaleString()+'원' : '-'}</td>
    <td class="py-1.5 px-3 text-right" id="txVIng-diffy-${i}">${diff(r.price, r.prevYearPrice)}</td>
  </tr>`
}

window.txIngRefreshVendorRow = function(i, prevPrice, prevYearPrice) {
  const cur = parseCommaNum(document.getElementById(`txVIng-price-${i}`)?.value)
  const diffEl  = document.getElementById(`txVIng-diff-${i}`)
  const diffYEl = document.getElementById(`txVIng-diffy-${i}`)
  const rowEl   = document.querySelector(`tr[data-vendor-row="${i}"]`)
  const makeDiff = (cur, prev) => {
    if (!cur || !prev) return '<span class="text-gray-300">-</span>'
    const d = cur - prev, p = ((d/prev)*100).toFixed(1)
    return `<span style="color:${d>0?'#dc2626':d<0?'#16a34a':'#6b7280'};font-weight:700">${d>0?'▲':'▼'} ${Math.abs(d).toLocaleString()}원(${p}%)</span>`
  }
  if (diffEl) diffEl.innerHTML = makeDiff(cur, prevPrice)
  if (diffYEl) diffYEl.innerHTML = makeDiff(cur, prevYearPrice)
  if (rowEl && cur > 0 && prevPrice > 0) rowEl.style.background = cur > prevPrice ? '#fff5f5' : cur < prevPrice ? '#f0fdf4' : ''
}

window.txIngAddVendorRow = function() {
  const tbody = document.getElementById('txIngVendorTbody')
  if (!tbody) return
  const idx = tbody.querySelectorAll('tr').length
  tbody.insertAdjacentHTML('beforeend', txIngBuildVendorRow(idx, { name:'', unit:'kg', price:'', prevPrice:0, prevYearPrice:0, amount:0, qty:0 }))
}

window.txIngSaveVendorPrices = async function(vendorName, year, month, hospitalId) {
  const tbody = document.getElementById('txIngVendorTbody')
  if (!tbody) return
  const authH = window._txIngManualAuthH || { Authorization: `Bearer ${localStorage.getItem('token')}` }
  const trs = tbody.querySelectorAll('tr[data-vendor-row]')
  const items = []
  trs.forEach(tr => {
    const i = tr.dataset.vendorRow
    const name  = document.getElementById(`txVIng-name-${i}`)?.value?.trim()
    const unit  = document.getElementById(`txVIng-unit-${i}`)?.value || 'kg'
    const price = parseCommaNum(document.getElementById(`txVIng-price-${i}`)?.value)
    if (name && price > 0) items.push({ ingredient_name: name, unit, unit_price: price })
  })
  if (!items.length) { showToast('입력된 단가가 없습니다', 'warning'); return }

  try {
    const hParam = hospitalId ? `?hospital_id=${hospitalId}` : ''
    const res = await axios.post(`/api/transaction/invoice/vendor-ingredient-prices${hParam}`, {
      vendor_name: vendorName, year, month, items
    }, { headers: authH })
    if (res.data?.ok) {
      showToast(`${res.data.saved}건 저장됨 (${vendorName})`, 'success')
    } else {
      showToast('저장 실패', 'error')
    }
  } catch(e) {
    showToast('저장 실패: ' + e.message, 'error')
  }
}

window.txIngReloadManual = function() {
  const y = parseInt(document.getElementById('txIngYearSel')?.value) || TXState.year
  const m = parseInt(document.getElementById('txIngMonthSel')?.value) || TXState.month
  window._txIngManualYear = y
  window._txIngManualMonth = m
  TXState.year  = y
  TXState.month = m
  const authH = window._txIngManualAuthH || { Authorization: `Bearer ${localStorage.getItem('token')}` }
  const hospitalId = window._txIngManualHospitalId
  if (window._txIngManualSelectedVendor) {
    txIngLoadVendorPrices(authH, hospitalId, y, m, window._txIngManualSelectedVendor)
  }
}

// ─── (구버전 호환용 – txIngBuildManualRow, txIngRefreshRow, txIngAddRow, txIngSaveManual 유지) ────
const txIngBuildManualRow_COMPAT = function(i, r) {
  const diff = (cur, prev) => {
    if (!cur || !prev) return '<span class="text-gray-300">-</span>'
    const d = cur - prev, p = ((d/prev)*100).toFixed(1)
    return `<span style="color:${d>0?'#dc2626':d<0?'#16a34a':'#6b7280'};font-weight:700">${d>0?'▲':'▼'} ${Math.abs(d).toLocaleString()}원(${p}%)</span>`
  }
  return `<tr class="border-b border-gray-50" data-ing-idx="${i}">
    <td class="py-1.5 px-3"><input type="text" id="txIng-name-${i}" value="${r.name||''}" class="border border-gray-200 rounded px-2 py-1 text-xs w-20"></td>
    <td class="py-1.5 px-3 text-center"><select id="txIng-unit-${i}" class="border border-gray-200 rounded px-1 py-1 text-xs">
      ${['kg','개','박스','묶음','L','봉','팩'].map(u=>`<option value="${u}" ${r.unit===u?'selected':''}>${u}</option>`).join('')}
    </select></td>
    <td class="py-1.5 px-3"><input type="text" inputmode="numeric" id="txIng-price-${i}" value="${r.price > 0 ? r.price.toLocaleString('ko-KR') : ''}" placeholder="0" class="border border-gray-200 rounded px-2 py-1 text-xs w-24 text-right comma-input" oninput="txIngRefreshRow(${i},${r.prevPrice||0},${r.prevYearPrice||0})"></td>
    <td class="py-1.5 px-3 text-right">${r.amount > 0 ? r.amount.toLocaleString()+'원' : '-'}</td>
    <td class="py-1.5 px-3 text-right text-gray-400">${r.prevPrice > 0 ? r.prevPrice.toLocaleString()+'원' : '-'}</td>
    <td class="py-1.5 px-3 text-right" id="txIng-diff-${i}">${diff(r.price, r.prevPrice)}</td>
    <td class="py-1.5 px-3 text-right text-gray-400">${r.prevYearPrice > 0 ? r.prevYearPrice.toLocaleString()+'원' : '-'}</td>
    <td class="py-1.5 px-3 text-right" id="txIng-diffy-${i}">${diff(r.price, r.prevYearPrice)}</td>
  </tr>`
}

const _txIngBuildManualRowOLD = window.txIngBuildManualRow || txIngBuildManualRow_COMPAT

window.txIngBuildManualRow = _txIngBuildManualRowOLD

window.txIngReloadManual = function() {
  const y = parseInt(document.getElementById('txIngYearSel')?.value) || TXState.year
  const m = parseInt(document.getElementById('txIngMonthSel')?.value) || TXState.month
  window._txIngManualYear = y
  window._txIngManualMonth = m
  TXState.year  = y
  TXState.month = m
  const authH = window._txIngManualAuthH || { Authorization: `Bearer ${localStorage.getItem('token')}` }
  const hospitalId = window._txIngManualHospitalId
  if (window._txIngManualSelectedVendor) {
    txIngLoadVendorPrices(authH, hospitalId, y, m, window._txIngManualSelectedVendor)
  }
}

window.txIngSaveManual = async function(year, month, hospitalId) {
  // 구버전 저장 함수 – 현재는 txIngSaveVendorPrices로 대체됨
  const vendor = window._txIngManualSelectedVendor || ''
  if (vendor) {
    return txIngSaveVendorPrices(vendor, year, month, hospitalId)
  }
}

async function txLoadCrossAnalysis() {
  const el = document.getElementById('txCrossContent')
  if (!el) return
  try {
    const hospitalId = TXState.selectedHospitalId || window._adminHospitalId || ''
    const hParam = hospitalId ? `&hospital_id=${hospitalId}` : ''
    const res = await axios.get(`/api/transaction/cross-analysis?year=${TXState.year}&month=${TXState.month}${hParam}`,
      { headers: { Authorization: `Bearer ${localStorage.getItem('token')}` } })
    const d = res.data
    if (!d.ok) throw new Error(d.error)

    const s = d.summary || {}
    const items = d.discrepancies || []

    // 전역 저장 (엑셀 다운로드용)
    window._crossSummary = s
    window._crossItems   = items
    window._crossYear    = TXState.year
    window._crossMonth   = TXState.month

    // 엑셀 버튼 표시
    const excelBtn = document.getElementById('crossExcelBtn')
    if (excelBtn) excelBtn.style.display = 'flex'

    el.innerHTML = `
    <div class="space-y-4">
      <!-- 요약 -->
      <div class="grid grid-cols-2 md:grid-cols-4 gap-3">
        ${[
          { label:'발주 총액',    val: (s.total_order_amount||0).toLocaleString()+'원',   icon:'fa-shopping-cart', color:'blue' },
          { label:'명세서 총액',  val: (s.total_invoice_amount||0).toLocaleString()+'원', icon:'fa-file-invoice',  color:'green' },
          { label:'경고 업체',    val: (s.warning_vendors||0)+'건',                    icon:'fa-exclamation-triangle', color:'yellow' },
          { label:'심각 업체',    val: (s.critical_vendors||0)+'건',                   icon:'fa-times-circle',  color:'red' }
        ].map(k => `
          <div class="bg-white rounded-xl shadow-sm border border-gray-100 p-4">
            <div class="flex items-center gap-2 mb-2">
              <div class="w-8 h-8 rounded-lg bg-${k.color}-100 flex items-center justify-center">
                <i class="fas ${k.icon} text-${k.color}-500 text-sm"></i>
              </div>
              <span class="text-xs text-gray-500">${k.label}</span>
            </div>
            <div class="text-lg font-bold text-gray-800">${k.val}</div>
          </div>`).join('')}
      </div>

      <!-- 명세서 없음 안내 (invoice_amount 합계가 0일 때) -->
      ${s.total_invoice_amount === 0 ? `
      <div class="bg-amber-50 border border-amber-200 rounded-xl p-4 text-sm text-amber-800 flex items-start gap-2">
        <i class="fas fa-folder-open text-amber-500 mt-0.5 text-base"></i>
        <div>
          <div class="font-semibold mb-1">거래명세서가 업로드되지 않았습니다</div>
          <div class="text-xs text-amber-700">이 병원에는 아직 거래명세서 데이터가 없습니다. 거래명세서 탭에서 파일을 업로드하면 발주 금액과 비교 분석할 수 있습니다.</div>
          <div class="text-xs text-amber-600 mt-1.5">※ 아래 목록은 발주 데이터만 있는 업체들입니다 (명세서 미업로드 상태)</div>
        </div>
      </div>` : `
      <!-- 교차 분석 안내 -->
      <div class="bg-blue-50 border border-blue-100 rounded-xl p-4 text-sm text-blue-700 flex items-start gap-2">
        <i class="fas fa-info-circle mt-0.5"></i>
        <div>발주 데이터(일별발주)와 거래명세서를 <strong>업체별</strong>로 매핑하여 금액 차이를 분석합니다.
        금액 차이 ±10% 이상 시 경고, ±30% 이상 시 심각으로 표시됩니다.
        <span class="block mt-1 text-blue-500 text-xs">※ 발주 업체와 명세서 업체명이 다를 경우 매칭되지 않을 수 있습니다.</span></div>
      </div>`}

      <!-- 교차 분석 테이블 -->
      <div class="bg-white rounded-xl shadow-sm border border-gray-100 p-5">
        <div class="flex items-center justify-between mb-3">
          <h4 class="font-bold text-gray-700 text-sm">발주 vs 명세서 업체별 비교</h4>
          <div class="flex gap-2 text-xs">
            <span class="px-2 py-0.5 bg-red-100 text-red-600 rounded-full">● 심각(≥30%)</span>
            <span class="px-2 py-0.5 bg-yellow-100 text-yellow-600 rounded-full">● 경고(≥10%)</span>
            <span class="px-2 py-0.5 bg-green-100 text-green-600 rounded-full">● 정상</span>
          </div>
        </div>
        <div class="overflow-x-auto">
          <table class="w-full text-xs">
            <thead><tr class="bg-gray-50">
              <th class="text-left px-3 py-2 text-gray-500 border-b">업체명</th>
              <th class="text-right px-3 py-2 text-gray-500 border-b">발주 총액</th>
              <th class="text-right px-3 py-2 text-gray-500 border-b">명세서 총액</th>
              <th class="text-right px-3 py-2 text-gray-500 border-b">차이금액</th>
              <th class="text-right px-3 py-2 text-gray-500 border-b">차이율</th>
              <th class="text-center px-3 py-2 text-gray-500 border-b">발주횟수</th>
              <th class="text-center px-3 py-2 text-gray-500 border-b">명세서품목</th>
              <th class="text-center px-3 py-2 text-gray-500 border-b">상태</th>
            </tr></thead>
            <tbody>
              ${items.length === 0 ? `
                <tr><td colspan="8" class="text-center text-gray-400 py-8">
                  발주 데이터 또는 명세서 데이터가 없습니다.
                </td></tr>` :
              items.map(item => {
                const diff = item.amount_diff || 0
                const fmt = v => (Number(v)||0).toLocaleString()
                return `
                <tr class="border-b border-gray-50 hover:bg-gray-50 ${
                  item.alert_level==='critical'?'bg-red-50/40':
                  item.alert_level==='warning' ?'bg-yellow-50/40':''}">
                  <td class="px-3 py-2 font-medium text-gray-700">${item.vendor_name||'-'}</td>
                  <td class="px-3 py-2 text-right text-blue-700 font-medium">${item.ordered_amount > 0 ? fmt(item.ordered_amount)+'원' : '<span class="text-gray-300">-</span>'}</td>
                  <td class="px-3 py-2 text-right text-green-700 font-medium">${item.invoice_amount > 0 ? fmt(item.invoice_amount)+'원' : '<span class="text-gray-300">-</span>'}</td>
                  <td class="px-3 py-2 text-right font-bold ${diff>0?'text-blue-600':diff<0?'text-red-600':'text-gray-400'}">
                    ${diff===0?'-':(diff>0?'+':'')+fmt(diff)+'원'}
                  </td>
                  <td class="px-3 py-2 text-right ${Math.abs(item.amount_diff_pct||0)>=30?'text-red-600 font-bold':Math.abs(item.amount_diff_pct||0)>=10?'text-yellow-600':'text-gray-500'}">
                    ${item.amount_diff_pct ? Math.abs(item.amount_diff_pct)+'%' : '-'}
                  </td>
                  <td class="px-3 py-2 text-center text-gray-500">${item.order_count||0}회</td>
                  <td class="px-3 py-2 text-center text-gray-500">${item.invoice_item_count||0}품목</td>
                  <td class="px-3 py-2 text-center">
                    <span class="px-2 py-0.5 rounded-full text-xs font-medium ${
                      item.alert_level==='critical'?'bg-red-100 text-red-600':
                      item.alert_level==='warning' ?'bg-yellow-100 text-yellow-600':
                      'bg-green-100 text-green-600'}">
                      ${item.alert_level==='critical'?'심각':item.alert_level==='warning'?'경고':'정상'}
                    </span>
                    ${item.alert_memo ? `<div class="text-gray-400 text-xs mt-0.5 whitespace-nowrap">${item.alert_memo}</div>` : ''}
                  </td>
                </tr>`}).join('')}
            </tbody>
          </table>
        </div>
      </div>
    </div>`
  } catch(e) {
    el.innerHTML = `
    <div class="bg-white rounded-xl p-8 text-center text-gray-400">
      <i class="fas fa-exchange-alt text-4xl mb-3"></i>
      <p class="text-sm">${TXState.year}년 ${TXState.month}월 교차 분석 데이터가 없습니다.</p>
      <p class="text-xs mt-1 text-gray-300">${e.message}</p>
    </div>`
  }
}

// ── 발주 교차분석 엑셀 다운로드 ──────────────────────────────────────
window.txExportCrossAnalysisExcel = function() {
  const s      = window._crossSummary || {}
  const items  = window._crossItems   || []
  const year   = window._crossYear    || TXState.year
  const month  = window._crossMonth   || TXState.month
  const hospName = TXState.selectedHospitalName || window._adminHospitalName || ''
  const nowStr = new Date().toLocaleString('ko-KR')

  if (!items.length) { showToast('교차분석 데이터가 없습니다. 먼저 분석을 실행하세요.', 'warning'); return }

  showToast('보고서 생성 중...', 'info')
  const wb = XLSX.utils.book_new()

  const FMT_WON='#,##0"원"', FMT_PCT='0.0"%"', FMT_NUM='#,##0'
  const F_BASE={name:'맑은 고딕',sz:10}, F_BOLD={name:'맑은 고딕',sz:10,bold:true}
  const F_TITLE={name:'맑은 고딕',sz:15,bold:true,color:{rgb:'1E3A5F'}}
  const F_SUB={name:'맑은 고딕',sz:10,italic:true,color:{rgb:'555555'}}
  const F_HDR={name:'맑은 고딕',sz:10,bold:true,color:{rgb:'FFFFFF'}}
  const F_SEC={name:'맑은 고딕',sz:11,bold:true,color:{rgb:'1E3A5F'}}
  const BG_TITLE={fgColor:{rgb:'1E3A5F'}}, BG_HDR={fgColor:{rgb:'2E6DA4'}}
  const BG_SEC={fgColor:{rgb:'EBF3FB'}}, BG_SUM={fgColor:{rgb:'FFF3CD'}}
  const BG_SUM2={fgColor:{rgb:'E8F5E9'}}, BG_META={fgColor:{rgb:'F0F7FF'}}
  const BG_ODD={fgColor:{rgb:'FAFAFA'}}, BG_EVEN={fgColor:{rgb:'FFFFFF'}}
  const BG_RED={fgColor:{rgb:'FFE8E8'}}, BG_YELLOW={fgColor:{rgb:'FFFDE7'}}
  const BD_T={style:'thin',color:{rgb:'CCCCCC'}}, BD_M={style:'medium',color:{rgb:'2E6DA4'}}
  const bdr=(t,r,b,l)=>({top:t,right:r,bottom:b,left:l})
  const BD_A=bdr(BD_T,BD_T,BD_T,BD_T), BD_AM=bdr(BD_M,BD_M,BD_M,BD_M)
  const AL_C={horizontal:'center',vertical:'center'}, AL_L={horizontal:'left',vertical:'center'}, AL_R={horizontal:'right',vertical:'center'}
  const ST=(f,bg,al,bd)=>({font:f||F_BASE,fill:bg||{},alignment:al||AL_L,border:bd||BD_A})
  const CS=(v,s)=>({v,s}), CN=(v,fmt,s)=>({v:Number(v)||0,t:'n',z:fmt||FMT_NUM,s})
  const mrg=(rs,re,cs,ce)=>({s:{r:rs,c:cs},e:{r:re,c:ce}})
  const S_TITLE=ST(F_TITLE,BG_TITLE,AL_C,BD_AM), S_META=ST(F_SUB,BG_META,AL_L,BD_A)
  const S_HDR=ST(F_HDR,BG_HDR,AL_C,BD_AM), S_SEC=ST(F_SEC,BG_SEC,AL_L,bdr(BD_M,BD_T,BD_T,BD_M))
  const S_SUM=ST(F_BOLD,BG_SUM,AL_L,BD_AM), S_SUM_N=(fmt)=>({...ST(F_BOLD,BG_SUM,AL_R,BD_AM),z:fmt||FMT_NUM})
  const S_SUM2=ST(F_BOLD,BG_SUM2,AL_L,BD_AM), S_SUM2_N=(fmt)=>({...ST(F_BOLD,BG_SUM2,AL_R,BD_AM),z:fmt||FMT_NUM})
  const S_BODY=(odd)=>ST(F_BASE,odd?BG_ODD:BG_EVEN,AL_L,BD_A)
  const S_BODY_N=(odd,fmt)=>({...ST(F_BASE,odd?BG_ODD:BG_EVEN,AL_R,BD_A),z:fmt||FMT_NUM})
  const S_BODY_C=(odd)=>ST(F_BASE,odd?BG_ODD:BG_EVEN,AL_C,BD_A)
  const S_EMPTY={font:F_BASE,fill:{},border:{},alignment:AL_L}
  const S_CRIT=(fmt)=>({...ST(F_BOLD,BG_RED,AL_R,BD_AM),z:fmt||FMT_NUM})
  const S_WARN=(fmt)=>({...ST(F_BOLD,BG_YELLOW,AL_R,BD_AM),z:fmt||FMT_NUM})

  const makeWS=(rows,cols,merges)=>{
    const ws={};let maxC=0
    rows.forEach((row,r)=>{row.forEach((cell,c)=>{if(c>maxC)maxC=c;if(cell==null)return;const ref=XLSX.utils.encode_cell({r,c});if(typeof cell==='object'&&'v' in cell){ws[ref]={v:cell.v,t:cell.t||(typeof cell.v==='number'?'n':'s'),z:cell.z,s:cell.s}}else{ws[ref]={v:cell,t:typeof cell==='number'?'n':'s',s:{}}}})})
    ws['!ref']=XLSX.utils.encode_range({s:{r:0,c:0},e:{r:rows.length-1,c:maxC}});if(cols)ws['!cols']=cols;if(merges)ws['!merges']=merges;return ws
  }

  const NCOL=8, rows=[], merges=[];let r=0
  const mm=String(month).padStart(2,'0')

  rows.push([CS(`${year}년 ${mm}월 발주 vs 거래명세서 교차분석 보고서`,S_TITLE)]); merges.push(mrg(r,r,0,NCOL-1)); r++
  rows.push([CS(`병원: ${hospName||'-'}   |   기준: ${year}년 ${mm}월   |   생성일시: ${nowStr}`,S_META)]); merges.push(mrg(r,r,0,NCOL-1)); r++
  rows.push(Array(NCOL).fill(CS('',S_EMPTY))); r++

  // 섹션1: 요약
  rows.push([CS('【 1. 교차분석 요약 】',S_SEC)]); merges.push(mrg(r,r,0,NCOL-1)); r++
  rows.push([CS('항목',S_HDR),CS('금액',S_HDR),CS('비율/건수',S_HDR),CS('비고',S_HDR),CS('',S_HDR),CS('',S_HDR),CS('',S_HDR),CS('',S_HDR)]); r++
  rows.push([CS('발주 총액',S_SUM),CN(s.total_order_amount||0,FMT_WON,S_SUM_N(FMT_WON)),CS('-',{...ST(F_BOLD,BG_SUM,AL_C,BD_AM)}),CS('발주 데이터 기준',S_SUM),CS('',S_SUM),CS('',S_SUM),CS('',S_SUM),CS('',S_SUM)]); r++
  rows.push([CS('명세서 총액',S_SUM),CN(s.total_invoice_amount||0,FMT_WON,S_SUM_N(FMT_WON)),CS('-',{...ST(F_BOLD,BG_SUM,AL_C,BD_AM)}),CS('거래명세서 기준',S_SUM),CS('',S_SUM),CS('',S_SUM),CS('',S_SUM),CS('',S_SUM)]); r++
  rows.push([CS('차이금액',{...S_SUM,font:{...F_BOLD,color:{rgb:((s.total_order_amount||0)-(s.total_invoice_amount||0))>0?'CC0000':'006633'}}}),CN((s.total_order_amount||0)-(s.total_invoice_amount||0),FMT_WON,S_SUM_N(FMT_WON)),CS('-',{...ST(F_BOLD,BG_SUM,AL_C,BD_AM)}),CS('발주-명세서',S_SUM),CS('',S_SUM),CS('',S_SUM),CS('',S_SUM),CS('',S_SUM)]); r++
  rows.push([CS('경고 업체',ST(F_BOLD,BG_YELLOW,AL_L,BD_AM)),CN(s.warning_vendors||0,'#,##0',{...ST(F_BOLD,BG_YELLOW,AL_R,BD_AM),z:'#,##0'}),CS('건',{...ST(F_BOLD,BG_YELLOW,AL_C,BD_AM)}),CS('±10%~30% 차이',ST(F_BASE,BG_YELLOW,AL_L,BD_A)),CS('',ST(F_BASE,BG_YELLOW,AL_L,BD_A)),CS('',ST(F_BASE,BG_YELLOW,AL_L,BD_A)),CS('',ST(F_BASE,BG_YELLOW,AL_L,BD_A)),CS('',ST(F_BASE,BG_YELLOW,AL_L,BD_A))]); r++
  rows.push([CS('심각 업체',ST(F_BOLD,BG_RED,AL_L,BD_AM)),CN(s.critical_vendors||0,'#,##0',{...ST(F_BOLD,BG_RED,AL_R,BD_AM),z:'#,##0'}),CS('건',{...ST(F_BOLD,BG_RED,AL_C,BD_AM)}),CS('±30% 이상 차이',ST(F_BASE,BG_RED,AL_L,BD_A)),CS('',ST(F_BASE,BG_RED,AL_L,BD_A)),CS('',ST(F_BASE,BG_RED,AL_L,BD_A)),CS('',ST(F_BASE,BG_RED,AL_L,BD_A)),CS('',ST(F_BASE,BG_RED,AL_L,BD_A))]); r++
  rows.push(Array(NCOL).fill(CS('',S_EMPTY))); r++

  // 섹션2: 업체별 상세
  rows.push([CS('【 2. 업체별 교차분석 상세 】',S_SEC)]); merges.push(mrg(r,r,0,NCOL-1)); r++
  rows.push([CS('업체명',S_HDR),CS('발주 총액',S_HDR),CS('명세서 총액',S_HDR),CS('차이금액',S_HDR),CS('차이율(%)',S_HDR),CS('발주횟수',S_HDR),CS('명세서품목',S_HDR),CS('상태',S_HDR)]); r++

  items.forEach((item,i)=>{
    const diff=item.amount_diff||0, pct=item.amount_diff_pct||0
    const isCrit=item.alert_level==='critical', isWarn=item.alert_level==='warning'
    const odd=i%2===0
    const rowBg=isCrit?BG_RED:isWarn?BG_YELLOW:odd?BG_ODD:BG_EVEN
    const stL=ST(isCrit||isWarn?F_BOLD:F_BASE,rowBg,AL_L,BD_A)
    const stC=ST(isCrit||isWarn?F_BOLD:F_BASE,rowBg,AL_C,BD_A)
    const stN=(fmt)=>({...ST(isCrit||isWarn?F_BOLD:F_BASE,rowBg,AL_R,BD_A),z:fmt||FMT_NUM})
    const diffColor=diff>0?'CC0000':diff<0?'006633':'555555'
    rows.push([
      CS(item.vendor_name||'-',stL),
      CN(item.ordered_amount||0,FMT_WON,stN(FMT_WON)),
      CN(item.invoice_amount||0,FMT_WON,stN(FMT_WON)),
      CN(diff,FMT_WON,{...stN(FMT_WON),font:{...(isCrit||isWarn?F_BOLD:F_BASE),color:{rgb:diffColor}}}),
      CN(Math.abs(pct),FMT_PCT,{...stN(FMT_PCT),font:{...(isCrit||isWarn?F_BOLD:F_BASE),color:{rgb:isCrit?'CC0000':isWarn?'B45309':'555555'}}}),
      CN(item.order_count||0,'#,##0',stC),
      CN(item.invoice_item_count||0,'#,##0',stC),
      CS(isCrit?'심각':isWarn?'경고':'정상',{...stC,font:{...stC.font,color:{rgb:isCrit?'CC0000':isWarn?'B45309':'006633'}}})
    ]); r++
  })

  rows.push([
    CS('합  계',S_SUM2),
    CN(s.total_order_amount||0,FMT_WON,S_SUM2_N(FMT_WON)),
    CN(s.total_invoice_amount||0,FMT_WON,S_SUM2_N(FMT_WON)),
    CN((s.total_order_amount||0)-(s.total_invoice_amount||0),FMT_WON,S_SUM2_N(FMT_WON)),
    CS('-',S_SUM2),
    CN(items.reduce((a,x)=>a+(Number(x.order_count)||0),0),'#,##0',S_SUM2_N('#,##0')),
    CN(items.reduce((a,x)=>a+(Number(x.invoice_item_count)||0),0),'#,##0',S_SUM2_N('#,##0')),
    CS(`경고 ${s.warning_vendors||0} / 심각 ${s.critical_vendors||0}`,S_SUM2)
  ]); r++

  const ws=makeWS(rows,[{wch:22},{wch:16},{wch:16},{wch:16},{wch:12},{wch:9},{wch:10},{wch:10}],merges)
  ws['!rows']=[{hpx:28},{hpx:18},{hpx:8}]
  XLSX.utils.book_append_sheet(wb,ws,'①교차분석보고서')

  const fname=`발주교차분석보고서_${hospName||'병원'}_${year}년${mm}월.xlsx`
  XLSX.writeFile(wb,fname)
  showToast(`✅ 교차분석 보고서 다운로드: ${fname}`,'success')
}

// ── 공통 UI 헬퍼 ─────────────────────────────────────────────────────
function txShowMsg(id, type, msg) {
  const el = document.getElementById(id)
  if (!el) return
  const styles = {
    success: 'bg-green-50 border border-green-200 text-green-700',
    error:   'bg-red-50 border border-red-200 text-red-600',
    info:    'bg-blue-50 border border-blue-200 text-blue-700'
  }
  el.className = `${styles[type]||styles.info} rounded-lg p-3 text-sm`
  el.textContent = msg
  el.classList.remove('hidden')
}

async function txLoadDashboard() {
  TXState.year  = +document.getElementById('txYear').value
  TXState.month = +document.getElementById('txMonth').value
  txSwitchTab(TXState.tab)
}

