// 테스트 파일 파싱 미리보기
async function previewInvoiceVendorTest(vendorId, hospitalId) {
  const fileInput = document.getElementById('ivt-file')
  const resultEl = document.getElementById('ivt-result')
  if (!fileInput?.files[0] || !resultEl) return

  resultEl.innerHTML = `<div class="text-center py-4 text-gray-400"><i class="fas fa-spinner fa-spin mr-1"></i>파싱 중...</div>`
  resultEl.classList.remove('hidden')

  try {
    // 업체 파싱 구조 가져오기
    const hqParam = hospitalId ? `?hospitalId=${hospitalId}` : ''
    const vr = await axios.get(`/api/transaction/invoice-vendors/${vendorId}${hqParam}`, { headers: authH })
    const v = vr.data.vendor

    // XLSX 라이브러리 로드
    if (!window.XLSX) {
      await new Promise((res, rej) => {
        const s = document.createElement('script')
        s.src = 'https://cdn.jsdelivr.net/npm/xlsx@0.18.5/dist/xlsx.full.min.js'
        s.onload = res; s.onerror = rej
        document.head.appendChild(s)
      })
    }

    const file = fileInput.files[0]
    const ab = await file.arrayBuffer()
    const wb = XLSX.read(ab, { type: 'array' })
    const ws = wb.Sheets[wb.SheetNames[0]]
    const rows = XLSX.utils.sheet_to_json(ws, { header: 1, defval: '' })

    // skip_rows 이후부터 데이터 파싱
    const skipRows = v.skip_rows || 4
    const dataRows = rows.slice(skipRows)

    const items = []
    let currentCategory = ''

    for (const row of dataRows) {
      if (!row || row.every(c => c === '' || c === null || c === undefined)) continue
      const code = String(row[v.col_code] || '').trim()
      const name = String(row[v.col_name] || '').trim()
      const qty = row[v.col_qty]
      const price = row[v.col_price]
      const amount = row[v.col_amount]

      // 소계행 감지 (cat_mode === 'subtotal')
      if (v.cat_mode === 'subtotal' && !code && name && !qty && !price) {
        if (name.includes('류') || name.includes('식') || name.includes('품')) {
          currentCategory = name.replace(/소계|합계|\d+/g, '').trim()
          continue
        }
      }

      if (!name) continue
      if (!code && !qty && !price) continue

      items.push({
        code, name,
        spec: String(row[v.col_spec] || ''),
        unit: String(row[v.col_unit] || ''),
        qty: isNaN(+qty) ? qty : +qty,
        price: isNaN(+price) ? price : +price,
        amount: isNaN(+amount) ? amount : +amount,
        category: currentCategory
      })
      if (items.length >= 10) break
    }

    window._invTestSampleRows = items.slice(0, 3)

    if (items.length === 0) {
      resultEl.innerHTML = `<div class="bg-red-50 border border-red-200 rounded-xl p-4 text-red-600 text-sm">
        <i class="fas fa-times-circle mr-1"></i>파싱된 데이터가 없습니다. 파싱 설정을 확인하세요.
        <div class="mt-2 text-xs">현재 설정: 건너뛸 행 ${skipRows}, 품목코드 열 ${v.col_code}, 품목명 열 ${v.col_name}</div>
      </div>`
      return
    }

    resultEl.innerHTML = `
      <div class="bg-green-50 border border-green-200 rounded-xl p-3 text-green-700 text-sm mb-3">
        <i class="fas fa-check-circle mr-1"></i>총 ${items.length}개 이상 항목 파싱 성공 (상위 10개 미리보기)
      </div>
      <div class="overflow-x-auto">
        <table class="w-full text-xs border-collapse">
          <thead>
            <tr class="bg-gray-50">
              <th class="border border-gray-200 px-2 py-1.5 text-left text-gray-600">분류</th>
              <th class="border border-gray-200 px-2 py-1.5 text-left text-gray-600">코드</th>
              <th class="border border-gray-200 px-2 py-1.5 text-left text-gray-600">품목명</th>
              <th class="border border-gray-200 px-2 py-1.5 text-right text-gray-600">수량</th>
              <th class="border border-gray-200 px-2 py-1.5 text-right text-gray-600">단가</th>
              <th class="border border-gray-200 px-2 py-1.5 text-right text-gray-600">금액</th>
            </tr>
          </thead>
          <tbody>
            ${items.map(it => `
              <tr class="hover:bg-gray-50">
                <td class="border border-gray-100 px-2 py-1.5">
                  ${it.category ? `<span class="bg-blue-100 text-blue-700 px-1.5 py-0.5 rounded text-xs">${it.category}</span>` : '-'}
                </td>
                <td class="border border-gray-100 px-2 py-1.5 text-gray-500 font-mono">${it.code||'-'}</td>
                <td class="border border-gray-100 px-2 py-1.5 font-medium">${it.name}</td>
                <td class="border border-gray-100 px-2 py-1.5 text-right">${it.qty}</td>
                <td class="border border-gray-100 px-2 py-1.5 text-right">${(+it.price||0).toLocaleString()}</td>
                <td class="border border-gray-100 px-2 py-1.5 text-right font-medium">${(+it.amount||0).toLocaleString()}</td>
              </tr>
            `).join('')}
          </tbody>
        </table>
      </div>
    `
    document.getElementById('ivt-confirm-btn')?.classList.remove('hidden')
  } catch(e) {
    resultEl.innerHTML = `<div class="bg-red-50 border border-red-200 rounded-xl p-4 text-red-600 text-sm">
      <i class="fas fa-times-circle mr-1"></i>오류: ${e.message}
    </div>`
  }
}

// 테스트 검증 완료로 표시
async function confirmInvoiceVendorTest(vendorId, hospitalId) {
  try {
    const hqParam = hospitalId ? `?hospitalId=${hospitalId}` : ''
    await axios.post(`/api/transaction/invoice-vendors/${vendorId}/test${hqParam}`, {
      success: true,
      sample_rows: window._invTestSampleRows || []
    }, { headers: authH })
    document.getElementById('invVendorTestModal')?.remove()
    showToast('검증 완료로 표시됐습니다!', 'success')
    loadInvoiceVendors(hospitalId)
  } catch(e) {
    showToast('저장 실패: ' + e.message, 'error')
  }
}


// ── 한글 폰트 사전 로드 (페이지 로드 후 백그라운드 시작) ──────────────────
// PDF 생성 전에 폰트를 미리 로드해두어 PDF 생성 속도를 높임
// setTimeout으로 페이지 로드 완료 후 비동기 시작
;(function startNanumFontPreload() {
  if (window._nanumB64Done || window._nanumLoading) return
  window._nanumLoading = true
  
  // 페이지 로드 완료 후 3초 뒤에 폰트 로드 시작 (페이지 초기 로딩 방해 안 함)
  setTimeout(function() {
    if (window._nanumB64Done) { window._nanumLoading = false; return }
    
    var fontTimer = setTimeout(function() {
      window._nanumB64 = null
      window._nanumB64Done = true
      window._nanumLoading = false
      console.log('[Font] 폰트 프리로드 타임아웃 (PDF는 영문 폰트로 생성됩니다)')
    }, 30000) // 30초 타임아웃
    
    fetch('/static/NanumGothic.ttf')
      .then(function(r) {
        if (!r.ok) throw new Error('HTTP ' + r.status)
        return r.arrayBuffer()
      })
      .then(function(buf) {
        clearTimeout(fontTimer)
        var uint8 = new Uint8Array(buf)
        var binary = ''
        var chunk = 8192
        for (var i = 0; i < uint8.length; i += chunk) {
          binary += String.fromCharCode.apply(null, uint8.subarray(i, Math.min(i + chunk, uint8.length)))
        }
        window._nanumB64 = btoa(binary)
        window._nanumB64Done = true
        window._nanumLoading = false
        console.log('[Font] 한글 폰트 로드 완료 (' + Math.round(window._nanumB64.length / 1024) + 'KB) - PDF에서 한글 사용 가능')
      })
      .catch(function(e) {
        clearTimeout(fontTimer)
        window._nanumB64 = null
        window._nanumB64Done = true
        window._nanumLoading = false
        console.warn('[Font] 폰트 로드 실패 - PDF는 영문 폰트로 생성됩니다:', e.message)
      })
  }, 3000)
})()

// ══════════════════════════════════════════════════════════════
// ① 직원용 스케줄 뷰 (단순 출력용 근무표)
// ══════════════════════════════════════════════════════════════
window.openStaffScheduleView = () => {
  const year = App.currentYear, month = App.currentMonth
  const employees = scheduleEmployees || []
  const schedMap = scheduleMonthData?.sched_map || {}
  const shifts = scheduleShifts || []
  const days = new Date(year, month, 0).getDate()
  const mm = String(month).padStart(2,'0')

  const shiftColorMap = {}
  shifts.forEach(s => { if (s.color) shiftColorMap[s.shift_code] = s.color })

  function cellStyle(code) {
    if (!code) return 'background:#f9fafb;color:#9ca3af'
    if (shiftColorMap[code]) return `background:${shiftColorMap[code]}22;color:${shiftColorMap[code]};font-weight:700`
    const m = {'연':'background:#fef9c3;color:#92400e','휴':'background:#fee2e2;color:#b91c1c',
      '오전':'background:#ede9fe;color:#6d28d9','오후':'background:#dbeafe;color:#1d4ed8',
      '경조':'background:#fce7f3;color:#9d174d','OT':'background:#ecfdf5;color:#065f46'}
    return m[code] || 'background:#f3f4f6;color:#374151'
  }

  const colMap = {'연':'#92400e','휴':'#b91c1c','오전':'#6d28d9','오후':'#1d4ed8','경조':'#9d174d','OT':'#065f46'}

  // 날짜 헤더
  let thHtml = '<th style="padding:6px 10px;text-align:left;font-size:11px;min-width:100px;position:sticky;left:0;background:#166534;z-index:3">이름</th>'
  for (let d=1; d<=days; d++) {
    const dow = getDayOfWeek(year, month, d)
    const isSun = dow==='일', isSat = dow==='토'
    thHtml += `<th style="min-width:28px;padding:4px 2px;text-align:center;font-size:10px;color:${isSun?'#fca5a5':isSat?'#93c5fd':'white'};${isSun||isSat?'background:#1a4731;':''}">
      <div>${d}</div><div style="font-size:8px;opacity:.8">${dow}</div></th>`
  }
  thHtml += '<th style="padding:4px 6px;font-size:10px;min-width:36px">근무</th>'

  // 직원 행
  let rowsHtml = ''
  employees.filter(e => e.is_active !== 0).forEach((emp, idx) => {
    const bg = idx % 2 === 0 ? '#fff' : '#f9fafb'
    let workDays = 0
    let cells = ''
    for (let d=1; d<=days; d++) {
      const dd = String(d).padStart(2,'0')
      const dateStr = `${year}-${mm}-${dd}`
      const rec = schedMap[`${emp.id}_${dateStr}`]
      const code = rec?.shift_code || ''
      const dow = getDayOfWeek(year, month, d)
      const isSun = dow==='일', isSat = dow==='토'
      const bg2 = isSun ? '#fff1f2' : isSat ? '#fffbeb' : bg
      if (code && code !== '연' && code !== '휴') workDays++
      cells += `<td style="padding:2px 1px;text-align:center;background:${bg2};border-left:1px solid #f3f4f6">
        ${code ? `<span style="display:inline-flex;align-items:center;justify-content:center;width:24px;height:24px;border-radius:4px;font-size:9px;font-weight:700;${cellStyle(code)}">${code}</span>` : '<span style="color:#e5e7eb;font-size:9px">·</span>'}
      </td>`
    }
    rowsHtml += `<tr style="border-bottom:1px solid #f3f4f6">
      <td style="padding:5px 10px;position:sticky;left:0;background:${bg};z-index:1;min-width:100px;border-right:1px solid #e5e7eb">
        <div style="font-size:11px;font-weight:600;color:#374151">${emp.name}</div>
        <div style="font-size:9px;color:#9ca3af">${emp.position || ''}</div>
      </td>
      ${cells}
      <td style="text-align:center;font-size:10px;font-weight:700;color:#166534;padding:2px 4px">${workDays}</td>
    </tr>`
  })

  const legend = shifts.map(s =>
    `<span style="display:inline-flex;align-items:center;gap:3px;font-size:10px;color:#374151;background:${s.color}22;border:1px solid ${s.color}44;border-radius:4px;padding:2px 6px">
      <span style="font-weight:700;color:${s.color}">${s.shift_code}</span> ${s.shift_name||''} ${s.start_time||''}${s.start_time?'~':''}${s.end_time||''}
    </span>`
  ).join('')

  const html = `
  <div style="font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;background:white;border-radius:12px;overflow:hidden;box-shadow:0 4px 20px rgba(0,0,0,.12);max-width:calc(100vw - 40px)">
    <div style="background:linear-gradient(135deg,#166534,#15803d);padding:16px 20px;display:flex;align-items:center;justify-content:between;gap:12px">
      <div>
        <h2 style="color:white;font-size:16px;font-weight:800;margin:0">${year}년 ${month}월 근무 스케줄</h2>
        <p style="color:rgba(255,255,255,.7);font-size:11px;margin:4px 0 0">직원용 · 금액/분석 제외</p>
      </div>
      <div style="margin-left:auto;display:flex;gap:8px">
        <button onclick="window.print()" style="padding:6px 12px;background:white;color:#166534;border:none;border-radius:6px;font-size:11px;font-weight:700;cursor:pointer"><i class="fas fa-print" style="margin-right:4px"></i>인쇄</button>
        <button onclick="document.getElementById('staffSchedModal').remove()" style="padding:6px 10px;background:rgba(255,255,255,.2);color:white;border:none;border-radius:6px;font-size:11px;cursor:pointer">닫기</button>
      </div>
    </div>
    <div style="padding:10px 16px;background:#f9fafb;border-bottom:1px solid #e5e7eb;display:flex;flex-wrap:wrap;gap:6px">
      ${legend}
    </div>
    <div style="overflow-x:auto;max-height:70vh">
      <table style="width:100%;border-collapse:collapse;font-size:12px;border:2px solid #166534">
        <thead style="position:sticky;top:0;z-index:10">
          <tr style="background:#166534;color:white">${thHtml}</tr>
        </thead>
        <tbody>${rowsHtml}</tbody>
      </table>
    </div>
  </div>`

  const modal = document.createElement('div')
  modal.id = 'staffSchedModal'
  modal.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,.6);z-index:9000;display:flex;align-items:center;justify-content:center;padding:20px;overflow:auto'
  modal.innerHTML = html
  modal.addEventListener('click', e => { if (e.target === modal) modal.remove() })
  document.body.appendChild(modal)
}

// ══════════════════════════════════════════════════════════════
// ③ 운영진용 요약 뷰 (대시보드 스타일)
// ══════════════════════════════════════════════════════════════
window.openExecutiveSummaryView = () => {
  const year = App.currentYear, month = App.currentMonth
  const employees = (scheduleEmployees || []).filter(e => e.is_active !== 0)
  const schedMap = scheduleMonthData?.sched_map || {}
  const shifts = scheduleShifts || []
  const extWorkers = scheduleExternalWorkers || []
  const extMap = scheduleExtSchedMap || {}
  const days = new Date(year, month, 0).getDate()
  const mm = String(month).padStart(2,'0')

  // 직원별 근무일수 계산
  let totalWorkDays = 0, maxWorkDays = 0, minWorkDays = 999
  const empStats = employees.map(emp => {
    let wd = 0, codeCnt = {}
    for (let d=1; d<=days; d++) {
      const ds = `${year}-${mm}-${String(d).padStart(2,'0')}`
      const code = schedMap[`${emp.id}_${ds}`]?.shift_code || ''
      if (code && code !== '연' && code !== '휴') { wd++; codeCnt[code] = (codeCnt[code]||0)+1 }
    }
    totalWorkDays += wd
    if (wd > maxWorkDays) maxWorkDays = wd
    if (wd < minWorkDays) minWorkDays = wd
    return { name: emp.name, position: emp.position, wd, codeCnt }
  })
  if (minWorkDays === 999) minWorkDays = 0
  const avgWorkDays = employees.length ? (totalWorkDays / employees.length).toFixed(1) : 0

  // 코드별 총 집계
  const totalCodeCnt = {}
  empStats.forEach(e => Object.entries(e.codeCnt).forEach(([k,v]) => { totalCodeCnt[k] = (totalCodeCnt[k]||0) + v }))

  // 외부인력 현황
  const extTotal = extWorkers.length
  let extWorkDays = 0
  extWorkers.forEach(w => {
    for (let d=1; d<=days; d++) {
      const ds = `${year}-${mm}-${String(d).padStart(2,'0')}`
      if (extMap[`${w.id}_${ds}`]?.shift_type) extWorkDays++
    }
  })

  // 근무 분포 바 차트 HTML
  const maxWd = Math.max(...empStats.map(e => e.wd), 1)
  const barRows = empStats.map(e => {
    const pct = Math.round(e.wd / maxWd * 100)
    const color = e.wd >= avgWorkDays * 1.1 ? '#ef4444' : e.wd <= avgWorkDays * 0.9 ? '#f59e0b' : '#166534'
    return `<div style="display:flex;align-items:center;gap:8px;margin-bottom:5px">
      <div style="width:70px;font-size:11px;color:#374151;font-weight:600;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${e.name}</div>
      <div style="flex:1;background:#f3f4f6;border-radius:4px;height:16px;overflow:hidden">
        <div style="width:${pct}%;height:100%;background:${color};border-radius:4px;transition:width .3s"></div>
      </div>
      <div style="width:30px;text-align:right;font-size:11px;font-weight:700;color:${color}">${e.wd}일</div>
    </div>`
  }).join('')

  // 코드 분포
  const codeItems = Object.entries(totalCodeCnt).sort((a,b)=>b[1]-a[1]).map(([k,v]) => {
    const sf = shifts.find(s => s.shift_code === k)
    const col = sf?.color || '#6b7280'
    return `<div style="display:flex;align-items:center;gap:6px;padding:8px 12px;background:${col}11;border:1px solid ${col}33;border-radius:8px">
      <span style="font-size:16px;font-weight:800;color:${col}">${v}</span>
      <div><div style="font-size:10px;font-weight:700;color:${col}">${k}</div><div style="font-size:9px;color:#9ca3af">${sf?.shift_name||''}</div></div>
    </div>`
  }).join('')

  // 과부하 경고 (평균 +2일 이상)
  const overloaded = empStats.filter(e => e.wd > Number(avgWorkDays) + 2)
  const underloaded = empStats.filter(e => e.wd < Number(avgWorkDays) - 2 && e.wd > 0)
  const warningHtml = overloaded.length || underloaded.length ? `
    <div style="background:#fff7ed;border:1px solid #fed7aa;border-radius:10px;padding:12px 16px;margin-top:12px">
      <h4 style="font-size:12px;font-weight:700;color:#c2410c;margin:0 0 8px"><i class="fas fa-exclamation-triangle" style="margin-right:6px"></i>인력 불균형 알림</h4>
      ${overloaded.map(e => `<div style="font-size:11px;color:#c2410c">⚠️ <b>${e.name}</b> — ${e.wd}일 근무 (평균 +${(e.wd-Number(avgWorkDays)).toFixed(1)}일)</div>`).join('')}
      ${underloaded.map(e => `<div style="font-size:11px;color:#b45309">🔵 <b>${e.name}</b> — ${e.wd}일 근무 (평균 -${(Number(avgWorkDays)-e.wd).toFixed(1)}일)</div>`).join('')}
    </div>` : ''

  const html = `
  <div style="font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;background:white;border-radius:12px;overflow:hidden;box-shadow:0 4px 20px rgba(0,0,0,.12);max-width:680px;width:100%">
    <div style="background:linear-gradient(135deg,#581c87,#7c3aed);padding:16px 20px;display:flex;align-items:center;gap:12px">
      <div>
        <h2 style="color:white;font-size:16px;font-weight:800;margin:0">${year}년 ${month}월 운영 현황</h2>
        <p style="color:rgba(255,255,255,.7);font-size:11px;margin:4px 0 0">운영진 요약 · 개인정보 제외</p>
      </div>
      <button onclick="document.getElementById('execSummaryModal').remove()" style="margin-left:auto;padding:6px 10px;background:rgba(255,255,255,.2);color:white;border:none;border-radius:6px;font-size:11px;cursor:pointer">닫기</button>
    </div>
    <!-- KPI 카드 -->
    <div style="display:grid;grid-template-columns:repeat(4,1fr);gap:1px;background:#e5e7eb;border-bottom:1px solid #e5e7eb">
      ${[
        {label:'총 직원', val:employees.length, icon:'fa-users', color:'#2563eb'},
        {label:'평균 근무일', val:avgWorkDays+'일', icon:'fa-calendar-check', color:'#166534'},
        {label:'최대 근무', val:maxWorkDays+'일', icon:'fa-arrow-up', color:'#ef4444'},
        {label:'최소 근무', val:minWorkDays+'일', icon:'fa-arrow-down', color:'#f59e0b'},
      ].map(c=>`<div style="background:white;padding:12px;text-align:center">
        <i class="fas ${c.icon}" style="color:${c.color};font-size:16px;margin-bottom:4px;display:block"></i>
        <div style="font-size:18px;font-weight:800;color:${c.color}">${c.val}</div>
        <div style="font-size:10px;color:#9ca3af">${c.label}</div>
      </div>`).join('')}
    </div>
    <!-- 파출/알바 현황 -->
    ${extTotal > 0 ? `<div style="padding:10px 16px;background:#fff7ed;border-bottom:1px solid #fed7aa;display:flex;gap:16px;align-items:center">
      <i class="fas fa-people-carry" style="color:#ea580c;font-size:14px"></i>
      <span style="font-size:12px;color:#c2410c;font-weight:600">외부인력 ${extTotal}명 운영 중</span>
      <span style="font-size:11px;color:#9a3412">총 ${extWorkDays}일 근무</span>
    </div>` : ''}
    <div style="padding:16px;display:grid;grid-template-columns:1fr 1fr;gap:16px">
      <!-- 근무 분포 -->
      <div>
        <h3 style="font-size:12px;font-weight:700;color:#374151;margin:0 0 10px"><i class="fas fa-chart-bar" style="margin-right:6px;color:#6b7280"></i>직원별 근무일수</h3>
        <div>${barRows}</div>
        ${warningHtml}
      </div>
      <!-- 코드 분포 -->
      <div>
        <h3 style="font-size:12px;font-weight:700;color:#374151;margin:0 0 10px"><i class="fas fa-th-large" style="margin-right:6px;color:#6b7280"></i>근무유형 현황</h3>
        <div style="display:grid;grid-template-columns:1fr 1fr;gap:6px">${codeItems || '<p style="font-size:11px;color:#9ca3af">근무 데이터 없음</p>'}</div>
      </div>
    </div>
  </div>`

  const modal = document.createElement('div')
  modal.id = 'execSummaryModal'
  modal.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,.6);z-index:9000;display:flex;align-items:center;justify-content:center;padding:20px;overflow:auto'
  modal.innerHTML = html
  modal.addEventListener('click', e => { if (e.target === modal) modal.remove() })
  document.body.appendChild(modal)
}

// ══════════════════════════════════════════════════════════════
// QR 코드 공유 관리 모달
// ══════════════════════════════════════════════════════════════
window.openQrManageModal = async () => {
  document.getElementById('qrManageModal')?.remove()

  const modal = document.createElement('div')
  modal.id = 'qrManageModal'
  modal.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,.6);z-index:9000;display:flex;align-items:center;justify-content:center;padding:20px;overflow:auto'
  modal.innerHTML = `
    <div style="background:white;border-radius:16px;overflow:hidden;box-shadow:0 8px 30px rgba(0,0,0,.2);width:100%;max-width:700px;max-height:90vh;display:flex;flex-direction:column">
      <div style="background:linear-gradient(135deg,#166534,#15803d);padding:16px 20px;display:flex;align-items:center;gap:12px;flex-shrink:0">
        <i class="fas fa-qrcode" style="color:white;font-size:20px"></i>
        <div>
          <h2 style="color:white;font-size:16px;font-weight:800;margin:0">QR 코드 공유 관리</h2>
          <p style="color:rgba(255,255,255,.8);font-size:11px;margin:3px 0 0">직원 개인 / 전체 근무표 QR 생성 및 공유</p>
        </div>
        <button onclick="document.getElementById('qrManageModal').remove()" style="margin-left:auto;padding:6px 10px;background:rgba(255,255,255,.2);color:white;border:none;border-radius:6px;cursor:pointer">닫기</button>
      </div>
      <!-- 탭 -->
      <div style="display:flex;border-bottom:2px solid #e5e7eb;background:#f9fafb;flex-shrink:0">
        <button id="qrTab_personal" onclick="qrSwitchTab('personal')"
          style="flex:1;padding:11px;font-size:12px;font-weight:700;border:none;background:#166534;color:white;cursor:pointer;border-bottom:3px solid #166534">
          <i class="fas fa-user" style="margin-right:5px"></i>개인 근무표 QR
        </button>
        <button id="qrTab_team" onclick="qrSwitchTab('team')"
          style="flex:1;padding:11px;font-size:12px;font-weight:700;border:none;background:transparent;color:#6b7280;cursor:pointer;border-bottom:3px solid transparent">
          <i class="fas fa-users" style="margin-right:5px"></i>전체 근무표 QR
        </button>
      </div>
      <!-- 개인 탭 패널 -->
      <div id="qrPanel_personal" style="display:flex;flex-direction:column;flex:1;overflow:hidden">
        <div style="padding:12px 16px;background:#fff7ed;border-bottom:1px solid #fed7aa;display:flex;gap:8px;align-items:center;flex-shrink:0">
          <button onclick="qrBulkGenerate()" style="padding:7px 14px;background:#ea580c;color:white;border:none;border-radius:8px;font-size:12px;font-weight:700;cursor:pointer">
            <i class="fas fa-magic" style="margin-right:5px"></i>전체 QR 일괄 생성
          </button>
          <span style="font-size:11px;color:#9a3412">📱 QR 스캔 시 본인 근무표만 확인 가능</span>
        </div>
        <div id="qrEmployeeList" style="overflow-y:auto;padding:12px 16px;flex:1">
          <div style="text-align:center;padding:30px;color:#9ca3af"><i class="fas fa-circle-notch fa-spin"></i> 불러오는 중...</div>
        </div>
      </div>
      <!-- 전체 탭 패널 -->
      <div id="qrPanel_team" style="display:none;flex-direction:column;flex:1;overflow:hidden">
        <div id="qrTeamContent" style="overflow-y:auto;padding:20px;flex:1">
          <div style="text-align:center;padding:30px;color:#9ca3af"><i class="fas fa-circle-notch fa-spin"></i> 불러오는 중...</div>
        </div>
      </div>
    </div>`
  modal.addEventListener('click', e => { if (e.target === modal) modal.remove() })
  document.body.appendChild(modal)

  // QR 라이브러리 로드 (로컬 번들 우선, 실패 시 CDN 폴백)
  if (!window.QRCode) {
    await new Promise((res) => {
      const s = document.createElement('script')
      s.src = '/static/qrcode.min.js'
      const timer = setTimeout(() => {
        const s2 = document.createElement('script')
        s2.src = 'https://cdn.jsdelivr.net/npm/qrcode@1.5.4/build/qrcode.min.js'
        s2.onload = () => res()
        s2.onerror = () => res()
        document.head.appendChild(s2)
      }, 3000)
      s.onload = () => { clearTimeout(timer); res() }
      s.onerror = () => {
        clearTimeout(timer)
        const s2 = document.createElement('script')
        s2.src = 'https://cdn.jsdelivr.net/npm/qrcode@1.5.4/build/qrcode.min.js'
        s2.onload = () => res()
        s2.onerror = () => res()
        document.head.appendChild(s2)
      }
      document.head.appendChild(s)
    })
  }

  // ── QR 개인 목록 버튼 이벤트 위임 ──────────────────────────────
  // 기존 핸들러 제거 후 재등록 (모달 재오픈 시 중복 방지)
  if (window._qrBtnHandler) {
    document.removeEventListener('click', window._qrBtnHandler)
    window._qrBtnHandler = null
  }
  window._qrBtnHandler = (e) => {
    const btn = e.target.closest('.qr-btn-kakao, .qr-btn-copy, .qr-btn-open, .qr-btn-dl, .qr-btn-regen')
    if (!btn) return
    const cls = btn.classList
    if (cls.contains('qr-btn-kakao'))  { qrCopyKakao(btn.dataset.name, btn.dataset.url) }
    else if (cls.contains('qr-btn-copy'))   { qrCopyLink(btn.dataset.url) }
    else if (cls.contains('qr-btn-open'))   { window.open(btn.dataset.url, '_blank') }
    else if (cls.contains('qr-btn-dl'))     { qrDownload(Number(btn.dataset.empid), btn.dataset.name) }
    else if (cls.contains('qr-btn-regen'))  { qrRegen(Number(btn.dataset.empid)) }
  }
  document.addEventListener('click', window._qrBtnHandler)

  await qrLoadList()
  qrLoadTeamPanel()
}

// 탭 전환
window.qrSwitchTab = (tab) => {
  document.getElementById('qrPanel_personal').style.display = tab === 'personal' ? 'flex' : 'none'
  document.getElementById('qrPanel_team').style.display    = tab === 'team'     ? 'flex' : 'none'
  const pBtn = document.getElementById('qrTab_personal')
  const tBtn = document.getElementById('qrTab_team')
  if (!pBtn || !tBtn) return
  if (tab === 'personal') {
    pBtn.style.background = '#166534'; pBtn.style.color = 'white'; pBtn.style.borderBottom = '3px solid #166534'
    tBtn.style.background = 'transparent'; tBtn.style.color = '#6b7280'; tBtn.style.borderBottom = '3px solid transparent'
  } else {
    tBtn.style.background = '#166534'; tBtn.style.color = 'white'; tBtn.style.borderBottom = '3px solid #166534'
    pBtn.style.background = 'transparent'; pBtn.style.color = '#6b7280'; pBtn.style.borderBottom = '3px solid transparent'
  }
}

// 전체 근무표 QR 패널 로드
window.qrLoadTeamPanel = async () => {
  const el = document.getElementById('qrTeamContent')
  if (!el) return
  try {
    const data = await api('GET', '/api/schedule/team-token')
    const token = data.token
    const teamUrl = token ? `${location.origin}/team-schedule/${token}` : ''
    const hospitalName = window._currentHospitalName || App?.hospitalName || '병원'
    const now = new Date()
    const month = now.getMonth() + 1

    el.innerHTML = `
    <div style="text-align:center;margin-bottom:20px">
      <div style="display:inline-flex;align-items:center;justify-content:center;width:60px;height:60px;background:#f0fdf4;border-radius:14px;margin-bottom:12px">
        <i class="fas fa-users" style="font-size:24px;color:#166534"></i>
      </div>
      <h3 style="font-size:15px;font-weight:800;color:#111827">전체 근무표 QR</h3>
      <p style="font-size:12px;color:#6b7280;margin-top:4px">스캔 시 병원 전체 직원의 이번 달 근무표를 확인할 수 있습니다</p>
    </div>

    ${token ? `
    <div style="display:flex;justify-content:center;margin-bottom:16px">
      <div style="background:#f0fdf4;border-radius:12px;padding:12px;border:2px solid #bbf7d0;display:inline-block">
        <canvas id="qrTeamCanvas" style="display:block;border-radius:6px"></canvas>
      </div>
    </div>
    <div style="background:#f9fafb;border-radius:8px;padding:10px 12px;margin-bottom:16px;word-break:break-all;font-size:11px;color:#374151;border:1px solid #e5e7eb">
      <i class="fas fa-link" style="color:#9ca3af;margin-right:4px"></i>${teamUrl}
    </div>
    <div style="display:flex;gap:8px;flex-wrap:wrap;justify-content:center;margin-bottom:16px">
      <button id="teamBtnKakao" style="padding:9px 16px;background:#FEE500;color:#3C1E1E;border:none;border-radius:8px;font-size:12px;font-weight:700;cursor:pointer">
        <i class="fas fa-comment" style="margin-right:5px"></i>카톡 전송용 복사
      </button>
      <button id="teamBtnCopy" style="padding:9px 16px;background:#166534;color:white;border:none;border-radius:8px;font-size:12px;font-weight:700;cursor:pointer">
        <i class="fas fa-copy" style="margin-right:5px"></i>링크 복사
      </button>
      <button id="teamBtnOpen" style="padding:9px 16px;background:#3b82f6;color:white;border:none;border-radius:8px;font-size:12px;font-weight:700;cursor:pointer">
        <i class="fas fa-eye" style="margin-right:5px"></i>미리보기
      </button>
      <button id="teamBtnDl" style="padding:9px 16px;background:#7c3aed;color:white;border:none;border-radius:8px;font-size:12px;font-weight:700;cursor:pointer">
        <i class="fas fa-download" style="margin-right:5px"></i>QR 저장
      </button>
    </div>
    <div style="border-top:1px solid #e5e7eb;padding-top:12px;text-align:center">
      <button id="teamBtnRegen" style="padding:7px 14px;background:#f3f4f6;color:#6b7280;border:1px solid #e5e7eb;border-radius:7px;font-size:11px;cursor:pointer">
        <i class="fas fa-redo" style="margin-right:4px"></i>QR 재생성 (기존 링크 무효화)
      </button>
    </div>` : `
    <div style="text-align:center">
      <p style="font-size:12px;color:#6b7280;margin-bottom:16px">아직 전체 근무표 QR이 생성되지 않았습니다</p>
      <button id="teamBtnGenerate" style="padding:12px 28px;background:#166534;color:white;border:none;border-radius:10px;font-size:13px;font-weight:700;cursor:pointer">
        <i class="fas fa-qrcode" style="margin-right:6px"></i>전체 근무표 QR 생성
      </button>
    </div>`}
    <div style="margin-top:16px;padding:10px 12px;background:#eff6ff;border-radius:8px;font-size:11px;color:#1e40af">
      <i class="fas fa-info-circle" style="margin-right:4px"></i>
      <strong>전체 공유 QR</strong>은 누구나 열람 가능합니다. 외부 공개가 우려되면 재생성하세요.
    </div>`

    // innerHTML 렌더 후 버튼에 이벤트 직접 바인딩 (onclick 따옴표 충돌 방지)
    const _s = (id) => document.getElementById(id)
    if (_s('teamBtnKakao'))    _s('teamBtnKakao').addEventListener('click', () => qrTeamCopyKakao(teamUrl, hospitalName, month))
    if (_s('teamBtnCopy'))     _s('teamBtnCopy').addEventListener('click', () => qrTeamCopyLink(teamUrl))
    if (_s('teamBtnOpen'))     _s('teamBtnOpen').addEventListener('click', () => window.open(teamUrl, '_blank'))
    if (_s('teamBtnDl'))       _s('teamBtnDl').addEventListener('click', () => qrTeamDownload())
    if (_s('teamBtnRegen'))    _s('teamBtnRegen').addEventListener('click', () => qrTeamRegen())
    if (_s('teamBtnGenerate')) _s('teamBtnGenerate').addEventListener('click', () => qrTeamGenerate())

    // QR 렌더링
    if (token && window.QRCode) {
      setTimeout(async () => {
        const canvas = document.getElementById('qrTeamCanvas')
        if (canvas) {
          try {
            await QRCode.toCanvas(canvas, teamUrl, { width: 160, margin: 1, color:{dark:'#166534',light:'#ffffff'} })
          } catch(e) {}
        }
      }, 100)
    }
  } catch(e) {
    el.innerHTML = `<div style="color:#ef4444;text-align:center;padding:20px">오류: ${e.message}</div>`
  }
}

window.qrTeamGenerate = async () => {
  try {
    await api('POST', '/api/schedule/team-token')
    await qrLoadTeamPanel()
    showToast('전체 근무표 QR이 생성됐습니다!', 'success')
  } catch(e) { showToast('생성 실패: ' + e.message, 'error') }
}

window.qrTeamRegen = async () => {
  if (!confirm('QR을 재생성하면 기존 링크가 무효화됩니다. 계속하시겠습니까?')) return
  try {
    await api('POST', '/api/schedule/team-token')
    await qrLoadTeamPanel()
    showToast('전체 근무표 QR이 재생성됐습니다', 'success')
  } catch(e) { showToast('재생성 실패', 'error') }
}

window.qrTeamCopyLink = (url) => {
  _copyText(url, '링크가 복사됐습니다')
}

window.qrTeamCopyKakao = (url, hospitalName, month) => {
  const msg = `[${hospitalName}] ${month}월 전체 근무표 📋\n\n아래 링크에서 전체 직원 근무표를 확인하세요 👇\n${url}`
  _copyText(msg, '카카오톡 메시지가 복사됐어요! 카톡에 붙여넣기 하세요 😊')
}

window.qrTeamOpen = (url) => { window.open(url, '_blank') }

window.qrTeamDownload = () => {
  const canvas = document.getElementById('qrTeamCanvas')
  if (!canvas) { showToast('QR 코드를 먼저 생성해주세요', 'error'); return }
  const hospitalName = window._currentHospitalName || App?.hospitalName || '병원'
  const link = document.createElement('a')
  link.download = `${hospitalName}_전체근무표_QR.png`
  link.href = canvas.toDataURL('image/png')
  link.click()
  showToast('전체 근무표 QR 다운로드 완료!', 'success')
}

window.qrLoadList = async function qrLoadList() {
  const listEl = document.getElementById('qrEmployeeList')
  if (!listEl) return
  try {
    const [data, empData] = await Promise.all([
      api('GET', '/api/schedule/share-tokens'),
      (scheduleEmployees && scheduleEmployees.length > 0)
        ? Promise.resolve(scheduleEmployees)
        : api('GET', '/api/schedule/employees').catch(() => [])
    ])
    const tokens = data.tokens || []
    const employees = (Array.isArray(empData) ? empData : (empData?.employees || empData || [])).filter(e => e.is_active !== 0)

    // scheduleEmployees 업데이트 (비어있었을 경우)
    if ((!scheduleEmployees || scheduleEmployees.length === 0) && employees.length > 0) {
      scheduleEmployees = employees
    }

    const tokenMap = {}
    tokens.forEach(t => { tokenMap[t.employee_id] = t.token })

    if (employees.length === 0) {
      listEl.innerHTML = `<div style="text-align:center;padding:30px;color:#9ca3af">
        <i class="fas fa-users" style="font-size:24px;margin-bottom:8px;display:block"></i>
        <p style="font-size:13px">등록된 직원이 없습니다.</p>
        <p style="font-size:11px;margin-top:4px">근무 스케줄 탭에서 직원을 먼저 등록하세요.</p>
      </div>`
      return
    }

    listEl.innerHTML = employees.map(emp => {
      const token = tokenMap[emp.id]
      const url = token ? `${location.origin}/my-schedule/${token}` : ''
      // data-* 속성으로 URL/이름 전달 (onclick 따옴표 충돌 방지)
      return `<div style="border:1px solid #e5e7eb;border-radius:12px;padding:14px;margin-bottom:10px;background:white" id="qrRow_${emp.id}">
        <div style="display:flex;align-items:center;gap:10px;margin-bottom:${token ? '12px' : '0'}">
          <div style="width:36px;height:36px;border-radius:8px;background:#f0fdf4;display:flex;align-items:center;justify-content:center;flex-shrink:0">
            <i class="fas fa-user" style="color:#166534;font-size:13px"></i>
          </div>
          <div style="flex:1;min-width:0">
            <div style="font-size:14px;font-weight:700;color:#111827">${emp.name}</div>
            <div style="font-size:11px;color:#6b7280">${emp.position || '직책 미설정'} · ${emp.team === 'cook' ? '조리팀' : '영양팀'}</div>
          </div>
          ${!token ? `
          <button onclick="qrGenOne(${emp.id})" style="padding:7px 14px;background:#166534;color:white;border:none;border-radius:8px;font-size:12px;font-weight:700;cursor:pointer">
            <i class="fas fa-qrcode" style="margin-right:4px"></i>QR 생성
          </button>` : ''}
        </div>
        ${token ? `
        <div style="display:flex;gap:14px;align-items:flex-start">
          <div style="flex-shrink:0;background:#f0fdf4;border-radius:10px;padding:8px;border:2px solid #bbf7d0">
            <canvas id="qr_${emp.id}" style="display:block;border-radius:4px"></canvas>
          </div>
          <div style="flex:1;min-width:0">
            <div style="font-size:11px;color:#6b7280;margin-bottom:8px;word-break:break-all;background:#f9fafb;border-radius:6px;padding:6px 8px;border:1px solid #e5e7eb">
              <i class="fas fa-link" style="color:#9ca3af;margin-right:4px"></i>${url}
            </div>
            <div style="display:flex;gap:6px;flex-wrap:wrap">
              <button class="qr-btn-kakao" data-name="${emp.name.replace(/"/g,'&quot;')}" data-url="${url}" data-empid="${emp.id}" style="padding:6px 12px;background:#FEE500;color:#3C1E1E;border:none;border-radius:7px;font-size:11px;font-weight:700;cursor:pointer">
                <i class="fas fa-comment" style="margin-right:4px"></i>카톡 전송용
              </button>
              <button class="qr-btn-copy" data-url="${url}" style="padding:6px 12px;background:#166534;color:white;border:none;border-radius:7px;font-size:11px;font-weight:600;cursor:pointer">
                <i class="fas fa-copy" style="margin-right:4px"></i>링크 복사
              </button>
              <button class="qr-btn-open" data-url="${url}" style="padding:6px 12px;background:#3b82f6;color:white;border:none;border-radius:7px;font-size:11px;font-weight:600;cursor:pointer">
                <i class="fas fa-eye" style="margin-right:4px"></i>미리보기
              </button>
              <button class="qr-btn-dl" data-empid="${emp.id}" data-name="${emp.name.replace(/"/g,'&quot;')}" style="padding:6px 12px;background:#7c3aed;color:white;border:none;border-radius:7px;font-size:11px;font-weight:600;cursor:pointer">
                <i class="fas fa-download" style="margin-right:4px"></i>QR저장
              </button>
              <button class="qr-btn-regen" data-empid="${emp.id}" style="padding:6px 12px;background:#f3f4f6;color:#6b7280;border:1px solid #e5e7eb;border-radius:7px;font-size:11px;cursor:pointer">
                <i class="fas fa-redo" style="margin-right:4px"></i>재생성
              </button>
            </div>
            <div style="font-size:10px;color:#9ca3af;margin-top:8px">
              <i class="fas fa-info-circle" style="margin-right:3px"></i>QR 스캔 또는 링크로 본인 근무표 확인
            </div>
          </div>
        </div>` : ''}
      </div>`
    }).join('')

    // 이벤트 위임은 openQrManageModal에서 document에 한 번만 등록 (중복 방지)

    // QR 캔버스 렌더링 (비동기, 하나씩 처리)
    for (const t of tokens) {
      const canvas = document.getElementById(`qr_${t.employee_id}`)
      if (!canvas) continue
      if (window.QRCode) {
        const url = `${location.origin}/my-schedule/${t.token}`
        try {
          await QRCode.toCanvas(canvas, url, { width: 120, margin: 1, color:{dark:'#166534',light:'#ffffff'} })
        } catch(e) {
          // QR 렌더 실패시 링크 아이콘으로 대체
          canvas.style.display = 'none'
          const parent = canvas.parentElement
          if (parent) {
            const fallback = document.createElement('div')
            fallback.style.cssText = 'width:120px;height:120px;background:#f0fdf4;border-radius:8px;display:flex;align-items:center;justify-content:center;border:2px solid #bbf7d0'
            fallback.innerHTML = '<i class="fas fa-link" style="color:#166534;font-size:20px"></i>'
            parent.insertBefore(fallback, canvas)
          }
        }
      } else {
        // QRCode 라이브러리 로드 실패 - 링크 표시
        canvas.style.display = 'none'
      }
    }
  } catch(e) {
    listEl.innerHTML = `<div style="color:#ef4444;padding:20px;text-align:center">오류: ${e.message}</div>`
  }
}

window.qrGenOne = async (empId) => {
  try {
    await api('POST', '/api/schedule/share-tokens', { employeeId: empId })
    await qrLoadList()
    showToast('QR 코드가 생성되었습니다', 'success')
  } catch(e) { showToast('생성 실패: ' + e.message, 'error') }
}

window.qrRegen = async (empId) => {
  if (!confirm('QR 코드를 재생성하면 기존 링크가 무효화됩니다. 계속하시겠습니까?')) return
  try {
    await api('POST', '/api/schedule/share-tokens', { employeeId: empId })
    await qrLoadList()
    showToast('QR 코드가 재생성되었습니다', 'success')
  } catch(e) { showToast('재생성 실패', 'error') }
}

window.qrBulkGenerate = async () => {
  try {
    const r = await api('POST', '/api/schedule/share-tokens/bulk')
    await qrLoadList()
    showToast(`${r.created}명 QR 코드 생성 완료`, 'success')
  } catch(e) { showToast('일괄 생성 실패', 'error') }
}

window.qrCopyLink = (url) => {
  if (!url) { showToast('URL이 없습니다', 'error'); return }
  _copyText(url, '링크가 복사되었습니다')
}

// 카카오톡용 메시지 복사 (이름+병원+월+링크)
window.qrCopyKakao = (name, url) => {
  if (!url) { showToast('URL이 없습니다', 'error'); return }
  const now = new Date()
  const month = now.getMonth() + 1
  const hospitalName = window._currentHospitalName || (typeof App !== 'undefined' && App?.hospitalName) || '병원'
  const msg = `[${hospitalName}] ${name} 님의 ${month}월 근무표 📅\n\n아래 링크를 눌러 확인하세요 👇\n${url}\n\n※ 본인 근무표만 확인 가능합니다`
  _copyText(msg, '카카오톡 메시지가 복사됐어요! 카톡에 붙여넣기 하세요 😊')
}

// 공통 복사 유틸 (clipboard API 실패 시 textarea 폴백)
function _copyText(text, successMsg) {
  const _fallback = () => {
    try {
      const ta = document.createElement('textarea')
      ta.value = text
      ta.style.cssText = 'position:fixed;top:-9999px;left:-9999px;opacity:0'
      document.body.appendChild(ta)
      ta.focus()
      ta.select()
      const ok = document.execCommand('copy')
      document.body.removeChild(ta)
      if (ok) showToast(successMsg, 'success')
      else prompt('복사하세요:', text)
    } catch(err) {
      prompt('복사하세요:', text)
    }
  }
  if (navigator.clipboard && window.isSecureContext) {
    navigator.clipboard.writeText(text).then(
      () => showToast(successMsg, 'success'),
      () => _fallback()
    )
  } else {
    _fallback()
  }
}

// QR 이미지 다운로드 (PNG)
window.qrDownload = (empId, name) => {
  const canvas = document.getElementById(`qr_${empId}`)
  if (!canvas) { showToast('QR 코드를 먼저 생성해주세요', 'error'); return }
  const link = document.createElement('a')
  link.download = `${name}_근무표_QR.png`
  link.href = canvas.toDataURL('image/png')
  link.click()
  showToast(`${name} 님 QR 다운로드 완료!`, 'success')
}

window.qrOpenLink = (url) => { window.open(url, '_blank') }
